  if(matches('hard carry','hypercarry'))return'tone-marksman';
  if(matches('danger','critical','engage','dive','diver','assassin','slayer','burst','hard cc','hard'))return'tone-engage';
  if(matches('disengage','peel','heal','shield','cleanse','protect','enchanter','success','ready'))return'tone-disengage';
  if(matches('mage','magic','ability power','battlemage','artillery','spell')||tokens.has('ap'))return'tone-magic';
  if(matches('physical','attack damage','fighter','juggernaut','skirmisher')||tokens.has('ad'))return'tone-physical';
  if(matches('tank','frontline','toughness','vanguard','warden'))return'tone-tank';
  if(matches('marksman','ranged','range','dps','carry','hypercarry'))return'tone-marksman';
  if(matches('poke','mobility','dash','blink','speed','lane'))return'tone-poke';
  if(matches('catch','control','crowd control','root','stun','airborne','charm','fear','suppress','soft'))return'tone-control';
  if(matches('split','macro','tower','warning','tier','early gank'))return'tone-macro';
  if(matches('support','controller','utility','vision'))return'tone-support';
  if(matches('true damage','specialist','flex'))return'tone-neutral';
  if(matches('strong'))return'tone-strong';
  if(matches('average','medium'))return'tone-average';
  if(matches('weak','low'))return'tone-weak';
