function teamFocusChampion(side,index,phase){const c=byId(state[side][index]),role=ROLES[index];if(!c)return `<article class="team-focus-champion ${side} empty"><button type="button" data-picker="slot:${side}:${index}">${roleIcon(role)}<b>${teamText('Choose champion','Chọn tướng')}</b><small>${esc(role)}</small></button></article>`;const guide=guideFor(c),plan=guide.gamePlan?.[phase]||teamText('No game plan data.','Chưa có dữ liệu kế hoạch.'),spike=guide.powerSpikes?.[phase]||teamText('No power spike data.','Chưa có dữ liệu ngưỡng sức mạnh.');return `<article class="team-focus-champion ${side}"><header>${portrait(c,'lg')}<div><small>${esc(role)} · ${teamText(phase.toUpperCase(),phase==='early'?'ĐẦU TRẬN':phase==='mid'?'GIỮA TRẬN':'CUỐI TRẬN')}</small><h3>${esc(c.name)}</h3><p>${tacticalTags(c).slice(0,3).map(tacticalTag).join('')}</p></div><strong class="power-${slug(c.power[phase])}">${esc(c.power[phase]||'—')}</strong></header><div class="team-focus-skills">${(c.abilities||[]).slice(0,5).map(a=>`<span title="${esc(`${a.slot} · ${a.name}`)}">${a.images?.[0]?`<img src="${esc(a.images[0])}" alt="${esc(a.name)}">`:`<i>${esc(a.slot)}</i>`}<b>${esc(a.slot)}</b><small>${esc(a.name)}</small></span>`).join('')}</div><section><div><small>${teamText('GAME PLAN','KẾ HOẠCH')}</small><p>${esc(plan)}</p></div><div><small>${teamText('POWER SPIKE','NGƯỠNG SỨC MẠNH')}</small><p>${esc(spike)}</p></div></section></article>`}
