function renderTeam(){return pageIntro(teamText('Team composition analyzer','Phân tích đội hình'),teamText('Build both teams, compare exact sheet identities, then inspect one lane and match phase at a time.','Xây dựng hai đội, đối chiếu đúng các hệ trong sheet rồi xem từng lane và giai đoạn trận.'),`<button type="button" class="primary" data-route="draft">${teamText('Draft Room','Phòng Ban/Pick')}</button>`)+teamSheetBoard()+teamWorkbookMatrices()+teamFocusPanel()}
function lanePressure(c,opponent,lane){if(!c)return 0;const slot=Math.max(state.blue.indexOf(c.id),state.red.indexOf(c.id)),resolvedLane=lane||ROLES[slot]||c.primaryRole,own=matchupsFor(c,resolvedLane),enemy=matchupsFor(opponent,resolvedLane),rangeEdge=opponent&&c.range==='Ranged'&&opponent.range==='Melee'?6:0,matchupEdge=opponent&&(own.bestLane.includes(opponent.name)||enemy.counters.includes(c.name))?10:0;return phaseValue(c.power.early)*18+(Number(c.ratings.damage)||0)*8+(Number(c.ratings.control)||0)*5+(Number(c.ratings.mobility)||0)*3+rangeEdge+matchupEdge}
function keyLaneSkills(c){return c?c.abilities.filter(a=>a.slot!=='Passive').sort((a,b)=>(b.tags.length-a.tags.length)).slice(0,3):[]}
function teamLaneDetail(){return `<section class="lane-detail"><div class="section-head"><h3>Lane & skill matchup matrix</h3><span>Pressure probability is inferred, not observed win rate</span></div><div class="lane-match-grid">${ROLES.map((role,index)=>{const a=byId(state.blue[index]),b=byId(state.red[index]),as=lanePressure(a,b),bs=lanePressure(b,a),prob=a||b?Math.round(Math.max(15,Math.min(85,50+(as-bs)*.8))):50;return `<article><header><span>${role}</span><b>${prob}% · ${100-prob}%</b><small>INFERRED PRESSURE</small></header><div class="lane-champions"><section>${a?portrait(a,'sm'):''}<b>${esc(a?.name||'—')}</b><span>${a?`${a.power.early} · ${a.damage.profile}`:'—'}</span></section><strong>${as===bs?'=':as>bs?'BLUE EDGE':'RED EDGE'}</strong><section>${b?portrait(b,'sm'):''}<b>${esc(b?.name||'—')}</b><span>${b?`${b.power.early} · ${b.damage.profile}`:'—'}</span></section></div><div class="lane-skill-pairs"><section>${keyLaneSkills(a).map(skill=>`<div>${skill.images[0]?`<img src="${esc(skill.images[0])}" alt="">`:''}<span><b>${esc(`${skill.slot} · ${skill.name}`)}</b><small>${esc(skill.cooldown||'No cooldown')} · ${esc(skill.tags.slice(0,4).join(', ')||'No tags')}</small></span></div>`).join('')||'<p>—</p>'}</section><section>${keyLaneSkills(b).map(skill=>`<div>${skill.images[0]?`<img src="${esc(skill.images[0])}" alt="">`:''}<span><b>${esc(`${skill.slot} · ${skill.name}`)}</b><small>${esc(skill.cooldown||'No cooldown')} · ${esc(skill.tags.slice(0,4).join(', ')||'No tags')}</small></span></div>`).join('')||'<p>—</p>'}</section></div><footer><span>Blue pressure <b>${as}</b></span><i><b style="width:${prob}%"></b></i><span>Red pressure <b>${bs}</b></span></footer></article>`}).join('')}</div></section>`}
function hasTeamTag(c,term){return new RegExp(term,'i').test([...(c.capabilities||[]),c.combat?.primary,c.combat?.secondary,c.combat?.macro,...(c.combat?.positioning||[])].filter(Boolean).join(' '))}
function detailedWarnings(side){const list=team(side),m=teamMetrics(side),items=[],add=(level,title,detail,fix,related=[])=>items.push({level,title,detail,fix,related});if(list.length<5)add('info',`Thiếu ${5-list.length} vị trí`,'Các phép so sánh hiện chỉ tính trên số tướng đã chọn.','Chọn đủ Top, Jungle, Mid, AD và Support.');if(!m.frontline)add('critical','Không có frontline','Đội thiếu người nhận nhịp engage đầu tiên và giữ khoảng trống cho carry.','Thêm Tank/Juggernaut có Toughness cao.');if(!m.engage)add('warning','Thiếu engage chủ động','Đội khó ép giao tranh khi đang có lợi thế.','Bổ sung champion có tag Engage hoặc hard CC.');if(!m.disengage)add('warning','Thiếu disengage','Carry dễ bị dive và đội khó reset giao tranh.','Ưu tiên Peel, Shield, Knockback hoặc Disengage.');if(!m.magic)add('critical','Không có magic damage','Đối thủ có thể tối ưu giáp vật lý.','Bổ sung nguồn AP ổn định.');if(!m.physical)add('critical','Không có physical damage','Đối thủ có thể tối ưu kháng phép.','Bổ sung AD carry hoặc nguồn physical DPS.');if(!m.cc)add('critical','Không có hard CC rõ ràng','Đội khó khóa mục tiêu và nối chuỗi kỹ năng.','Thêm Root, Stun, Airborne hoặc Suppression.');if(m.clearwave<TEAM_RULES.waveClearWarningThreshold)add('warning','Wave clear thấp','Khó giữ trụ, setup objective và đẩy nhiều lane.',`Thêm champion có Clearwave từ ${TEAM_RULES.waveClearStrongThreshold} trở lên.`);if(m.melee>=4&&!m.frontline)add('critical','Quá nhiều melee nhưng thiếu tank','Đội phải cùng bước vào vùng nguy hiểm mà không có người chịu đòn.','Đổi một melee carry sang frontline hoặc ranged DPS.');const carries=list.filter(c=>c.profiles?.carry||c.profiles?.hyperCarry);if(carries.length===1)add('warning','Chỉ có một carry','Đối thủ có thể dồn toàn bộ tài nguyên để khóa nguồn sát thương duy nhất.','Bổ sung carry phụ hoặc threat split push.',carries);if(list.filter(c=>hasTeamTag(c,'Strong Ult|TeamFight')).length>=4)add('warning','Phụ thuộc ultimate','Sức mạnh giao tranh giảm mạnh khi các ultimate chính đang hồi.','Tránh ép objective khi cooldown chưa sẵn sàng.');return items}
function replacementSuggestions(side,warning){const used=new Set(selectedIds()),roleNeeds={"Không có magic damage":c=>/magic/i.test(c.damage?.type),"Không có physical damage":c=>/physical/i.test(c.damage?.type),"Không có frontline":c=>(Number(c.ratings?.toughness)||0)>=3||/tank|juggernaut/i.test(`${c.classification?.primary} ${c.classification?.secondary}`),"Thiếu engage chủ động":c=>hasTeamTag(c,'Engage'),"Thiếu disengage":c=>hasTeamTag(c,'Disengage|Shield|Heal'),"Không có hard CC rõ ràng":c=>hasTeamTag(c,'Root|Stun|Airborne|Suppression|CC Hard'),"Wave clear thấp":c=>(Number(c.ratings?.clearwave)||0)>=TEAM_RULES.waveClearStrongThreshold};const test=roleNeeds[warning.title]||(()=>false),openRoles=ROLES.filter((_,index)=>!state[side][index]);return CHAMPIONS.filter(c=>!used.has(c.id)&&test(c)&&(openRoles.length?openRoles.some(role=>c.roles.includes(role)):c.roles.some(role=>ROLES.includes(role)))).sort((a,b)=>teamScoreCandidate(b)-teamScoreCandidate(a)).slice(0,3)}
function teamScoreCandidate(c){return ['damage','toughness','control','mobility','utility'].reduce((n,key)=>n+(Number(c.ratings?.[key])||0),0)}
function rankingBlock(side){const list=team(side).map(c=>({c,score:(Number(c.ratings.damage)||0)+(Number(c.ratings.toughness)||0)+(Number(c.ratings.control)||0)*1.25+(Number(c.ratings.utility)||0)+c.abilities.filter(a=>a.tags.includes('Strong Ult')||a.tags.includes('TeamFight')).length})).sort((a,b)=>b.score-a.score);return `<section class="ranking-side ${side}"><header><b>${side.toUpperCase()}</b><span>Teamfight ranking</span></header>${list.map(({c,score},i)=>{const decisive=c.abilities.find(a=>a.tags.includes('Strong Ult')||a.tags.includes('TeamFight'))||c.abilities.find(a=>a.tags.some(tag=>/engage|disengage|aoe|airborne|stun|root/i.test(tag)));return `<article><strong>${i+1}</strong>${portrait(c,'sm')}<span><b>${esc(c.name)}</b><small>${esc([c.combat.primary,c.combat.secondary,c.combat.positioning.join(' · ')].filter(Boolean).join(' · '))}</small>${decisive?`<small>Decisive: ${esc(decisive.slot)} ${esc(decisive.name)}</small>`:''}</span><em>${score.toFixed(1)}</em></article>`}).join('')||'<p class="empty">Chưa chọn đội hình</p>'}</section>`}
function tacticalFlags(side){const list=team(side),metric=(label,test)=>{const picks=list.filter(test);return `<article><span>${esc(label)}</span><b>${picks.length}</b><div>${picks.map(c=>portrait(c,'xs')).join('')||'<small>Không có</small>'}</div></article>`};return `<section class="tactical-side ${side}"><header><b>${side.toUpperCase()}</b><span>Threat & execution profile</span></header><div>${metric('Split pusher',c=>hasTeamTag(c,'Split'))}${metric('Assassin / Flank',c=>hasTeamTag(c,'Assassin|Flank'))}${metric('Hard CC',c=>hasTeamTag(c,'Root|Stun|Airborne|Suppression|CC Hard'))}${metric('Dive',c=>hasTeamTag(c,'Dive|Dash'))}${metric('Wave clear',c=>(Number(c.ratings.clearwave)||0)>=TEAM_RULES.waveClearStrongThreshold)}${metric('Tower pressure',c=>(Number(c.ratings.tower)||0)>=TEAM_RULES.towerStrongThreshold)}${metric('Strong ultimate',c=>c.abilities.some(a=>a.tags.includes('Strong Ult')||a.tags.includes('TeamFight')))}</div></section>`}
function extendedWarningRules(side){const list=team(side),m=teamMetrics(side),items=[],add=(level,title,detail,fix,related=[])=>items.push({level,title,detail,fix,related}),carries=list.filter(c=>c.profiles?.carry||c.profiles?.hyperCarry),peel=list.filter(c=>hasTeamTag(c,'Shield|Heal|Disengage|Peel|CC Hard')),dps=list.filter(c=>/dps|marksman|hyper/i.test(`${c.damage.profile} ${c.classification.primary}`)),assassins=list.filter(c=>hasTeamTag(c,'Assassin|Flank')),tanks=list.filter(c=>(Number(c.ratings.toughness)||0)>=3||/tank/i.test(`${c.classification.primary} ${c.classification.secondary}`)),strongByPhase=PHASES.map(phase=>list.filter(c=>c.power[phase]==='Strong').length);if(list.length&&m.backline===0)add('warning','Không có backline','Đội thiếu nguồn sát thương an toàn ở tuyến sau.','Bổ sung ranged carry hoặc champion có self-peel.');if(list.length&&!dps.length)add('critical','Không có DPS ổn định','Đội có thể hết sát thương sau combo đầu tiên.','Thêm nguồn damage duy trì.',list);if(m.ranged>=4&&!m.frontline)add('critical','Nhiều ranged nhưng không có tank','Đội có tầm đánh nhưng không có người tạo không gian.','Thêm frontline có peel hoặc engage.');if(carries.length&&peel.length===0)add('critical','Carry thiếu peel','Các carry không có Shield, Heal, Disengage hoặc hard CC bảo vệ.','Bổ sung enchanter hoặc controller.',carries);if(list.length&&!m.split)add('info','Không có split pusher','Đội khó kéo giãn bản đồ bằng side lane.','Chơi group/catch hoặc thêm champion Split/Flex.');if(list.length&&m.tower<TEAM_RULES.towerWarningThreshold)add('warning','Tower pressure thấp','Sau khi thắng giao tranh, đội có thể chuyển hóa lợi thế thành công trình chậm.',`Thêm champion có tower rating từ ${TEAM_RULES.towerStrongThreshold}.`);if(list.length&&!m.catch)add('warning','Không có công cụ bắt lẻ','Đội khó trừng phạt đối thủ đi lẻ trong fog of war.','Bổ sung Pick, Catch, Hook hoặc mobility + CC.');if(assassins.length>=2&&!m.engage)add('warning','Nhiều assassin nhưng thiếu người mở','Các flank threat phải tự tìm góc và dễ vào lệch nhịp.','Thêm engage đáng tin cậy hoặc vision control.',assassins);if(tanks.length>=3&&m.damage<2.4)add('critical','Nhiều tank nhưng thiếu damage','Đội sống lâu nhưng khó kết thúc carry đối phương.','Đổi một tank sang DPS carry.',tanks);if(list.length&&list.reduce((sum,c)=>sum+(Number(c.difficulty)||0),0)/list.length>=2.8)add('warning','Đội hình khó vận hành','Nhiều champion yêu cầu execution cao và phối hợp cooldown chính xác.','Giảm một champion difficulty cao hoặc dùng Simple game plan.',list.filter(c=>(Number(c.difficulty)||0)>=3));if(list.length===5&&Math.max(...strongByPhase)<2)add('info','Power spike không đồng bộ','Không có giai đoạn nào ít nhất hai champion cùng đạt Strong.','Chơi theo lane windows, tránh ép 5v5 theo lịch cứng.');return items}
function warningBoard(side){const items=[...detailedWarnings(side),...extendedWarningRules(side)].filter((item,index,array)=>array.findIndex(other=>other.title===item.title)===index);return `<section class="warning-side ${side}"><header><b>${side.toUpperCase()}</b><span>Composition warnings · ${items.length}</span></header>${items.map(w=>{const suggestions=replacementSuggestions(side,w);return `<article class="${w.level}"><div><span>${w.level}</span><b>${esc(w.title)}</b></div><p>${esc(w.detail)}</p><small>${esc(w.fix)}</small>${w.related?.length?`<div class="warning-related"><span>Related</span>${w.related.map(c=>portrait(c,'xs')).join('')}</div>`:''}${suggestions.length?`<footer><span>Suggestions:</span>${suggestions.map(c=>`<button type="button" data-focus="${c.id}" data-route="champions">${portrait(c,'xs')}<b>${esc(c.name)}</b><small>${esc(c.roles.join(' · '))}</small></button>`).join('')}</footer>`:''}</article>`}).join('')||'<article class="ok"><b>No critical composition warning</b><p>Damage, control and formation meet the baseline thresholds.</p></article>'}</section>`}
function damageBalanceScore(metrics){const total=metrics.physical+metrics.magic;return total?Math.min(metrics.physical,metrics.magic)/Math.max(metrics.physical,metrics.magic)*5:0}
function executionScore(side){const list=team(side);return list.length?5-list.reduce((sum,c)=>sum+(Number(c.difficulty)||0),0)/list.length:0}
function advantageMark(a,b){const delta=Number(a)-Number(b),size=Math.abs(delta);if(size<.15)return'===';const mark=delta>0?'>':'<';return size>=2?mark.repeat(3):size>=.75?mark.repeat(2):mark}
function finalVerdict(){const b=teamMetrics('blue'),r=teamMetrics('red'),axes=[['Draft',teamScore('blue'),teamScore('red')],['Lane',ROLES.reduce((sum,role,index)=>sum+lanePressure(byId(state.blue[index]),byId(state.red[index]),role),0)/5,ROLES.reduce((sum,role,index)=>sum+lanePressure(byId(state.red[index]),byId(state.blue[index]),role),0)/5],['Early',b.early,r.early],['Mid',b.mid,r.mid],['Late',b.late,r.late],['Teamfight',b.control+b.toughness+b.damage,r.control+r.toughness+r.damage],['Range',b.ranged,r.ranged],['Damage balance',damageBalanceScore(b),damageBalanceScore(r)],['Frontline',b.frontline,r.frontline],['Mobility',b.mobility,r.mobility],['Control',b.control,r.control],['Utility',b.utility,r.utility],['Split',b.split,r.split],['Catch',b.catch,r.catch],['Objective setup',(b.clearwave+b.control+b.mobility)/3,(r.clearwave+r.control+r.mobility)/3],['Execution ease',executionScore('blue'),executionScore('red')]];return `<section class="final-verdict"><div class="section-head"><h3>Total Advantage Verdict</h3><span>Each axis stays independent so one losing lane is never hidden by the total</span></div><div class="verdict-axes">${axes.map(([label,bv,rv])=>`<div><span class="blue">${Number(bv).toFixed(1)}</span><b>${label}<small>${advantageMark(bv,rv)} · ${bv===rv?'Even':bv>rv?'Blue edge':'Red edge'}</small></b><span class="red">${Number(rv).toFixed(1)}</span></div>`).join('')}</div><div class="win-plan"><div><b>Blue Plan</b>${winCondition('blue','red').map(x=>`<p>${esc(x)}</p>`).join('')}</div><div><b>Red Plan</b>${winCondition('red','blue').map(x=>`<p>${esc(x)}</p>`).join('')}</div></div></section>`}
function sheetProjection(){const edges=ROLES.map((_,i)=>{const a=byId(state.blue[i]),b=byId(state.red[i]);if(!a||!b)return 50;const av=lanePressure(a,b,ROLES[i]),bv=lanePressure(b,a,ROLES[i]);return Math.max(15,Math.min(85,50+(av-bv)*.8))}),blue=edges.reduce((n,v)=>n+v,0)/edges.length,red=100-blue,weak=edges.indexOf(Math.min(...edges)),strong=edges.indexOf(Math.max(...edges)),banBlue=byId(state.red[weak]),banRed=byId(state.blue[strong]);return `<section class="sheet-projection"><div class="ban-call blue"><small>BAN FOR TEAM BLUE</small><b>${esc(banBlue?.name||'—')}</b><span>${ROLES[weak]} pressure</span></div><div class="sheet-odds"><strong>${blue.toFixed(1)}%</strong><i><b style="width:${blue}%"></b><em style="width:${red}%"></em></i><strong>${red.toFixed(1)}%</strong><small>Trung bình 5 lane · inferred pressure</small></div><div class="ban-call red"><small>BAN FOR TEAM RED</small><b>${esc(banRed?.name||'—')}</b><span>${ROLES[strong]} pressure</span></div></section>`}
function sheetPhaseMatrix(){const b=teamMetrics('blue').weightedPower,r=teamMetrics('red').weightedPower;return `<section class="sheet-block"><div class="section-head"><h3>Power curve theo từng vị trí</h3><span>Strong · Average · Weak</span></div><div class="sheet-phase-table">${ROLES.map((role,i)=>{const blue=byId(state.blue[i]),red=byId(state.red[i]);return `<div><span>${blue?portrait(blue,'sm'):''}<b>${esc(blue?.name||'—')}</b></span><section>${PHASES.map(p=>`<p>${pill(blue?.power?.[p]||'—',slug(blue?.power?.[p]))}<small>${p.toUpperCase()}</small>${pill(red?.power?.[p]||'—',slug(red?.power?.[p]))}</p>`).join('')}</section><span><b>${esc(red?.name||'—')}</b>${red?portrait(red,'sm'):''}</span><em>${role}</em></div>`}).join('')}</div><footer><b>${b.early.toFixed(2)} / ${b.mid.toFixed(2)} / ${b.late.toFixed(2)}</b><span>ROLE-WEIGHTED OUTPUT</span><b>${r.early.toFixed(2)} / ${r.mid.toFixed(2)} / ${r.late.toFixed(2)}</b></footer></section>`}
function phaseWeightPanel(){return `<section class="phase-weight-panel"><div class="section-head"><h3>Role-weighted power contract</h3><span>Exact coefficients recovered from the Team workbook prototype</span></div><div class="phase-weight-sides">${['blue','red'].map(side=>`<article class="${side}"><header><b>${side.toUpperCase()}</b>${PHASES.map(phase=>`<span><small>${phase}</small><strong>${teamMetrics(side).weightedPower[phase].toFixed(2)}</strong></span>`).join('')}</header><div>${ROLES.map((role,index)=>{const c=byId(state[side][index]);return `<p><span>${c?portrait(c,'xs'):''}<b>${esc(c?.name||role)}</b><small>${role}</small></span>${PHASES.map(phase=>`<em title="${esc(`${role} ${phase} ${c?.power?.[phase]||'empty'}`)}">${rolePhaseWeight(c,index,phase).toFixed(2)}</em>`).join('')}</p>`}).join('')}</div></article>`).join('')}</div></section>`}
function contributorFaces(side,test){const hits=team(side).filter(test);return `<div class="contributor-faces">${hits.map(c=>portrait(c,'xs')).join('')||'<span>—</span>'}</div>`}
function sheetIdentity(){const kinds=['Engage','Disengage','Poke','Split','Catch'];return `<section class="sheet-block"><div class="section-head"><h3>Combat identity & contributors</h3><span>Tướng đóng góp trực tiếp cho từng hệ</span></div>${kinds.map(kind=>`<div class="identity-row">${contributorFaces('blue',c=>hasTeamTag(c,kind))}${pill(kind,slug(kind))}<b>${team('blue').filter(c=>hasTeamTag(c,kind)).length} ${compareMark(team('blue').filter(c=>hasTeamTag(c,kind)).length,team('red').filter(c=>hasTeamTag(c,kind)).length)} ${team('red').filter(c=>hasTeamTag(c,kind)).length}</b>${contributorFaces('red',c=>hasTeamTag(c,kind))}</div>`).join('')}</section>`}
function compareMark(a,b){return a>b?'>>>':a<b?'<<<':'==='}
function sheetSkillMatrix(){return `<section class="sheet-block skill-sheet"><div class="section-head"><h3>Skill detail comparison</h3><span>Passive · Q · W · E · R, tag và cooldown</span></div>${ROLES.map((role,i)=>{const b=byId(state.blue[i]),r=byId(state.red[i]),side=(c,tone)=>`<div class="skill-sheet-side ${tone}">${c?`<header>${portrait(c,'sm')}<b>${esc(c.name)}</b></header><div>${c.abilities.slice(0,5).map(a=>`<article>${a.images?.[0]?`<img src="${esc(a.images[0])}" alt="">`:''}<strong>${esc(a.slot)}</strong><span>${esc(a.name)}</span><small>${esc(a.cooldown||'—')}</small><footer>${a.tags.slice(0,5).map(tag=>pill(tag,slug(tag))).join('')}</footer></article>`).join('')}</div>`:'<p class="empty">Chưa chọn</p>'}</div>`;return `<div class="skill-sheet-row">${side(b,'blue')}<div class="skill-duel-center"><em>${role}</em>${laneFaceoff(i,true)}</div>${side(r,'red')}</div>`}).join('')}</section>`}
function sheetTriggerMatrix(){const rows=[['Dive',c=>hasTeamTag(c,'Dive|Dash')],[`Clearwave ${TEAM_RULES.waveClearEliteThreshold}+`,c=>(Number(c.ratings.clearwave)||0)>=TEAM_RULES.waveClearEliteThreshold],[`Clearwave ${TEAM_RULES.waveClearStrongThreshold}+`,c=>(Number(c.ratings.clearwave)||0)>=TEAM_RULES.waveClearStrongThreshold],[`Tower ${TEAM_RULES.towerStrongThreshold}+`,c=>(Number(c.ratings.tower)||0)>=TEAM_RULES.towerStrongThreshold],['Strong Ult',c=>c.abilities.some(a=>a.tags.includes('Strong Ult')||a.tags.includes('TeamFight'))]];return `<section class="sheet-block"><div class="section-head"><h3>Sheet trigger matrix</h3><span>Chỉ hiện contributor đạt đúng ngưỡng</span></div>${rows.map(([label,test])=>`<div class="trigger-sheet-row"><b>${label}</b>${contributorFaces('blue',test)}<small>${label.includes(String(TEAM_RULES.waveClearEliteThreshold))?`rating ≥ ${TEAM_RULES.waveClearEliteThreshold}`:label.match(/\d/)?`rating ≥ ${label.match(/\d+/)?.[0]}`:'tag match'}</small>${contributorFaces('red',test)}</div>`).join('')}</section>`}
function sheetReferenceReport(){return `${sheetProjection()}<div class="sheet-reference-grid">${sheetPhaseMatrix()}${sheetIdentity()}</div>${sheetTriggerMatrix()}${sheetSkillMatrix()}`}
function teamExtendedReport(){return `<section class="report-divider"><span>COMBAT & MACRO</span><h2>Phân tích vận hành đội hình</h2></section><div class="mirror-report">${tacticalFlags('blue')}${tacticalFlags('red')}</div><div class="mirror-report">${rankingBlock('blue')}${rankingBlock('red')}</div><section class="report-divider"><span>RISK & ADJUSTMENT</span><h2>Cảnh báo và gợi ý thay champion</h2></section><div class="mirror-report">${warningBoard('blue')}${warningBoard('red')}</div>${finalVerdict()}`}
const TEAM_SECTIONS=[['overview','Overview'],['power','Power'],['combat','Combat'],['damage','Damage'],['formation','Formation'],['carry','Carry'],['utility','Utility'],['matchups','Matchups'],['gameplan','Game Plan'],['spikes','Power Spikes'],['warnings','Warnings']];
function availableTeamSections(){return state.analysisMode==='simple'?TEAM_SECTIONS.filter(([id])=>['overview','power','damage','formation','carry','warnings'].includes(id)):TEAM_SECTIONS}
function teamWorkspaceBar(){const sessions=[...state.savedSessions].sort((a,b)=>String(b.updatedAt).localeCompare(String(a.updatedAt))),history=[...state.changeHistory].reverse().slice(0,8);return `<section class="team-workspace" aria-labelledby="workspace-title"><div class="session-primary"><label><span id="workspace-title">Analysis name</span><input data-session-name value="${esc(state.sessionName)}" maxlength="80" autocomplete="off"></label><label><span>Saved analyses</span><select data-session-load><option value="">Select a saved analysis</option>${sessions.map(item=>`<option value="${esc(item.id)}" ${item.id===state.activeSessionId?'selected':''}>${esc(item.name)} · ${esc(new Intl.DateTimeFormat(undefined,{month:'short',day:'numeric',hour:'2-digit',minute:'2-digit'}).format(new Date(item.updatedAt)))}</option>`).join('')}</select></label><div class="session-actions"><button type="button" class="primary" data-action="save-session">Save Analysis</button><button type="button" data-action="copy-session-link">Copy Link</button><button type="button" data-action="export-session">Export JSON</button><label class="import-session"><input type="file" accept="application/json,.json" data-session-import><span>Import JSON</span></label></div></div><div class="session-preferences"><fieldset><legend>Analysis mode</legend><div class="segmented">${[['simple','Simple'],['advanced','Advanced'],['expert','Expert']].map(([id,label])=>`<button type="button" data-analysis-mode="${id}" class="${state.analysisMode===id?'active':''}" aria-pressed="${state.analysisMode===id}">${label}</button>`).join('')}</div></fieldset><fieldset><legend>Perspective</legend><div class="segmented">${[['neutral','Neutral'],['blue','Blue'],['red','Red']].map(([id,label])=>`<button type="button" data-perspective="${id}" class="${state.perspective===id?'active':''}" aria-pressed="${state.perspective===id}">${label}</button>`).join('')}</div></fieldset><div class="ban-controls"><button type="button" data-action="toggle-bans" aria-pressed="${state.bansVisible}">${state.bansVisible?'Hide Bans':'Show Bans'}</button><button type="button" class="danger-button" data-action="reset-all-bans" ${[...state.blueBans,...state.redBans].some(Boolean)?'':'disabled'}>Reset All Bans</button></div><details class="history-menu"><summary>History <span>${state.changeHistory.length}</span></summary><div>${history.map((entry,index)=>`<button type="button" data-history-index="${state.changeHistory.length-1-index}"><b>${esc(new Intl.DateTimeFormat(undefined,{hour:'2-digit',minute:'2-digit',second:'2-digit'}).format(new Date(entry.at)))}</b><span>${entry.blue.filter(Boolean).length} Blue · ${entry.red.filter(Boolean).length} Red · ${[...entry.blueBans,...entry.redBans].filter(Boolean).length} bans</span></button>`).join('')||'<p>No composition changes yet.</p>'}</div></details></div><div class="mobile-side-tabs segmented" aria-label="Mobile team side"><button type="button" data-mobile-team-side="blue" class="${state.mobileTeamSide==='blue'?'active':''}" aria-pressed="${state.mobileTeamSide==='blue'}">Blue Team</button><button type="button" data-mobile-team-side="red" class="${state.mobileTeamSide==='red'?'active':''}" aria-pressed="${state.mobileTeamSide==='red'}">Red Team</button></div></section>`}
function teamResultTabs(){return `<nav class="team-result-tabs" aria-label="Team analysis sections"><div role="tablist">${availableTeamSections().map(([id,label])=>`<button type="button" role="tab" data-team-section="${id}" aria-selected="${state.teamSection===id}" class="${state.teamSection===id?'active':''}">${label}</button>`).join('')}</div></nav>`}
function teamBoardOnly(){return `${teamDataLegend()}<section class="team-board">${composition('blue')}${faceoffRail()}${composition('red')}</section>`}
function utilityDetailPanel(){const tools=['Shield','Vision','Buff','CC Hard','Heal','Slow','Speed','Cleanse','Damage Reduction','Invulnerability','Untargetability','Revive','Global','Terrain','Zone'];const side=teamSide=>`<section class="utility-detail-side ${teamSide}"><header><b>${teamSide.toUpperCase()}</b><span>Utility sources & skills</span></header>${tools.map(tool=>{const rows=team(teamSide).flatMap(c=>c.abilities.filter(a=>(a.tags||[]).some(tag=>slug(tag).includes(slug(tool))||slug(tool).includes(slug(tag)))).map(a=>({c,a})));return `<article><div><b>${esc(tool)}</b><strong>${rows.length}</strong></div><section>${rows.map(({c,a})=>`<span>${portrait(c,'xs')}${a.images?.[0]?`<img src="${esc(a.images[0])}" alt="">`:''}<b>${esc(c.name)}</b><small>${esc(`${a.slot} · ${a.name}`)}</small></span>`).join('')||'<small>No observed source</small>'}</section></article>`}).join('')}</section>`;return `<div class="mirror-report utility-detail">${side('blue')}${side('red')}</div>`}
function formationDetailPanel(){const side=teamSide=>{const list=team(teamSide),positions=['Frontline','Midline','Backline','Flank'];return `<section class="formation-detail ${teamSide}"><header><b>${teamSide.toUpperCase()}</b><span>Combat line structure</span></header>${positions.map(position=>{const picks=list.filter(c=>c.combat.positioning.includes(position));return `<article><div><b>${position}</b><strong>${picks.length}</strong></div><section>${picks.map(c=>`<span>${portrait(c,'sm')}<b>${esc(c.name)}</b><small>Toughness ${esc(c.ratings.toughness)} · Mobility ${esc(c.ratings.mobility)}</small></span>`).join('')||'<small>Missing line</small>'}</section></article>`}).join('')}</section>`};return `<div class="formation-grid">${formation('blue')}${formation('red')}</div><div class="mirror-report">${side('blue')}${side('red')}</div>`}
function carryStructurePanel(){const side=teamSide=>{const list=team(teamSide),ranked=list.map(c=>({c,score:(c.profiles?.hyperCarry?5:0)+(c.profiles?.carry?3:0)+(Number(c.ratings.damage)||0)+(c.power.late==='Strong'?2:0)})).sort((a,b)=>b.score-a.score),peel=list.filter(c=>hasTeamTag(c,'Shield|Heal|Disengage|Peel|CC Hard'));return `<section class="carry-structure ${teamSide}"><header><b>${teamSide.toUpperCase()}</b><span>Resource & protection plan</span></header>${ranked.map(({c,score},index)=>`<article>${portrait(c,'sm')}<span><small>${index===0?'Primary carry':index===1?'Secondary carry':'Enabler / role player'}</small><b>${esc(c.name)}</b><em>${esc([c.damage.profile,c.power.late].filter(Boolean).join(' · '))}</em></span><strong>${score.toFixed(1)}</strong></article>`).join('')}<footer><b>Peel sources</b>${peel.map(c=>portrait(c,'xs')).join('')||'<span>None</span>'}</footer></section>`};return `<div class="mirror-report">${side('blue')}${side('red')}</div>`}
function teamPlansPanel(){const side=teamSide=>`<section class="team-plan-side ${teamSide}"><header><b>${teamSide.toUpperCase()}</b><span>Champion plans by phase</span></header>${ROLES.map((role,index)=>{const c=byId(state[teamSide][index]),guide=c?guideFor(c):null;return `<details ${index===0?'open':''}><summary><span>${role}</span>${c?portrait(c,'xs'):''}<b>${esc(c?.name||'Empty slot')}</b></summary><div>${PHASES.map(phase=>`<article><b>${phase}</b><p>${esc(guide?.gamePlan?.[phase]||'No observed plan')}</p></article>`).join('')}</div></details>`}).join('')}</section>`;return `<div class="mirror-report">${side('blue')}${side('red')}</div>`}
function teamPowerSpikesPanel(){const side=teamSide=>`<section class="team-spike-side ${teamSide}"><header><b>${teamSide.toUpperCase()}</b><span>Shared power windows</span></header>${PHASES.map(phase=>{const contributors=phaseContributors(teamSide,phase),strong=contributors.filter(item=>item.champion.power[phase]==='Strong');return `<article><div><b>${phase.toUpperCase()}</b><strong>${strong.length} strong</strong></div><section>${contributors.map(({champion,value})=>`<details><summary>${portrait(champion,'xs')}<b>${esc(champion.name)}</b><span>${value.toFixed(2)}</span></summary><p>${esc(guideFor(champion).powerSpikes?.[phase]||'No observed spike')}</p></details>`).join('')}</section></article>`}).join('')}</section>`;return `<div class="mirror-report">${side('blue')}${side('red')}</div>`}
function attackDependencyPanel(){const classify=share=>share<=TEAM_RULES.basicAttackMaxShare?'Ability-based':share<=TEAM_RULES.hybridAttackMaxShare?'Hybrid':'Basic-attack based',side=teamSide=>{const list=team(teamSide),average=list.length?list.reduce((sum,c)=>sum+(Number(c.damage.basicAttackShare)||0),0)/list.length:0,attackers=list.filter(c=>(Number(c.damage.basicAttackShare)||0)>TEAM_RULES.hybridAttackMaxShare),hasAttackDenial=team(teamSide==='blue'?'red':'blue').some(c=>hasTeamTag(c,'Blind|Disarm'));return `<section class="analysis-detail-side ${teamSide}"><header><b>${teamSide.toUpperCase()}</b><span>Attack dependency · ${Math.round(average*100)}% basic attacks</span></header>${list.map(c=>{const share=Number(c.damage.basicAttackShare)||0;return `<article>${portrait(c,'xs')}<span><b>${esc(c.name)}</b><small>${classify(share)}</small></span><meter min="0" max="1" value="${share}">${Math.round(share*100)}%</meter><strong>${Math.round(share*100)}%</strong></article>`}).join('')||'<p>No champions selected.</p>'}${attackers.length&&hasAttackDenial?`<footer class="risk-note"><b>Attack denial risk</b><span>${attackers.map(c=>esc(c.name)).join(', ')} can be heavily affected by Blind or Disarm.</span></footer>`:''}</section>`};return `<div class="mirror-report analysis-detail">${side('blue')}${side('red')}</div>`}
function hardCcDetailPanel(){const hardPattern=/airborne|charm|fear|flee|root|sleep|stun|suppression|taunt|knock|polymorph|cc hard/i,ccRule=tag=>DATA.crowdControl.find(item=>slug(item.name).includes(slug(tag))||slug(tag).includes(slug(item.name))),side=teamSide=>{const rows=team(teamSide).flatMap(c=>c.abilities.flatMap(a=>(a.tags||[]).filter(tag=>hardPattern.test(tag)).map(tag=>({c,a,tag,rule:ccRule(tag)}))));return `<section class="analysis-detail-side ${teamSide}"><header><b>${teamSide.toUpperCase()}</b><span>Hard CC skills · ${rows.length} observed effects</span></header>${rows.map(({c,a,tag,rule})=>`<article>${portrait(c,'xs')}<span><b>${esc(c.name)} · ${esc(a.slot)} ${esc(a.name)}</b><small>${esc(tag)} · ${a.tags.some(value=>/aoe|area|zone/i.test(value))?'AOE':'Single/unspecified'} · Range: unspecified · ${a.slot==='R'?'Ultimate':'Basic skill'} · ${a.tags.some(value=>/engage/i.test(value))?'Engage':'Follow-up'}</small></span><strong title="Tenacity interaction">${esc(rule?.tenacity||'Unknown')}</strong></article>`).join('')||'<p>No hard CC source observed.</p>'}</section>`};return `<div class="mirror-report analysis-detail">${side('blue')}${side('red')}</div>`}
function strongUltimatePanel(){const side=teamSide=>{const rows=team(teamSide).flatMap(c=>c.abilities.filter(a=>a.slot==='R'&&(a.tags.includes('Strong Ult')||a.tags.includes('TeamFight'))).map(a=>({c,a})));return `<section class="analysis-detail-side ${teamSide}"><header><b>${teamSide.toUpperCase()}</b><span>Strong ultimate contributors · ${rows.length}</span></header>${rows.map(({c,a})=>`<article>${a.images?.[0]?`<img class="portrait xs" src="${esc(a.images[0])}" alt="">`:portrait(c,'xs')}<span><b>${esc(c.name)} · R ${esc(a.name)}</b><small>${esc(a.tags.join(' · '))}</small></span><strong>${esc(a.cooldown||'Unknown CD')}</strong></article>`).join('')||'<p>No Strong Ult / TeamFight tag observed.</p>'}${rows.length>=4?'<footer class="risk-note"><b>Cooldown dependency</b><span>Avoid forcing a decisive fight while multiple key ultimates are unavailable.</span></footer>':''}</section>`};return `<div class="mirror-report analysis-detail">${side('blue')}${side('red')}</div>`}
function teamSectionContent(section){if(section==='power')return phaseWeightPanel()+sheetPhaseMatrix();if(section==='combat')return `<div class="sheet-reference-grid">${sheetIdentity()}</div>`+sheetTriggerMatrix()+`<div class="mirror-report">${tacticalFlags('blue')}${tacticalFlags('red')}</div>`+hardCcDetailPanel()+strongUltimatePanel()+`<div class="mirror-report">${rankingBlock('blue')}${rankingBlock('red')}</div>`;if(section==='damage')return `<div class="team-deep-grid">${teamDeepAnalysis('blue')}${teamDeepAnalysis('red')}</div>`+attackDependencyPanel();if(section==='formation')return formationDetailPanel();if(section==='carry')return carryStructurePanel();if(section==='utility')return utilityDetailPanel()+hardCcDetailPanel();if(section==='matchups')return teamLaneDetail()+sheetSkillMatrix();if(section==='gameplan')return teamPlansPanel();if(section==='spikes')return teamPowerSpikesPanel()+strongUltimatePanel();if(section==='warnings')return `<div class="mirror-report">${warningBoard('blue')}${warningBoard('red')}</div>${finalVerdict()}`;return''}
function teamCoreAnalysis(){const bm=teamMetrics('blue'),rm=teamMetrics('red');return `<section class="analysis-grid team-core-analysis"><div class="panel span-2"><div class="section-head"><h3>Core comparison</h3><span>Direct composition metrics</span></div>${metricRow('Early','early',bm,rm,3)}${metricRow('Mid','mid',bm,rm,3)}${metricRow('Late','late',bm,rm,3)}${metricRow('Damage','damage',bm,rm)}${metricRow('Toughness','toughness',bm,rm)}${metricRow('Control','control',bm,rm)}${metricRow('Mobility','mobility',bm,rm)}${metricRow('Utility','utility',bm,rm)}</div><div class="panel"><div class="section-head"><h3>Lane matchup</h3><span>Early power + damage</span></div><div class="lane-list">${laneRows()||'<p class="empty">Choose champions to compare lanes.</p>'}</div></div><div class="panel"><div class="section-head"><h3>Win condition</h3><span>From the selected composition</span></div><div class="win-plan"><div><b>Blue</b>${winCondition('blue','red').map(value=>`<p>${esc(value)}</p>`).join('')}</div><div><b>Red</b>${winCondition('red','blue').map(value=>`<p>${esc(value)}</p>`).join('')}</div></div></div>${teamSummary('blue')}${teamSummary('red')}</section>`}
function renderTeamFull(){return renderTeam()}

const DRAFT_SEQUENCE=[['ban','blueBans',0],['ban','redBans',0],['ban','blueBans',1],['ban','redBans',1],['ban','blueBans',2],['ban','redBans',2],['slot','blue',0],['slot','red',0],['slot','red',1],['slot','blue',1],['slot','blue',2],['slot','red',2],['ban','redBans',3],['ban','blueBans',3],['ban','redBans',4],['ban','blueBans',4],['slot','blue',3],['slot','red',3],['slot','red',4],['slot','blue',4]];
function draftRoster(side){return `<section class="pro-roster ${side}"><header><span>${side==='blue'?'BLUE SIDE':'RED SIDE'}</span><b>${state[side].filter(Boolean).length}/5</b></header><div>${state[side].map((id,index)=>{const c=byId(id);return `<button type="button" class="${c?'filled':''}" data-picker="slot:${side}:${index}"><small>${side==='blue'?'B':'R'}${index+1}</small>${c?portrait(c,'sm'):'<i>+</i>'}<span><b>${esc(c?.name||'Open pick')}</b><em>${esc(c?.roles.join(' · ')||'Flex slot')}</em></span>${c?`<i data-clear="${side}:${index}">×</i>`:''}</button>`}).join('')}</div><footer>${state[`${side}Bans`].map((id,index)=>{const c=byId(id);return `<button type="button" data-picker="ban:${side}Bans:${index}">${c?portrait(c,'xs'):`<span>${index+1}</span>`}<small>${esc(c?.name||`Ban ${index+1}`)}</small></button>`}).join('')}</footer></section>`}
function seriesScore(side){return state.draftSeries.games.filter(game=>game.winner===side).length}
function seriesFinished(){const wins=Math.ceil(state.draftSeries.format/2);return seriesScore('blue')>=wins||seriesScore('red')>=wins||state.draftSeries.currentGame>state.draftSeries.format}
function seriesHistory(){const games=state.draftSeries.games.slice(-4),locked=new Set(fearlessIds());return `<section class="series-history"><div class="section-head"><h3>Previous games · Fearless pool</h3><span>${locked.size} champions locked</span></div>${games.length?`<div class="series-games">${games.map((game,offset)=>{const index=state.draftSeries.games.length-games.length+offset;return `<article><header><b>Game ${game.number}</b><span>${game.winner?`${game.winner} win`:'Result pending'}</span></header><div class="history-side blue"><small>Blue</small>${game.blue.map(id=>portrait(byId(id)||'', 'xs')).join('')}</div><div class="history-side red"><small>Red</small>${game.red.map(id=>portrait(byId(id)||'', 'xs')).join('')}</div><footer><button type="button" data-game-winner="${index}:blue" class="${game.winner==='blue'?'active':''}">Blue win</button><button type="button" data-game-winner="${index}:red" class="${game.winner==='red'?'active':''}">Red win</button></footer></article>`}).join('')}</div>`:'<p class="empty">Chưa có ván trước. Sau khi chốt Game 1, champion đã pick sẽ xuất hiện và bị khóa ở ván sau.</p>'}</section>`}
function assignDraftRoles(ids){const filled=ids.filter(Boolean),best={score:-1,order:ids};function walk(role,remaining,order,score){if(role===ROLES.length){if(score>best.score)best.score=score,best.order=order;return}if(!remaining.length){walk(role+1,remaining,[...order,null],score);return}remaining.forEach((id,i)=>{const c=byId(id),fit=c&&roleFits(c,role)?3:c?.primaryRole===ROLES[role]?2:0;walk(role+1,[...remaining.slice(0,i),...remaining.slice(i+1)],[...order,id],score+fit)})}walk(0,filled,[],0);return best.order}
function completeDraftGame(){if(seriesFinished()){notify('Series đã kết thúc; reset series để bắt đầu lại');return}if(state.blue.filter(Boolean).length<5||state.red.filter(Boolean).length<5){notify('Cần đủ 10 lượt pick trước khi chốt ván');return}const game={number:state.draftSeries.currentGame,blue:[...state.blue],red:[...state.red],blueBans:[...state.blueBans],redBans:[...state.redBans],winner:null};state.draftSeries.games.push(game);state.draftSeries.currentGame++;clearCurrentDraft();save();render();notify(`Đã lưu Game ${game.number} · Fearless pool đã cập nhật`)}
function draftRecommendation(){const turn=DRAFT_SEQUENCE[state.draftStep],side=turn?.[1]?.startsWith('red')?'red':'blue',enemy=side==='blue'?'red':'blue',unavailable=new Set([...selectedIds(),...fearlessIds()]),filters=state.draftFilters,missingRoles=ROLES.filter(role=>!team(side).some(c=>c.roles.includes(role))),mode=turn?.[0]==='ban'&&state.draftMode==='bestFit'?'bestBan':state.draftMode;return CHAMPIONS.filter(c=>!unavailable.has(c.id)&&(!filters.meta||['S+','S'].includes(c.tier))&&(!filters.mastery||c.profiles.mastery)&&(!filters.flex||c.profiles.flex)&&(!filters.flexLane||settingRoles(c).length>1)&&(!filters.carry||c.profiles.carry)).map(c=>{const tier={'S+':4,S:3,'A+':2,A:1}[c.tier]||0,synergy=team(side).reduce((n,ally)=>n+(ally.matchups.synergies.includes(c.name)?2:0),0),counter=team(enemy).reduce((n,foe)=>n+(foe.matchups.counters.includes(c.name)?3:0),0),lane=team(enemy).reduce((n,foe)=>n+(c.matchups.bestLane.includes(foe.name)?3:0),0),threat=team(side).reduce((n,ally)=>n+(ally.matchups.counters.includes(c.name)?3:0),0),roleFit=c.roles.some(role=>missingRoles.includes(role))?3:0,flex=c.profiles.flex?1:0,fit=roleFit+flex+synergy+tier;const score={bestFit:fit,bestBan:threat+tier,counter:counter+tier,bestLane:lane+tier,matchup:counter+lane+synergy}[mode]??fit;return {c,score,reasons:[roleFit?'Covers role':'',flex?'Flex pick':'',settingRoles(c).length>1?'Flex lane':'',tier?'Meta tier':'',synergy?'Synergy':'',counter?'Counters enemy':'',lane?'Favorable lane':'',threat?'Threat to team':''].filter(Boolean)}}).sort((a,b)=>b.score-a.score||a.c.name.localeCompare(b.c.name)).slice(0,16)}
function renderDraft(){const turn=DRAFT_SEQUENCE[state.draftStep],done=state.draftStep>=DRAFT_SEQUENCE.length,recs=draftRecommendation(),locked=fearlessIds(),modes=[['bestFit','Best fit'],['bestBan','Best ban'],['counter','Counter'],['bestLane','Best lane'],['matchup','Matchup']],pickLabel=turn?.[0]==='slot'?`${turn[1]==='blue'?'B':'R'}${turn[2]+1}`:'';return pageIntro('Pro Draft Room',`Game ${state.draftSeries.currentGame} · BO${state.draftSeries.format} · Fearless Draft ${state.draftSeries.fearless?'ON':'OFF'}`,`<button type="button" data-action="reset-draft">Reset game</button><button type="button" data-action="reset-series">Reset series</button>`)+`<section class="series-scoreboard"><div class="blue"><small>BLUE</small><b>${seriesScore('blue')}</b></div><div><span>GAME ${state.draftSeries.currentGame}</span><strong>BEST OF ${state.draftSeries.format}</strong><div class="segmented"><button type="button" data-series-format="3" class="${state.draftSeries.format===3?'active':''}">BO3</button><button type="button" data-series-format="5" class="${state.draftSeries.format===5?'active':''}">BO5</button></div></div><div class="red"><small>RED</small><b>${seriesScore('red')}</b></div></section>${seriesHistory()}<div class="draft-controls"><div class="segmented">${modes.map(([id,label])=>`<button type="button" data-draft-mode="${id}" class="${state.draftMode===id?'active':''}">${label}</button>`).join('')}</div><div class="draft-filter-row"><label><input type="checkbox" data-series-fearless ${state.draftSeries.fearless?'checked':''}><span>Fearless (${locked.length})</span></label>${[['meta','Meta S/S+'],['mastery','Mastery'],['flex','Flex'],['carry','Carry']].map(([id,label])=>`<label><input type="checkbox" data-draft-filter="${id}" ${state.draftFilters[id]?'checked':''}><span>${label}</span></label>`).join('')}</div></div><div class="draft-layout"><section class="draft-main"><div class="draft-status"><span>${done?'Draft complete':`Turn ${state.draftStep+1} / ${DRAFT_SEQUENCE.length}`}</span><h3>${done?'Ready to lock game':`${turn[1].startsWith('blue')?'Blue':'Red'} ${turn[0]==='ban'?`Ban ${turn[2]+1}`:`Pick ${pickLabel}`}`}</h3><div><button type="button" data-action="draft-prev" ${state.draftStep===0?'disabled':''}>Back</button><button type="button" data-action="draft-next" ${done?'disabled':''}>Skip</button>${done?'<button type="button" data-action="auto-roles">Assign roles</button><button type="button" class="primary" data-action="complete-game">Lock game</button>':''}</div></div><div class="pro-draft-board">${draftRoster('blue')}<div class="draft-center"><b>${turn?state.draftStep+1:'✓'}</b><span>${turn?.[0]?.toUpperCase()||'DONE'}</span><small>${locked.length} fearless locks</small></div>${draftRoster('red')}</div><div class="draft-timeline">${DRAFT_SEQUENCE.map(([type,side,index],i)=>{const c=byId(state[side][index]);return `<button type="button" class="${i===state.draftStep?'current':''} ${side.startsWith('red')?'red':''}" data-draft-step="${i}"><small>${i+1} · ${type}</small><b>${esc(c?.name||'—')}</b></button>`}).join('')}</div></section><aside class="draft-assistant"><div class="section-head"><h3>Draft Assistant</h3><span>${modes.find(([id])=>id===state.draftMode)?.[1]}</span></div><div class="recommend-list">${recs.map(({c,score,reasons})=>`<button type="button" data-draft-pick="${c.id}">${portrait(c,'xs')}<span><b>${esc(c.name)}</b><small>${esc(reasons.join(' · ')||c.roles.join(' · '))}</small></span><em>${score}</em></button>`).join('')||'<p class="empty">No legal champion matches these filters.</p>'}</div><div class="draft-needs"><h3>Blue needs</h3>${warnings('blue').map(x=>pill(x,'warning')).join('')||pill('Ready','success')}<h3>Red needs</h3>${warnings('red').map(x=>pill(x,'warning')).join('')||pill('Ready','success')}</div><div class="fearless-locks"><h3>Fearless unavailable</h3><div>${locked.map(id=>portrait(byId(id)||'', 'xs')).join('')||'<small>None yet</small>'}</div></div></aside></div>`}

function championSkillClasses(c){const contract=unique((SETTING.named?.skillChampTypes||[]).filter(value=>value&&!['0','1'].includes(String(value)))),tags=unique([...(c.capabilities||[]),...(c.abilities||[]).flatMap(ability=>ability.tags||[])]);return contract.filter(type=>tags.some(tag=>slug(tag)===slug(type)))}
function championReleaseYear(c){return String(c.metadata?.releaseYear||String(c.metadata?.releaseDate||'').match(/\d{4}/)?.[0]||'')}
function attackStyle(c){const share=Number(c.damage?.basicAttackShare)||0;return share<=TEAM_RULES.basicAttackMaxShare?'Ability':share<=TEAM_RULES.hybridAttackMaxShare?'Hybrid':'Basic attack'}
function relationNameMatch(list,target){const key=slug(target);return (list||[]).some(name=>slug(name)===key)}
function countersTarget(c,targetName){const target=splitName(targetName)||byId(slug(targetName));return relationNameMatch(c.matchups?.bestLane,targetName)||target&&relationNameMatch(target.matchups?.counters,c.name)}
function matchupFitsTarget(c,targetName){const target=splitName(targetName)||byId(slug(targetName));return relationNameMatch(c.matchups?.bestLane,targetName)||relationNameMatch(c.matchups?.synergies,targetName)||target&&relationNameMatch(target.matchups?.bestLane,c.name)}
function finderPass(c){const f=state.finder,group=(selected,values)=>!selected.length||selected.some(x=>values.includes(x)),profiles=Object.entries(c.profiles||{}).filter(([,v])=>v).map(([k])=>k),capabilities=c.capabilities.map(slug),skillEffects=(c.skillTags||c.abilities.flatMap(ability=>ability.tags||[])).map(slug);const hay=[c.name,...c.roles,...Object.values(c.classification),...Object.values(c.combat),...c.capabilities,...c.abilities.map(a=>a.name)].flat().join(' ').toLowerCase();return (!f.search||hay.includes(f.search.toLowerCase()))&&group(f.roles,c.roles)&&group(f.classes,Object.values(c.classification))&&group(f.skillClasses,championSkillClasses(c))&&group(f.combat,[c.combat.primary,c.combat.secondary,c.combat.macro])&&group(f.range,[c.range])&&group(f.tiers,[c.tier])&&group(f.profiles,profiles)&&group(f.damageTypes,[c.damage.type])&&group(f.damageProfiles,[c.damage.profile])&&group(f.positions,c.combat.positioning)&&group(f.attackStyles,[attackStyle(c)])&&(!f.releaseYear||championReleaseYear(c)===String(f.releaseYear))&&f.capabilities.every(x=>capabilities.includes(slug(x)))&&f.skillEffects.every(x=>skillEffects.includes(slug(x)))&&f.counterTargets.every(target=>countersTarget(c,target))&&f.matchupTargets.every(target=>matchupFitsTarget(c,target))&&Object.entries(f.phase).every(([p,v])=>!v||c.power[p]===v)}
function draftPoolCandidates(){const unavailable=new Set([...selectedIds(),...fearlessIds()]),tierValue={'S+':5,S:4,'A+':3,A:2,B:1},mode=state.draftPoolMode;return CHAMPIONS.filter(c=>!unavailable.has(c.id)&&(mode==='all'||mode==='own'&&state.draftOwnPool.includes(c.id)||mode==='enemy'&&state.draftEnemyPool.includes(c.id)||mode==='meta'&&['S+','S','A+'].includes(c.tier)||mode==='flex'&&c.profiles.flex||mode==='flexLane'&&settingRoles(c).length>1)).sort((a,b)=>{if(state.draftSort==='name')return a.name.localeCompare(b.name);if(state.draftSort==='early')return phaseValue(b.power.early)-phaseValue(a.power.early)||a.name.localeCompare(b.name);if(state.draftSort==='late')return phaseValue(b.power.late)-phaseValue(a.power.late)||a.name.localeCompare(b.name);if(state.draftSort==='mastery')return Number(b.profiles.mastery)-Number(a.profiles.mastery)||a.name.localeCompare(b.name);if(state.draftSort==='flexLane')return settingRoles(b).length-settingRoles(a).length||a.name.localeCompare(b.name);return (tierValue[b.tier]||0)-(tierValue[a.tier]||0)||a.name.localeCompare(b.name)})}
function draftPoolBoard(){const list=draftPoolCandidates(),modes=[['all','All'],['own','Own pool'],['enemy','Enemy pool'],['meta','Meta'],['flex','Flex'],['flexLane','Flex lane']];return `<section class="draft-pool-board"><div class="section-head"><h3>Champion pool manager</h3><span>${list.length} legal champions · Fearless locks excluded</span></div><div class="pool-toolbar"><div class="segmented">${modes.map(([id,label])=>`<button type="button" data-pool-mode="${id}" class="${state.draftPoolMode===id?'active':''}">${label}</button>`).join('')}</div><label>Sort<select data-draft-sort><option value="tier" ${state.draftSort==='tier'?'selected':''}>Tier</option><option value="mastery" ${state.draftSort==='mastery'?'selected':''}>Mastery</option><option value="flexLane" ${state.draftSort==='flexLane'?'selected':''}>Flex lanes</option><option value="name" ${state.draftSort==='name'?'selected':''}>Name</option><option value="early" ${state.draftSort==='early'?'selected':''}>Early</option><option value="late" ${state.draftSort==='late'?'selected':''}>Late</option></select></label></div><div class="pool-grid">${list.slice(0,80).map(c=>`<article>${portrait(c,'sm')}<div><b>${esc(c.name)}</b><small>${esc(settingRoles(c).join(' · ')||c.roles.join(' · '))} · ${esc(c.tier||'—')} · ${esc(c.power.early)}/${esc(c.power.late)}</small></div><button type="button" data-draft-pick="${c.id}">Pick</button><label><input type="checkbox" data-pool-assign="own:${c.id}" ${state.draftOwnPool.includes(c.id)?'checked':''}><span>Own</span></label><label><input type="checkbox" data-pool-assign="enemy:${c.id}" ${state.draftEnemyPool.includes(c.id)?'checked':''}><span>Enemy</span></label></article>`).join('')||'<p class="empty">This pool has no legal champion.</p>'}</div></section>`}
function draftWorkbookControls(){const rules=state.draftRestrictions,items=[['onlyBanPool','Only Ban Champion Pool'],['onlyEnemyPool',"Only Pick Enemy's Pool"],['onlyOwnPool','Only Pick Own Pool'],['assistant','Assistant Ban & Pick'],['enabled','Ban & Pick enabled']];const sideNeeds=side=>{const metrics=teamMetrics(side),missing=ROLES.filter(role=>!team(side).some(c=>c.roles.includes(role))),needs=[...missing.map(role=>`Missing ${role}`)];if(!metrics.frontline)needs.push('Need Tank');if(!metrics.engage)needs.push('Need Engage');if(!metrics.magic)needs.push('Need AP');if(!metrics.physical)needs.push('Need AD');return needs};return `<section class="draft-workbook-controls"><div>${items.map(([key,label])=>`<label><input type="checkbox" data-draft-restriction="${key}" ${rules[key]?'checked':''}><span>${label}</span></label>`).join('')}</div><div class="draft-needs-board"><section class="blue"><b>Blue checks</b>${sideNeeds('blue').map(value=>pill(value,'warning')).join('')||pill('Ready','success')}</section><section class="red"><b>Red checks</b>${sideNeeds('red').map(value=>pill(value,'warning')).join('')||pill('Ready','success')}</section></div></section>`}
function draftWorkbookContract(){const filters=[['meta','Meta'],['mastery','Mastery'],['flex','Flex'],['flexLane','Flex lane'],['carry','Carry']];return `<section class="workbook-contract-bar draft-contract"><div class="section-head"><h3>Ban & Pick workbook contract</h3><span>'Ban & pick'!S5:V19</span></div><div>${filters.map(([key,label])=>`<label><input type="checkbox" data-draft-filter="${key}" ${state.draftFilters[key]?'checked':''}><span><small>${esc(label)}</small><b>${state.draftFilters[key]?'Active':'Available'}</b></span></label>`).join('')}</div><p>Counter, Best Lane and Match-up remain recommendation modes; Mastery and Flex lane are independent filters as in the workbook.</p></section>`}
function renderDraftFull(){return renderDraft()+draftWorkbookContract()+draftWorkbookControls()+draftPoolBoard()}
function filterChecks(field,values){return values.map(value=>`<label class="filter-chip"><input type="checkbox" data-filter="${field}" value="${esc(value)}" ${state.finder[field].includes(value)?'checked':''}><span>${esc(value)}</span></label>`).join('')}
function finderCard(c){return `<button type="button" class="finder-card ${state.focus===c.id?'selected':''}" data-focus="${c.id}">${portrait(c)}<span><b>${esc(c.name)}</b><small>${esc(c.roles.join(' · '))} · ${esc(c.classification.primary)}</small><em>${pill(c.combat.primary)}${pill(c.range)}${c.tier?pill(c.tier,'tier'):''}</em></span></button>`}
function miniAbility(a){return `<div class="mini-ability">${a.images[0]?`<img src="${esc(a.images[0])}" alt="${esc(a.name)}" width="36" height="36" loading="lazy" decoding="async">`:'<span>'+esc(a.slot[0])+'</span>'}<div><small>${esc(a.slot)}</small><b>${esc(a.name)}</b><p>${esc(a.tags.join(' · '))}</p></div></div>`}
function laneRelationBlock(title,names,tone){return `<section class="relation-block ${tone}"><div class="section-head"><h3>${title}</h3><span>${names.length}</span></div><div>${names.map((name,index)=>{const c=splitName(name);return `<button type="button" data-matchup-opponent="${c?.id||slug(name)}">${portrait(name,'xs')}<span><b>${esc(name)}</b><small>#${index+1} · ${esc(c?.primaryRole||'')}</small></span></button>`}).join('')||'<p class="empty">Chưa có dữ liệu.</p>'}</div></section>`}
function matchupSourcePanel(champion,opponent,lane){if(!opponent)return'';const a=slug(champion.name),b=slug(opponent.name),counterUrl=`https://www.counterstats.net/league-of-legends/${a}/vs-${b}/${normalizedLane(lane).toLowerCase()}/all`,lolUrl=`https://lolalytics.com/lol/${a}/vs/${b}/build/`;return `<section class="observed-matchup"><div class="section-head"><h3>Observed matchup statistics</h3><span>Live source links used by the workbook</span></div><div class="matchup-versus">${portrait(champion,'sm')}<b>${esc(champion.name)}</b><strong>VS · ${esc(normalizedLane(lane))}</strong>${portrait(opponent,'sm')}<b>${esc(opponent.name)}</b></div><div class="observed-slots">${['Counter kills','Champion kills','Early gold lead','Win percent'].map(label=>`<span><small>${label}</small><b>Open source</b></span>`).join('')}</div><div class="source-actions"><a href="${esc(counterUrl)}" target="_blank" rel="noreferrer">CounterStats ↗</a><a href="${esc(lolUrl)}" target="_blank" rel="noreferrer">Lolalytics ↗</a></div><p>Google Sheets used IMPORTXML for these four values. The static app keeps them separate from inferred pressure and opens the same observed sources.</p></section>`}
function matchupDirectionPanel(champion,opponent,lane){if(!opponent)return'';const a=matchupsFor(champion,lane),b=matchupsFor(opponent,lane),relation=(source,target)=>source.bestLane.includes(target.name)?['Favorable','✓ Listed in favorable lane block','success']:source.counters.includes(target.name)?['Threatened','! Listed in counter block','danger']:source.bans.includes(target.name)?['Ban priority','! Listed in priority ban block','warning']:source.synergies.includes(target.name)?['Synergy only','↔ Listed as duo, not opponent','soft']:['No direct row','— No explicit workbook relation','neutral'],ar=relation(a,opponent),br=relation(b,champion),edge=ar[0]==='Favorable'||br[0]==='Threatened'?champion.name:br[0]==='Favorable'||ar[0]==='Threatened'?opponent.name:'No explicit edge';return `<section class="matchup-direction"><div class="section-head"><h3>Directional relationship audit</h3><span>Counter&Matchup!A1:HT714 · direction is never assumed reciprocal</span></div><div class="direction-versus"><article>${portrait(champion,'sm')}<b>${esc(champion.name)} → ${esc(opponent.name)}</b>${pill(ar[0],ar[2])}<p>${esc(ar[1])}</p></article><strong><small>LANE</small>${esc(lane)}<em>${esc(edge)}</em></strong><article>${portrait(opponent,'sm')}<b>${esc(opponent.name)} → ${esc(champion.name)}</b>${pill(br[0],br[2])}<p>${esc(br[1])}</p></article></div><footer><span>✓ favorable</span><span>! counter / ban</span><span>↔ synergy</span><span>— no direct relation</span></footer></section>`}
function renderMatchupsFull(){const c=byId(state.focus)||CHAMPIONS[0],lanes=matchupLanes(c),lane=lanes.includes(normalizedLane(state.matchupLane))?normalizedLane(state.matchupLane):(lanes[0]||normalizedLane(c.roles[0])),data=matchupsFor(c,lane),opponent=byId(state.matchupOpponent)||splitName(data.counters[0]);return pageIntro('Counter & Matchup','Lane-specific blocks recovered directly from Counter&Matchup I / II / III.',`<button type="button" class="primary" data-picker="focus:focus:0">Chọn champion</button>`)+`<section class="matchup-focus">${portrait(c,'lg')}<div><span>${esc(c.roles.join(' · '))}</span><h2>${esc(c.name)}</h2><p>${esc(c.classification.primary)} · ${esc(c.combat.primary)} · ${esc(c.damage.profile)}</p></div>${phaseStrip(c)}</section><div class="lane-tabs segmented">${lanes.map(value=>`<button type="button" data-matchup-lane="${value}" class="${value===lane?'active':''}">${value}</button>`).join('')}</div><div class="relation-grid">${laneRelationBlock('Counters / threats',data.counters,'danger')}${laneRelationBlock('Favorable lane',data.bestLane,'lane')}${laneRelationBlock('Synergy / best duo',data.synergies,'success')}${laneRelationBlock('Priority bans',data.bans,'warning')}</div>${matchupDirectionPanel(c,opponent,lane)}${matchupSourcePanel(c,opponent,lane)}`}
function focusDetail(c){return `<header class="profile-head">${portrait(c,'lg')}<div><span>${esc(c.roles.join(' · '))}</span><h2>${esc(c.name)}</h2><p>${esc(c.classification.primary)} / ${esc(c.classification.secondary)} · ${esc(c.damage.profile)}</p></div>${c.links.guide?`<a href="${esc(c.links.guide)}" target="_blank" rel="noreferrer">Guide ↗</a>`:''}</header>${championTypeStrip(c)}${phaseStrip(c)}<div class="fact-grid"><span><small>Combat</small><b>${esc(c.combat.primary||'—')}</b></span><span><small>Macro</small><b>${esc(c.combat.macro||'—')}</b></span><span><small>Range</small><b>${esc(c.range)}</b></span><span><small>Difficulty</small><b>${c.difficulty??'—'}</b></span></div><div class="ability-preview">${c.abilities.slice(0,8).map(miniAbility).join('')}</div>`}
function renderFinder(){const results=CHAMPIONS.filter(finderPass),selected=byId(state.focus)||results[0]||CHAMPIONS[0],classes=unique(CHAMPIONS.flatMap(c=>[c.classification.primary,c.classification.secondary])).sort(),combats=unique(CHAMPIONS.flatMap(c=>[c.combat.primary,c.combat.secondary,c.combat.macro])).sort(),caps=['Engage','Disengage','Poke','Pick','CC Hard','Mobility','Dash','Heal','Shield','Slow','Clearwave','Airborne'].filter(x=>CHAMPIONS.some(c=>c.capabilities.includes(x))),tiers=unique(CHAMPIONS.map(c=>c.tier)).sort(),damageTypes=unique(CHAMPIONS.map(c=>c.damage.type)).sort(),years=unique(CHAMPIONS.map(c=>c.metadata?.releaseYear)).sort((a,b)=>b-a);return pageIntro('Champion Finder','Lọc champion bằng vai trò, phase, class, combat, profile và đặc tính kỹ năng. Các nhóm dùng AND; lựa chọn trong cùng nhóm dùng OR.')+`<div class="finder-layout"><aside class="filter-panel"><label class="field"><span>Tìm kiếm</span><input data-finder-search value="${esc(state.finder.search)}" placeholder="Tên, skill, tag..."></label><label class="field"><span>Release year</span><select data-year-filter><option value="">Any</option>${years.map(year=>`<option value="${year}" ${String(state.finder.releaseYear)===String(year)?'selected':''}>${year}</option>`).join('')}</select></label><div class="filter-group"><h3>Role</h3>${filterChecks('roles',ROLES)}</div><div class="filter-group"><h3>Power curve</h3><div class="phase-filters">${PHASES.map(p=>`<label><span>${p}</span><select data-phase-filter="${p}"><option value="">Any</option>${DATA.dictionary.power.map(v=>`<option ${state.finder.phase[p]===v?'selected':''}>${v}</option>`).join('')}</select></label>`).join('')}</div></div><details open><summary>Tier / Meta</summary><div>${filterChecks('tiers',tiers)}</div></details><details open><summary>Profile</summary><div>${filterChecks('profiles',['mastery','carry','hyperCarry','flex'])}</div></details><details open><summary>Class</summary><div>${filterChecks('classes',classes)}</div></details><details><summary>Combat</summary><div>${filterChecks('combat',combats)}</div></details><details><summary>Damage type</summary><div>${filterChecks('damageTypes',damageTypes)}</div></details><details><summary>Range</summary><div>${filterChecks('range',['Melee','Ranged'])}</div></details><details><summary>Required capabilities</summary><div>${filterChecks('capabilities',caps)}</div></details><button type="button" data-action="clear-filters">Xóa bộ lọc</button></aside><section class="finder-results"><div class="result-toolbar"><b>${results.length} champions</b><span>Đặc tính chọn nhiều = phải có đủ</span></div><div class="finder-list">${results.map(finderCard).join('')||'<p class="empty">Không có champion phù hợp.</p>'}</div></section><aside class="finder-detail">${focusDetail(selected)}<section class="finder-relations"><h3>Counter</h3><div>${selected.matchups.counters.slice(0,5).map(name=>pill(name,'danger')).join('')||'—'}</div><h3>Favorable lane</h3><div>${selected.matchups.bestLane.slice(0,5).map(name=>pill(name,'lane')).join('')||'—'}</div><h3>Synergy</h3><div>${selected.matchups.synergies.slice(0,5).map(name=>pill(name,'success')).join('')||'—'}</div></section></aside></div>`}
function finderMatrix(results){return `<section class="champion-matrix"><div class="section-head"><h3>Champion data matrix</h3><span>${results.length} records · cùng bộ lọc phía trên</span></div><div class="cc-table-wrap"><table class="data-table"><thead><tr><th>Champion</th><th>Roles</th><th>Tier</th><th>Early</th><th>Mid</th><th>Late</th><th>Class</th><th>Combat</th><th>Macro</th><th>Range</th><th>Damage</th><th>Profiles</th><th>Capabilities</th><th>Top counters</th><th>Top synergy</th></tr></thead><tbody>${results.map(c=>`<tr data-focus="${c.id}"><td><button type="button" data-focus="${c.id}">${portrait(c,'xs')}<b>${esc(c.name)}</b></button></td><td>${esc(c.roles.join(' · '))}</td><td>${pill(c.tier||'—','tier')}</td><td>${pill(c.power.early,slug(c.power.early))}</td><td>${pill(c.power.mid,slug(c.power.mid))}</td><td>${pill(c.power.late,slug(c.power.late))}</td><td>${esc([c.classification.primary,c.classification.secondary].filter(Boolean).join(' · '))}</td><td>${esc([c.combat.primary,c.combat.secondary].filter(Boolean).join(' · '))}</td><td>${esc(c.combat.macro||'—')}</td><td>${esc(c.range)}</td><td>${esc(`${c.damage.type} · ${c.damage.profile}`)}</td><td>${Object.entries(c.profiles).filter(([,v])=>v).map(([k])=>pill(k)).join('')||'—'}</td><td><b>${c.capabilities.length}</b> ${esc(c.capabilities.slice(0,4).join(' · '))}</td><td>${esc(c.matchups.counters.slice(0,3).join(' · ')||'—')}</td><td>${esc(c.matchups.synergies.slice(0,3).join(' · ')||'—')}</td></tr>`).join('')}</tbody></table></div></section>`}
function checkRelationCell(row,column,lane){const data=matchupsFor(row,lane),name=column.name;if(data.counters.includes(name))return ['C','danger'];if(data.bestLane.includes(name))return ['L','lane'];if(data.synergies.includes(name))return ['D','success'];if(data.bans.includes(name))return ['B','warning'];return ['','']}
function checkWorkbookPanel(results){const focus=byId(state.focus)||results[0]||CHAMPIONS[0],available=matchupLanes(focus),lane=available.includes(normalizedLane(state.checkLane))?normalizedLane(state.checkLane):(available[0]||normalizedLane(focus.primaryRole)),profileMatch=c=>!state.checkProfile||Boolean(c.profiles?.[state.checkProfile]),pool=results.filter(c=>(!state.checkGrade||c.tier===state.checkGrade)&&profileMatch(c)).slice(0,14),columns=CHAMPIONS.filter(c=>c.roles.includes(lane)).slice(0,12),data=matchupsFor(focus,lane);const relationRow=(label,names,tone)=>`<div class="check-relation-row"><b>${label}</b>${names.slice(0,6).map(name=>{const c=splitName(name);return `<button type="button" class="${tone}" ${c?`data-focus="${c.id}"`:''}>${portrait(name,'xs')}<small>${esc(name)}</small></button>`}).join('')||'<span>—</span>'}</div>`;return `<section class="check-workbook"><div class="section-head"><h3>Workbook Check matrix</h3><span>C = counter · L = favorable lane · D = duo · B = ban</span></div><div class="check-controls"><label><span>Lane</span><select data-check-control="checkLane">${ROLES.map(value=>`<option ${value===lane?'selected':''}>${value}</option>`).join('')}</select></label><label><span>Grade</span><select data-check-control="checkGrade"><option value="">All grades</option>${['S+','S','A+','A'].map(value=>`<option ${state.checkGrade===value?'selected':''}>${value}</option>`).join('')}</select></label><label><span>Positive profile</span><select data-check-control="checkProfile"><option value="">Any</option>${[['mastery','Master'],['carry','Carry'],['hyperCarry','Hyper Carry'],['flex','Flex']].map(([value,label])=>`<option value="${value}" ${state.checkProfile===value?'selected':''}>${label}</option>`).join('')}</select></label><div><span>Focused champion</span><b>${portrait(focus,'xs')}${esc(focus.name)}</b></div></div><div class="check-matrix-wrap"><table class="check-matrix"><thead><tr><th>Champion</th>${columns.map(c=>`<th title="${esc(c.name)}">${portrait(c,'xs')}</th>`).join('')}</tr></thead><tbody>${pool.map(row=>`<tr><th><button type="button" data-focus="${row.id}">${portrait(row,'xs')}<span>${esc(row.name)}</span></button></th>${columns.map(column=>{const [mark,tone]=checkRelationCell(row,column,lane);return `<td class="${tone}" title="${esc(row.name)} / ${esc(column.name)}">${mark||'·'}</td>`}).join('')}</tr>`).join('')}</tbody></table></div><div class="check-relations">${relationRow('Counter',data.counters,'danger')}${relationRow('Matchup / best lane',data.bestLane,'lane')}${relationRow('Best duo',data.synergies,'success')}${relationRow('Best ban',data.bans,'warning')}</div></section>`}
function checkSettingPanel(){const raw=(SETTING.named?.typeSkill||[]).filter(Boolean),features=unique(raw).filter(value=>CHAMPIONS.some(c=>c.capabilities.includes(value))),rangeList=keys=>keys.map(key=>SETTING.ranges?.[key]?`Setting!${SETTING.ranges[key]}`:'unmapped').join(' · ');return `<section class="check-setting-panel"><div class="section-head"><h3>Check validation contract</h3><span>Strict dropdowns and helper ranges</span></div><div class="check-contract-row"><span><small>Champion input</small><b>Check!B5 → Check!B7:B</b></span><span><small>Lane validation</small><b>Setting!${esc(SETTING.ranges?.lanes||'N4:N8')}</b></span><span><small>Feature slots 1–5</small><b>${esc(rangeList(['checkFeature1','checkFeature2','checkFeature3','checkFeature4','checkFeature5']))}</b></span><span><small>Counter slots 1–5</small><b>${esc(rangeList(['checkCounter1','checkCounter2','checkCounter3','checkCounter4','checkCounter5']))}</b></span></div><details><summary><b>All mapped Type Skill filters</b><span>${features.length} available in current champion data</span></summary><div class="check-feature-cloud">${features.map(value=>`<label class="filter-chip"><input type="checkbox" data-filter="capabilities" value="${esc(value)}" ${state.finder.capabilities.includes(value)?'checked':''}><span>${esc(value)}</span></label>`).join('')}</div></details></section>`}
function checkSkillClassPanel(){const classes=unique((SETTING.named?.skillChampTypes||[]).filter(value=>value&&!['0','1'].includes(String(value)))),available=classes.filter(value=>CHAMPIONS.some(c=>championSkillClasses(c).includes(value)));return `<section class="check-skill-classes"><div class="section-head"><h3>Skill class contract</h3><span>Setting!${esc(SETTING.ranges?.skillChampTypes||'Q4:Q182')} · exact tag matching</span></div><p>Skill class is independent from champion class. Values come from the Setting dropdown contract and match normalized ability tags without free-text guessing.</p><div>${available.map(value=>`<label class="filter-chip"><input type="checkbox" data-filter="skillClasses" value="${esc(value)}" ${state.finder.skillClasses.includes(value)?'checked':''}><span>${esc(value)}</span></label>`).join('')}</div></section>`}
function checkFilterToggle(field,value,label,code=''){const active=state.finder[field]?.includes(value),exists=CHAMPIONS.some(c=>{if(field==='roles')return c.roles.includes(value);if(field==='classes')return Object.values(c.classification).includes(value);if(field==='combat')return [c.combat.primary,c.combat.secondary,c.combat.macro].includes(value);if(field==='capabilities')return c.capabilities.some(item=>slug(item)===slug(value));if(field==='tiers')return c.tier===value;if(field==='profiles')return Boolean(c.profiles?.[value]);if(field==='attackStyles')return attackStyle(c)===value;return true}),iconKey=field==='roles'?'role':field==='classes'?'className':field==='combat'?'combat':field==='capabilities'?'combat':field==='damageTypes'||field==='damageProfiles'||field==='attackStyles'?'damage':field==='range'?'range':'className';return `<label class="check-filter-toggle ${active?'active':''} ${exists?'':'unavailable'}" title="${esc(label)}"><input type="checkbox" data-filter="${field}" value="${esc(value)}" ${active?'checked':''} ${exists?'':'disabled'}><span><b class="check-filter-icon">${filterIcon(iconKey,value)}</b>${code?`<em>${esc(code)}</em>`:''}<small>${esc(label)}</small></span></label>`}
function checkSelect(field,label,values){const active=state.finder[field]?.[0]||'';return `<label class="check-select"><span>${esc(label)}</span><select data-check-select="${field}"><option value="">Any</option>${values.map(value=>`<option value="${esc(value)}" ${active===value?'selected':''}>${esc(value)}</option>`).join('')}</select></label>`}
function checkMultiFilter(field,label,values,{mode='OR',open=false}={}){const selected=state.finder[field]||[];return `<details class="check-multi-filter" ${open?'open':''}><summary><span>${esc(label)}</span><b><i>${selected.length||'Any'}</i><em>${mode}</em></b></summary><div>${values.map(value=>{const item=Array.isArray(value)?value:[value,''];return checkFilterToggle(field,item[0],item[0],item[1])}).join('')}</div></details>`}
function checkFeatureOptions(){const priority=['Engage','Disengage','Poke','Catch','Dive','CC','CC Hard','CC Chain','Mobility','Dash','Blink','Heal','Shield','Slow','Clearwave','Vision','WooCombo','Strong Ult','Global','Buff','Reset','Peel','Burst','Dps','Sustain','Pick'],counts=new Map();CHAMPIONS.forEach(c=>(c.capabilities||[]).forEach(value=>counts.set(value,(counts.get(value)||0)+1)));return unique([...priority,...[...counts.keys()].sort((a,b)=>(counts.get(b)||0)-(counts.get(a)||0)||a.localeCompare(b))]).filter(value=>counts.has(value))}
function finderList(field){if(!state.finder)state.finder=structuredClone(DEFAULT_STATE.finder);if(!Array.isArray(state.finder[field]))state.finder[field]=[];return state.finder[field]}
function refreshFinderFocus(){const current=byId(state.focus);if(current&&finderPass(current))return;const next=CHAMPIONS.find(champion=>finderPass(champion));if(next)state.focus=next.id}
function checkRelationSlots(title,names,tone){const list=(names||[]).filter(Boolean);return `<div class="check-slot-row ${tone}"><b><span>${title}</span><small>${list.length}</small></b><section>${list.map(name=>{const champion=splitName(name);return `<button type="button" class="${tone} filled" ${champion?`data-focus="${champion.id}"`:''}>${portrait(name,'xs')}<small>${esc(name)}</small></button>`}).join('')||'<span class="empty-slot">—</span>'}</section></div>`}
function checkHoverCard(c){const tags=[c.classification.primary,c.damage.profile,c.range,attackStyle(c),c.combat.primary,c.combat.macro].filter(Boolean),aa=Math.round((Number(c.damage?.basicAttackShare)||0)*100),skill=Math.max(0,100-aa);return `<span class="check-hover-card" role="tooltip"><span class="check-hover-head">${portrait(c,'sm')}<span><small>${esc(c.roles.join(' / '))} · ${esc(c.tier||'No grade')}</small><b>${esc(c.name)}</b><em>${esc(c.damage.type)} · ${esc(c.damage.profile)}</em></span></span><span class="check-hover-tags">${tags.map(tag=>pill(tag,semanticTone(tag))).join('')}</span><span class="check-hover-bars"><i><small>AA</small><b style="width:${aa}%"></b><em>${aa}%</em></i><i><small>Skill</small><b style="width:${skill}%"></b><em>${skill}%</em></i></span><span class="check-hover-rel"><small>Counter ${c.matchups?.counters?.length||0}</small><small>Matchup ${c.matchups?.bestLane?.length||0}</small><small>Duo ${c.matchups?.synergies?.length||0}</small></span></span>`}
function renderCheckSelector(){
  const matches=CHAMPIONS.filter(finderPass),selected=byId(state.focus)||matches[0]||CHAMPIONS[0],selectedLane=state.finder.roles[0]||normalizedLane(state.checkLane)||normalizedLane(selected.primaryRole),relationLane=matchupLanes(selected).includes(selectedLane)?selectedLane:(matchupLanes(selected)[0]||selectedLane),relations=matchupsFor(selected,relationLane);
  const years=unique(CHAMPIONS.map(championReleaseYear)).filter(Boolean).sort((a,b)=>Number(b)-Number(a)),classes=unique(CHAMPIONS.flatMap(c=>[c.classification.primary,c.classification.secondary])).filter(Boolean).sort(),damageProfiles=unique(CHAMPIONS.map(c=>c.damage.profile)).filter(Boolean).sort(),damageTypes=unique(CHAMPIONS.map(c=>c.damage.type)).filter(Boolean).sort(),positions=unique(CHAMPIONS.flatMap(c=>c.combat.positioning)).filter(Boolean).sort(),skillClasses=unique(CHAMPIONS.flatMap(championSkillClasses)).filter(Boolean).sort(),skillEffects=unique(CHAMPIONS.flatMap(c=>c.skillTags||[])).filter(Boolean).sort((a,b)=>a.localeCompare(b)),championNames=CHAMPIONS.map(c=>c.name).sort((a,b)=>a.localeCompare(b));
  const roleCodes={Top:'T',Jungle:'J',Mid:'M',AD:'A',Support:'S'},classCodes={Fighter:'FI',Mage:'MG',Marksman:'MM',Slayer:'SL',Tank:'TK',Controller:'CT',Specialist:'SP'};
  const combat=unique(CHAMPIONS.flatMap(c=>[c.combat.primary,c.combat.secondary,c.combat.macro])).filter(Boolean).sort(),features=checkFeatureOptions();
  return pageIntro('Check champion pool','All champions remain in fixed positions. Matching records are active; records missing any selected requirement are dimmed.',`<button type="button" data-action="clear-filters">Clear all</button>`)+`<section class="check-selector">
    <div class="check-topbar check-topbar-compact">
      <label class="check-year"><span>Year</span><select data-year-filter><option value="">Any</option>${years.map(year=>`<option value="${year}" ${state.finder.releaseYear===year?'selected':''}>${year}</option>`).join('')}</select></label>
      <div class="check-icon-group"><span>Lane</span><div>${ROLES.map(role=>`<button type="button" data-check-role="${role}" class="${state.finder.roles.includes(role)?'active':''}" aria-pressed="${state.finder.roles.includes(role)}"><b class="check-lane-icon">${filterIcon('role',role)}</b><em>${roleCodes[role]}</em><small data-no-translate>${role}</small></button>`).join('')}</div></div>
      <label class="check-search"><span>Search</span><input data-finder-search value="${esc(state.finder.search)}" placeholder="Champion, skill, tag..."></label>
    </div>
    <div class="check-body">
      <aside class="check-name-rail"><header><b>${matches.length}</b><span>available</span></header><div>${matches.map(c=>`<button type="button" data-focus="${c.id}" class="${c.id===selected.id?'active':''}" aria-pressed="${c.id===selected.id}"><i>${filterIcon('role',c.primaryRole)}</i><span>${esc(c.name)}</span></button>`).join('')||'<p>No match</p>'}</div></aside>
      <main class="check-champion-grid" style="--check-columns:13">${CHAMPIONS.map(c=>{const available=finderPass(c),isSelected=c.id===selected.id;return `<button type="button" data-focus="${c.id}" class="${available?'available':'dimmed'} ${isSelected?'selected':''}" aria-pressed="${isSelected}" title="${esc(c.name)} · ${esc(c.roles.join(', '))} · ${esc(c.classification.primary)}">${portrait(c,'xs')}<span class="check-champ-label"><b>${esc(c.name)}</b><small data-no-translate>${esc(c.primaryRole)}</small></span><i class="check-champ-icons">${filterIcon('role',c.primaryRole)}${filterIcon('className',c.classification.primary)}</i>${checkHoverCard(c)}</button>`}).join('')}</main>
      <aside class="check-filter-console">
        <section class="check-selected-preview">${portrait(selected,'lg')}<div><small>${esc(relationLane)} · ${esc(selected.tier||'No grade')}</small><h3>${esc(selected.name)}</h3><p>${esc(selected.roles.join(' · '))} · ${esc(selected.damage.profile)}</p><div>${selected.capabilities.slice(0,4).map(value=>pill(value)).join('')}</div></div></section>
        <div class="check-phase-row">${PHASES.map(phase=>`<label><span>${phase}</span><select data-phase-filter="${phase}"><option value="">Any</option>${DATA.dictionary.power.map(value=>`<option value="${value}" ${state.finder.phase[phase]===value?'selected':''}>${value}</option>`).join('')}</select></label>`).join('')}</div>
        <div class="check-dropdown-grid check-single-grid">${checkSelect('damageProfiles','Style damage',damageProfiles)}${checkSelect('damageTypes','Type damage',damageTypes)}${checkSelect('range','Range type',['Melee','Ranged'])}${checkSelect('skillClasses','Skill tags',skillClasses)}</div>
        <section class="check-icon-row check-attack-style"><header><span>Skill type</span><b>${state.finder.attackStyles.length||'Any'}</b></header><div>${[['Ability','AP'],['Hybrid','HY'],['Basic attack','AA']].map(([value,code])=>checkFilterToggle('attackStyles',value,value,code)).join('')}</div></section>
        <section class="check-relation-pickers"><header><span>Counter / Matchup target</span><b>${state.finder.counterTargets.length+state.finder.matchupTargets.length||'Any'}</b></header><div>${checkSelect('counterTargets','Counter',championNames)}${checkSelect('matchupTargets','Matchup',championNames)}</div></section>
        ${checkMultiFilter('classes','Class',Object.entries(classCodes),{mode:'OR',open:true})}
        ${checkMultiFilter('positions','Position',positions.map(value=>[value,{Frontline:'F',Midline:'M',Backline:'B',Flank:'FL'}[value]||'']),{mode:'OR',open:true})}
        ${checkMultiFilter('combat','Combat',combat,{mode:'OR',open:true})}
        ${checkMultiFilter('capabilities','Skill features',features,{mode:'AND',open:true})}
        <section class="check-icon-row check-positive-row"><header><span>Positive</span><b>${state.finder.profiles.length||'Any'}</b></header><div>${[['mastery','Master'],['carry','Carry'],['hyperCarry','Hyper Carry'],['flex','Flex']].map(([value,label])=>checkFilterToggle('profiles',value,label,{mastery:'M',carry:'C',hyperCarry:'HC',flex:'F'}[value])).join('')}</div></section>
        <div class="check-grade check-grade-compact"><span>Meta grade</span>${['S+','S','A+','A'].map(value=>checkFilterToggle('tiers',value,value,value)).join('')}</div>
        <section class="check-effect-picker">
          <header><span>Skill effects / tags · AND</span><b>${state.finder.skillEffects.length}</b></header>
          <div>${state.finder.skillEffects.map(value=>`<button type="button" data-check-effect-remove="${esc(value)}" title="${state.lang==='vi'?'Gỡ':'Remove'} ${esc(value)}"><span>${esc(value)}</span><b aria-hidden="true">×</b></button>`).join('')||'<p>Select one or more effects from the menu below.</p>'}</div>
          <label><span>Add effect</span><select data-check-effect-add><option value="">Choose effect / tag...</option>${skillEffects.filter(value=>!state.finder.skillEffects.includes(value)).map(value=>`<option value="${esc(value)}">${esc(value)}</option>`).join('')}</select></label>
        </section>
      </aside>
    </div>
    <footer class="check-output">${checkRelationSlots('Counter',relations.counters,'danger')}${checkRelationSlots('Matchup',relations.bestLane,'lane')}${checkRelationSlots('Best duo',relations.synergies,'success')}${checkRelationSlots('Best ban',relations.bans,'warning')}</footer>
  </section>`;
}
function renderFinderFull(){return renderCheckSelector()}

function relationBlock(title,names,tone){return `<section class="relation-block ${tone}"><div class="section-head"><h3>${title}</h3><span>${names.length}</span></div><div>${names.slice(0,40).map(name=>{const c=splitName(name);return `<button type="button" ${c?`data-focus="${c.id}"`:''}>${portrait(name,'xs')}<span><b>${esc(name)}</b><small>${esc(c?.primaryRole||'')}</small></span></button>`}).join('')||'<p class="empty">Chưa có dữ liệu.</p>'}</div></section>`}
function renderMatchups(){const c=byId(state.focus)||CHAMPIONS[0],records=matchupRecords(c);return pageIntro('Counter & Matchup','Bốn quan hệ độc lập: khắc chế, kèo lane thuận lợi, đồng đội phối hợp tốt và ưu tiên cấm.',`<button type="button" class="primary" data-picker="focus:focus:0">Chọn champion</button>`)+`<section class="matchup-focus">${portrait(c,'lg')}<div><span>${esc(c.primaryRole)}</span><h2>${esc(c.name)}</h2><p>${esc(c.classification.primary)} · ${esc(c.combat.primary)} · ${esc(c.damage.profile)}</p></div>${phaseStrip(c)}</section><div class="relation-grid">${relationBlock('Counters / threats',c.matchups.counters,'danger')}${relationBlock('Favorable lane',c.matchups.bestLane,'lane')}${relationBlock('Synergy / best duo',c.matchups.synergies,'success')}${relationBlock('Priority bans',c.matchups.bans,'warning')}</div><section class="matchup-evidence"><div class="section-head"><h3>Normalized relationship evidence</h3><span>Không tạo win rate khi nguồn không có số liệu</span></div><div class="cc-table-wrap"><table class="data-table"><thead><tr><th>Rank</th><th>Champion</th><th>Relationship</th><th>Lane</th><th>Confidence</th><th>Source</th></tr></thead><tbody>${records.filter(r=>r.rank<=8).map(r=>`<tr><td>${r.rank}</td><td>${esc(r.targetName)}</td><td>${esc(r.relation)}</td><td>${esc(r.lane)}</td><td>${pill(r.confidence,r.confidence==='High'?'success':'soft')}</td><td>${esc(r.source)}</td></tr>`).join('')}</tbody></table></div></section>`}

function formation(side){return `<div class="formation ${side}">${team(side).map((c,i)=>`<div class="formation-unit position-${slug(c.combat.positioning[0]||['Frontline','Midline','Backline'][i%3])}">${portrait(c,'sm')}<span>${esc(c.name)}</span></div>`).join('')||'<p>Chưa có đội hình</p>'}</div>`}
function triggerRows(side){return team(side).map(c=>`<div class="trigger-champion">${portrait(c,'xs')}<b>${esc(c.name)}</b><div>${c.abilities.filter(a=>a.tags.length).slice(0,5).map(a=>`<span title="${esc(a.tags.join(', '))}">${a.images[0]?`<img src="${esc(a.images[0])}" alt="${esc(a.name)}" width="28" height="28" loading="lazy" decoding="async">`:esc(a.slot)}</span>`).join('')}</div></div>`).join('')}
function fightRoles(side){const list=team(side),rank=key=>[...list].sort((a,b)=>(Number(b.ratings[key])||0)-(Number(a.ratings[key])||0))[0];return {carry:rank('damage'),frontline:rank('toughness'),controller:rank('control'),peel:rank('utility'),engage:list.find(c=>c.combat.primary==='Engage'||hasCapability(c,'Engage','Airborne','Stun'))}}
function fightPlan(side,enemy,phase){const m=teamMetrics(side),e=teamMetrics(enemy),roles=fightRoles(side),items=[];items.push(m.poke>e.poke?'Bào máu trước khi bước vào tầm mở giao tranh.':'Giữ đội hình ngoài tầm poke và vào combat theo một nhịp.');items.push(m.engage>e.disengage?`Mở giao tranh bằng ${roles.engage?.name||'nguồn engage chính'} khi carry địch lộ vị trí.`:'Giữ kỹ năng phản giao tranh, không dùng hết CC vào frontline.');items.push(m.frontline?`Đánh front-to-back, bảo vệ ${roles.carry?.name||'carry'} ở tuyến sau.`:'Dùng flank/catch; tránh giao tranh kéo dài trực diện.');if(phase==='late')items.push('Không face-check. Kiểm tra bụi bằng skill và giữ carry ngoài choke.');return items}
function renderTeamfight(){const b=teamMetrics('blue'),r=teamMetrics('red'),bs=teamScore('blue'),rs=teamScore('red'),phase=state.teamfightPhase,br=fightRoles('blue'),rr=fightRoles('red');return pageIntro('Teamfight analysis','Đọc đội hình theo vị trí giao tranh, nguồn mở combat, chuỗi CC, bảo kê và trọng số chỉ số.',`<div class="segmented">${PHASES.map(p=>`<button type="button" data-teamfight-phase="${p}" class="${phase===p?'active':''}">${p}</button>`).join('')}</div><button type="button" data-route="team">Sửa đội hình</button>`)+`<div class="teamfight-score"><div class="blue"><small>Blue weighted score</small><b>${bs.toFixed(1)}</b></div><span>${bs===rs?'Cân bằng':bs>rs?'Blue có lợi thế':'Red có lợi thế'}</span><div class="red"><small>Red weighted score</small><b>${rs.toFixed(1)}</b></div></div><div class="formation-grid">${formation('blue')}${formation('red')}</div><div class="analysis-grid"><section class="panel span-2"><div class="section-head"><h3>Combat matrix</h3><span>Dùng weight trong Settings</span></div>${metricRow('Damage','damage',b,r)}${metricRow('Toughness','toughness',b,r)}${metricRow('Control','control',b,r)}${metricRow('Mobility','mobility',b,r)}${metricRow('Utility','utility',b,r)}${metricRow('Engage','engage',b,r,8)}${metricRow('Disengage','disengage',b,r,8)}${metricRow('Poke','poke',b,r,8)}</section><section class="panel"><div class="section-head"><h3>Blue skill triggers</h3><span>Skill-level</span></div>${triggerRows('blue')||'<p class="empty">Chưa có dữ liệu</p>'}</section><section class="panel"><div class="section-head"><h3>Red skill triggers</h3><span>Skill-level</span></div>${triggerRows('red')||'<p class="empty">Chưa có dữ liệu</p>'}</section></div><div class="fight-role-grid">${[['Blue',br,'blue'],['Red',rr,'red']].map(([label,roles,tone])=>`<section class="${tone}"><h3>${label} combat roles</h3>${Object.entries(roles).map(([role,c])=>`<div><span>${role}</span>${c?portrait(c,'xs'):''}<b>${esc(c?.name||'—')}</b></div>`).join('')}<article>${fightPlan(tone,tone==='blue'?'red':'blue',phase).map((x,i)=>`<p><b>${i+1}</b>${esc(x)}</p>`).join('')}</article></section>`).join('')}</div>`}

function comparePicker(field,c,label){return `<button type="button" class="compare-pick" data-picker="focus:${field}:0">${portrait(c,'lg')}<span><small>${label}</small><b>${esc(c.name)}</b><em>${esc(c.roles.join(' · '))}</em></span></button>`}
function statCompare(a,b,key,label,max=5){const av=Number(a.ratings[key])||0,bv=Number(b.ratings[key])||0;return `<div class="stat-compare"><b>${label}</b><span>${av}</span><div><i style="width:${av/max*50}%"></i><i style="width:${bv/max*50}%"></i></div><span>${bv}</span></div>`}
function baseStatCompare(a,b){const keys=unique([...Object.keys(a.baseStats||{}),...Object.keys(b.baseStats||{})]);return `<section class="compare-stat-table"><div class="section-head"><h3>Full base stats</h3><span>Giá trị gốc và cấp 18 khi có dữ liệu</span></div><div class="cc-table-wrap"><table class="data-table"><thead><tr><th>Stat</th><th>${esc(a.name)}</th><th>Delta</th><th>${esc(b.name)}</th><th>Leader</th></tr></thead><tbody>${keys.map(key=>{const av=Number(a.baseStats?.[key]),bv=Number(b.baseStats?.[key]),valid=Number.isFinite(av)&&Number.isFinite(bv),delta=valid?av-bv:null;return `<tr><td><b>${esc(key)}</b></td><td>${Number.isFinite(av)?av:'—'}</td><td>${delta==null?'—':`${delta>0?'+':''}${Number(delta.toFixed(2))}`}</td><td>${Number.isFinite(bv)?bv:'—'}</td><td>${!valid?'—':delta===0?'Equal':delta>0?esc(a.name):esc(b.name)}</td></tr>`}).join('')}</tbody></table></div></section>`}
function renderCompare(){const a=byId(state.compareA)||CHAMPIONS[0],b=byId(state.compareB)||CHAMPIONS[1],ag=guideFor(a),bg=guideFor(b);return pageIntro('Champion compare','So sánh trực tiếp phase, chỉ số, damage profile, độ khó, bộ kỹ năng và cách sử dụng.')+`<div class="compare-select">${comparePicker('compareA',a,'Champion A')}<span>VS</span>${comparePicker('compareB',b,'Champion B')}</div><div class="compare-layout"><section class="panel"><h3>${esc(a.name)}</h3>${phaseStrip(a)}<p>${esc(ag.strengths||'Chưa có mô tả.')}</p></section><section class="panel compare-center">${statCompare(a,b,'damage','Damage')}${statCompare(a,b,'toughness','Toughness')}${statCompare(a,b,'control','Control')}${statCompare(a,b,'mobility','Mobility')}${statCompare(a,b,'utility','Utility')}<div class="compare-facts"><span>${esc(a.damage.profile)}</span><b>Damage</b><span>${esc(b.damage.profile)}</span><span>${a.difficulty??'—'}</span><b>Difficulty</b><span>${b.difficulty??'—'}</span><span>${esc(a.range)}</span><b>Range</b><span>${esc(b.range)}</span><span>${esc(a.metadata?.patch||'—')}</span><b>Patch</b><span>${esc(b.metadata?.patch||'—')}</span></div></section><section class="panel"><h3>${esc(b.name)}</h3>${phaseStrip(b)}<p>${esc(bg.strengths||'Chưa có mô tả.')}</p></section></div>${baseStatCompare(a,b)}<section class="compare-guides"><article><h3>${esc(a.name)} · Game plan</h3><p class="weakness">${esc(ag.weaknesses||'—')}</p>${PHASES.map(p=>`<div><b>${p}</b><p>${esc(ag.gamePlan?.[p]||'Chưa có dữ liệu.')}</p><small>${esc(ag.powerSpikes?.[p]||'Chưa có dữ liệu.')}</small></div>`).join('')}</article><article><h3>${esc(b.name)} · Game plan</h3><p class="weakness">${esc(bg.weaknesses||'—')}</p>${PHASES.map(p=>`<div><b>${p}</b><p>${esc(bg.gamePlan?.[p]||'Chưa có dữ liệu.')}</p><small>${esc(bg.powerSpikes?.[p]||'Chưa có dữ liệu.')}</small></div>`).join('')}</article></section><section class="ability-compare"><div>${a.abilities.map(miniAbility).join('')}</div><div>${b.abilities.map(miniAbility).join('')}</div></section>`}

function objectivePlan(side,phase){const m=teamMetrics(side),plans=[];if(phase==='early'){plans.push(m.early>=2.2?'Tranh quyền đi trước và ép cua / rồng đầu.':'Ưu tiên giữ wave, tránh mất tempo vì giao tranh sớm.');if(m.mobilitySources>1)plans.push('Dùng mobility để tạo quân số ở sông.')}if(phase==='mid'){plans.push(m.engage>m.poke?'Thiết lập góc flank trước Herald/Rồng.':'Bào máu và giữ khoảng cách trước khi ăn mục tiêu.');if(m.clearwave>50)plans.push('Đẩy wave trước rồi mới kiểm soát vision.')}if(phase==='late'){plans.push(m.frontline?'Đặt frontline vào choke, carry giữ tầm đánh.':'Không face-check; dùng skill tầm xa kiểm tra bụi.');plans.push(m.split?'Tạo áp lực cánh trước Baron/Elder.':'Giữ đội hình 5 người quanh mục tiêu.')}return plans}
function jungleRouteFor(side){const selected=state[side==='blue'?'mapRouteBlue':'mapRouteRed'],manual=DATA.jungleRoutes.find(route=>route.name===selected);if(manual)return manual;const jungler=byId(state[side][1]);if(!jungler)return DATA.jungleRoutes[0];const aggressive=jungler.power.early==='Strong'||jungler.combat.primary==='Engage';return DATA.jungleRoutes.find(r=>aggressive?r.earlyGank:!r.earlyGank)||DATA.jungleRoutes[0]}
function statAtLevel(c,key,level){const base=Number(c.baseStats?.[key]),at18=Number(c.baseStats?.[`${key}18`]);if(!Number.isFinite(base))return null;if(!Number.isFinite(at18)||level<=1)return base;return base+(at18-base)*(level-1)/17}
function compareLevelPanel(){const a=byId(state.compareA)||CHAMPIONS[0],b=byId(state.compareB)||CHAMPIONS[1],level=state.compareLevel,stats=[['hp','HP'],['hpRegen','HP5'],['mp','MP'],['mpRegen','MP5'],['ad','AD'],['as','AS'],['ar','Armor'],['mr','MR'],['ms','Move speed'],['range','Range']];return `<section class="level-compare"><div class="section-head"><h3>Level-scaled stats</h3><label>Level <b>${level}</b><input type="range" min="1" max="18" value="${level}" data-compare-level></label></div><div class="level-stat-head"><span>${portrait(a,'sm')}<b>${esc(a.name)}</b></span><strong>LEVEL ${level}</strong><span>${portrait(b,'sm')}<b>${esc(b.name)}</b></span></div><div class="level-stat-grid">${stats.map(([key,label])=>{const av=statAtLevel(a,key,level),bv=statAtLevel(b,key,level),delta=av!=null&&bv!=null?av-bv:null;return `<div><span class="blue">${av==null?'—':Number(av.toFixed(2))}</span><b>${label}<small>${delta==null?'':`${delta>0?'+':''}${Number(delta.toFixed(2))}`}</small></b><span class="red">${bv==null?'—':Number(bv.toFixed(2))}</span></div>`}).join('')}</div></section>`}
function compareLanePanel(){const a=byId(state.compareA)||CHAMPIONS[0],b=byId(state.compareB)||CHAMPIONS[1],all=unique([...matchupLanes(a),...matchupLanes(b)]),common=all.filter(lane=>matchupLanes(a).includes(lane)&&matchupLanes(b).includes(lane)),lanes=common.length?common:all,lane=lanes.includes(normalizedLane(state.compareLane))?normalizedLane(state.compareLane):(lanes[0]||normalizedLane(a.primaryRole)),am=matchupsFor(a,lane),bm=matchupsFor(b,lane),aFav=am.bestLane.includes(b.name)||bm.counters.includes(a.name),bFav=bm.bestLane.includes(a.name)||am.counters.includes(b.name),verdict=aFav===bFav?'No direct sheet edge':aFav?`${a.name} has sheet edge`:`${b.name} has sheet edge`;return `<section class="compare-lane-panel"><div class="section-head"><h3>Lane-specific matchup</h3><span>Counter&Matchup block for the selected lane</span></div><div class="lane-tabs segmented">${lanes.map(value=>`<button type="button" data-compare-lane="${value}" class="${value===lane?'active':''}">${value}</button>`).join('')}</div><div class="compare-lane-verdict"><div>${portrait(a,'sm')}<b>${esc(a.name)}</b><small>${am.counters.includes(b.name)?'Listed as threatened':am.bestLane.includes(b.name)?'Listed favorable':'No direct relation'}</small></div><strong>${esc(verdict)}</strong><div>${portrait(b,'sm')}<b>${esc(b.name)}</b><small>${bm.counters.includes(a.name)?'Listed as threatened':bm.bestLane.includes(a.name)?'Listed favorable':'No direct relation'}</small></div></div>${matchupSourcePanel(a,b,lane)}</section>`}
function soloMatchupBoard(){const a=byId(state.compareA)||CHAMPIONS[0],b=byId(state.compareB)||CHAMPIONS[1],lane=normalizedLane(state.compareLane),ap=lanePressure(a,b,lane),bp=lanePressure(b,a,lane),prob=Math.round(Math.max(15,Math.min(85,50+(ap-bp)*.8))),rows=[['Damage','damage'],['Toughness','toughness'],['Control','control'],['Mobility','mobility'],['Utility','utility']];const side=(c,position)=>`<article class="${position}"><header>${portrait(c,'lg')}<div><small>${esc(lane)} · ${esc(c.range)}</small><h3>${esc(c.name)}</h3><span>${esc(c.classification.primary)} · ${esc(c.damage.profile)}</span></div></header><div class="solo-tags">${[...c.combat.positioning,c.combat.primary,c.combat.secondary,c.combat.macro].filter(Boolean).map(value=>pill(value)).join('')}</div><div class="solo-strong"><small>Strong skill order</small><b>${esc(c.strongSkills||'—')}</b>${c.abilities.filter(skill=>skill.tags.includes('Strong Ult')||skill.tags.includes('TeamFight')).map(skill=>miniAbility(skill)).join('')}</div></article>`;return `<section class="solo-matchup-board"><div class="section-head"><h3>Solo matchup workbook</h3><span>Symmetric lane, role, range and execution comparison</span></div><div class="solo-sides">${side(a,'blue')}<div class="solo-center"><b>${prob}% · ${100-prob}%</b><small>INFERRED LANE PRESSURE</small>${rows.map(([label,key])=>`<div><span>${Number(a.ratings[key])||0}</span><b>${label}</b><span>${Number(b.ratings[key])||0}</span></div>`).join('')}</div>${side(b,'red')}</div></section>`}
function compareWorkbookContract(){const a=byId(state.compareA)||CHAMPIONS[0],b=byId(state.compareB)||CHAMPIONS[1],facts=[['Lane',state.compareLane,'Compare!F2'],['Level',state.compareLevel,'Compare!E4'],['Champion A',a.name,'Compare left block'],['Champion B',b.name,'Compare right block']];return `<section class="workbook-contract-bar"><div class="section-head"><h3>Compare workbook contract</h3><span>Compare!A1:Y37</span></div><div>${facts.map(([label,value,source])=>`<span><small>${esc(label)} · ${esc(source)}</small><b>${esc(value)}</b></span>`).join('')}</div><p>Base stats, phase ratings, game plans, power spikes and skill comparisons update from the same selected pair.</p></section>`}
const COMPARE_LANES=['Top','Jungle','Mid','Bot'];
function compareRole(lane,slot='carry'){return lane==='Bot'?(slot==='support'?'Support':'AD'):lane}
function comparePool(lane,slot='carry'){const role=compareRole(lane,slot);return CHAMPIONS.filter(c=>c.roles.includes(role)).sort((a,b)=>a.name.localeCompare(b.name))}
function normalizeCompareLineup(lane=state.compareLane){
  lane=COMPARE_LANES.includes(lane)?lane:'Top';state.compareLane=lane;
  const assign=(field,slot,excluded=[])=>{const pool=comparePool(lane,slot),current=byId(state[field]);if(!current||!pool.includes(current)||excluded.includes(current.id))state[field]=pool.find(c=>!excluded.includes(c.id))?.id||pool[0]?.id||state[field]};
  assign('compareA','carry');assign('compareB','carry',[state.compareA]);
  if(lane==='Bot'){assign('compareBlueSupport','support',[state.compareA,state.compareB]);assign('compareRedSupport','support',[state.compareA,state.compareB,state.compareBlueSupport])}
  return {blue:[byId(state.compareA),lane==='Bot'?byId(state.compareBlueSupport):null].filter(Boolean),red:[byId(state.compareB),lane==='Bot'?byId(state.compareRedSupport):null].filter(Boolean)}
}
function compareSelect(field,lane,slot,label){const selected=state[field],role=compareRole(lane,slot),blocked={compareA:[state.compareB],compareB:[state.compareA],compareBlueSupport:[state.compareA,state.compareB,state.compareRedSupport],compareRedSupport:[state.compareA,state.compareB,state.compareBlueSupport]}[field]||[],pool=comparePool(lane,slot).filter(c=>c.id===selected||!blocked.includes(c.id));return `<label class="lane-pick-select"><span>${esc(label)}</span><select data-compare-pick="${field}" aria-label="${esc(label)}">${pool.map(c=>`<option value="${c.id}" ${c.id===selected?'selected':''}>${esc(c.name)} · ${esc(role)}</option>`).join('')}</select></label>`}
function sheetRelation(c,opponent,lane){const own=matchupsFor(c,lane),enemy=matchupsFor(opponent,lane);if(own.bestLane.includes(opponent.name)||enemy.counters.includes(c.name))return 1;if(own.counters.includes(opponent.name)||enemy.bestLane.includes(c.name))return -1;return 0}
function duoSynergy(ad,support){if(!ad||!support)return 0;const explicit=matchupsFor(ad,'ADC').synergies.includes(support.name)||matchupsFor(support,'Support').synergies.includes(ad.name),control=Number(support.ratings.control)||0,utility=Number(support.ratings.utility)||0,carry=Number(ad.ratings.damage)||0,range=ad.range==='Ranged'?4:0;return Math.round(Math.min(100,35+(explicit?25:0)+control*6+utility*5+carry*4+range))}
function lineupMetric(list,key){return list.length?list.reduce((sum,c)=>sum+(Number(c.ratings[key])||0),0)/list.length:0}
function lineupPhase(list,phase){return list.length?list.reduce((sum,c)=>sum+phaseValue(c.power[phase]),0)/list.length:0}
function laneCompareModel(lineup,lane){
  const [a,aSupport]=lineup.blue,[b,bSupport]=lineup.red,bot=lane==='Bot';
  const soloBlue=lanePressure(a,b,compareRole(lane)),soloRed=lanePressure(b,a,compareRole(lane));
  const supportBlue=bot?lanePressure(aSupport,bSupport,'Support'):0,supportRed=bot?lanePressure(bSupport,aSupport,'Support'):0;
  const blueDuo=bot?duoSynergy(a,aSupport):0,redDuo=bot?duoSynergy(b,bSupport):0;
  const relation=sheetRelation(a,b,compareRole(lane))+(bot?sheetRelation(aSupport,bSupport,'Support'):0);
  const delta=(soloBlue-soloRed)*(bot ? .45 : .72)+(supportBlue-supportRed)*.35+(blueDuo-redDuo)*.16+relation*6;
  const blue=Math.round(Math.max(15,Math.min(85,50+delta))),red=100-blue;
  const evidence=[`${lane} role fit confirmed`,relation?`${Math.abs(relation)} direct sheet relation${Math.abs(relation)>1?'s':''}`:'No direct counter relation in sheet'];
  if(bot)evidence.push(`Duo synergy ${blueDuo} vs ${redDuo}`);
  evidence.push(`Level ${state.compareLevel} stats available`);
  return {blue,red,blueDuo,redDuo,evidence,confidence:relation||bot?'Medium':'Supporting'}
}
function lineupHeader(list,side,lane){return `<article class="lane-side-card ${side}"><header><small>${side==='blue'?'BLUE SIDE':'RED SIDE'} · ${esc(lane)}</small><strong>${list.length===2?'Bot duo':'Solo lane'}</strong></header><div class="lane-side-picks">${list.map((c,index)=>`<div>${portrait(c,index?'md':'lg')}<span><small>${esc(compareRole(lane,index?'support':'carry'))}</small><b>${esc(c.name)}</b><em>${esc(c.classification.primary)} · ${esc(c.range)}</em></span></div>`).join('')}</div></article>`}
function laneSelectionPanel(lineup,lane,model){return `<section class="lane-compare-hero"><div class="section-head"><div><h2>Lane matchup comparison</h2><p>Only champions valid for the selected lane can be compared.</p></div><span class="data-badge">SHEET-INFERRED · NOT WIN RATE</span></div><nav class="lane-mode-tabs" aria-label="Comparison lane">${COMPARE_LANES.map(value=>`<button type="button" data-compare-lane="${value}" class="${value===lane?'active':''}" aria-pressed="${value===lane}">${value==='Bot'?'Bot · AD + Support':value}</button>`).join('')}</nav><div class="lane-pick-controls"><div>${compareSelect('compareA',lane,'carry',lane==='Bot'?'Blue AD':'Blue champion')}${lane==='Bot'?compareSelect('compareBlueSupport',lane,'support','Blue Support'):''}</div><div class="lane-vs-mark" aria-hidden="true">VS</div><div>${compareSelect('compareB',lane,'carry',lane==='Bot'?'Red AD':'Red champion')}${lane==='Bot'?compareSelect('compareRedSupport',lane,'support','Red Support'):''}</div></div><div class="lane-lineup-grid">${lineupHeader(lineup.blue,'blue',lane)}<div class="lane-compat-score"><small>INFERRED LANE FIT</small><strong>${model.blue}<span>:</span>${model.red}</strong><div class="lane-score-track"><i style="width:${model.blue}%"></i></div><p>${model.blue===model.red?'Balanced lane':model.blue>model.red?'Blue side has the model edge':'Red side has the model edge'} · ${model.confidence} confidence</p></div>${lineupHeader(lineup.red,'red',lane)}</div></section>`}
function laneAxesPanel(lineup,lane,model){const axes=[['Lane pressure',null],['Early','early'],['Mid','mid'],['Late','late'],['Damage','damage'],['Toughness','toughness'],['Control','control'],['Mobility','mobility'],['Utility','utility']],score=(list,key)=>key==='early'||key==='mid'||key==='late'?lineupPhase(list,key):lineupMetric(list,key),pressure=(side)=>side==='blue'?model.blue:model.red;return `<section class="lane-axis-panel"><div class="section-head"><div><h3>${lane==='Bot'?'Duo matchup axes':'Matchup axes'}</h3><p>Ratings are averaged per side so a Bot duo remains comparable.</p></div><div class="lane-evidence">${model.evidence.map(value=>`<span>${termIcon('Check','pill-icon')}${esc(value)}</span>`).join('')}</div></div><div class="lane-axis-grid">${axes.map(([label,key])=>{const av=key?score(lineup.blue,key):pressure('blue'),bv=key?score(lineup.red,key):pressure('red'),max=key?3:100,ap=Math.round(av/max*100),bp=Math.round(bv/max*100);return `<div class="lane-axis-row"><b class="blue-value">${Number(av.toFixed?.(1)??av)}</b><i class="axis-bar blue"><span style="width:${ap}%"></span></i><strong>${esc(label)}<small>${av===bv?'EVEN':av>bv?'BLUE EDGE':'RED EDGE'}</small></strong><i class="axis-bar red"><span style="width:${bp}%"></span></i><b class="red-value">${Number(bv.toFixed?.(1)??bv)}</b></div>`}).join('')}</div>${lane==='Bot'?`<div class="duo-synergy-row"><span><small>BLUE DUO COMPATIBILITY</small><b>${model.blueDuo}/100</b></span><p>Combines explicit sheet synergy, carry damage/range and Support control/utility.</p><span><small>RED DUO COMPATIBILITY</small><b>${model.redDuo}/100</b></span></div>`:''}</section>`}
function decisiveSkills(c){const ranked=[...(c.abilities||[])].sort((a,b)=>Number(b.tags?.some(tag=>['Strong Ult','TeamFight','Engage','Disengage'].includes(tag)))-Number(a.tags?.some(tag=>['Strong Ult','TeamFight','Engage','Disengage'].includes(tag))));return ranked.slice(0,3)}
function laneSkillsPanel(lineup){const cards=(list,side)=>`<div class="${side}">${list.map(c=>`<article><header>${portrait(c,'sm')}<span><small>${esc(c.name)}</small><b>Decisive skills</b></span></header>${decisiveSkills(c).map(miniAbility).join('')}</article>`).join('')}</div>`;return `<section class="lane-skill-board ability-compare"><div class="section-head"><h3>Decisive skills</h3><span>Prioritized by teamfight, engage and disengage tags</span></div><div class="lane-skill-columns">${cards(lineup.blue,'blue')}${cards(lineup.red,'red')}</div></section>`}
function lanePlanPanel(lineup){const side=(list,label)=>`<div>${list.map(c=>{const guide=guideFor(c);return `<details><summary>${portrait(c,'xs')}<b>${esc(c.name)}</b><span>${esc(label)} game plan</span></summary><p class="weakness">${esc(guide.weaknesses||'No weakness note available.')}</p>${PHASES.map(phase=>`<article><b>${phase}</b><p>${esc(guide.gamePlan?.[phase]||'No plan available.')}</p><small>${esc(guide.powerSpikes?.[phase]||'No spike note available.')}</small></article>`).join('')}</details>`}).join('')}</div>`;return `<section class="lane-plan-board"><div class="section-head"><h3>Game plan & power spikes</h3><span>Open only the champion you need</span></div><div>${side(lineup.blue,'Blue')}${side(lineup.red,'Red')}</div></section>`}
function laneCompareContract(lineup,lane){const facts=[['Lane',lane,'Compare!F2'],['Level',state.compareLevel,'Compare!E4'],['Blue',lineup.blue.map(c=>c.name).join(' + '),'Compare left block'],['Red',lineup.red.map(c=>c.name).join(' + '),'Compare right block']];return `<section class="workbook-contract-bar"><div class="section-head"><h3>Compare workbook contract</h3><span>Compare!A1:Y37</span></div><div>${facts.map(([label,value,source])=>`<span><small>${esc(label)} · ${esc(source)}</small><b>${esc(value)}</b></span>`).join('')}</div><p>Bot comparison supplements the workbook with a lane-valid AD + Support pair on each side.</p></section>`}
function renderCompareFull(){const lane=COMPARE_LANES.includes(state.compareLane)?state.compareLane:'Top',lineup=normalizeCompareLineup(lane),model=laneCompareModel(lineup,lane);return pageIntro('Lane compare','Compare a valid same-lane matchup. Bot is modeled as AD + Support versus AD + Support.')+laneSelectionPanel(lineup,lane,model)+laneAxesPanel(lineup,lane,model)+(lane==='Bot'?'':compareLevelPanel())+laneSkillsPanel(lineup)+lanePlanPanel(lineup)+laneCompareContract(lineup,lane)}
function lanePriority(side,index,phase){const c=byId(state[side][index]);return c?phaseValue(c.power[phase])+(Number(c.ratings.clearwave)||0)/50+(Number(c.ratings.mobility)||0)/3:0}
function routeCoordinate(step,route={},index=0){const key=slug(step),gankText=slug(`${route.gankLane||''} ${route.gankSoon||''} ${route.firstGank||''}`),scuttleText=slug(`${route.scuttlerPosition||''} ${route.scuttlerAt||''} ${route.scuttler||''}`),points={bluesentinel:[35,70],bluebuff:[35,70],gromp:[24,68],murkwolves:[39,62],wolves:[39,62],raptors:[52,70],redbrambleback:[60,78],redbuff:[60,78],krugs:[71,84],dragon:[69,68],riftherald:[32,34],herald:[32,34],baron:[31,31],atakhan:[28,32],invade:[74,28]};if(/riftscuttler|scuttle|scuttler/.test(key))return /bot|dragon|lower/.test(scuttleText)?[57,59]:[43,41];if(/gank|dive/.test(key)){if(/top/.test(gankText))return [25,22];if(/mid/.test(gankText))return [50,50];if(/bot|ad|support/.test(gankText))return [77,78];return index<4?[50,50]:[77,78]}const direct=Object.entries(points).find(([name])=>key.includes(name));return direct?.[1]||[50,50]}
function routeStepType(step=''){const key=slug(step);if(/gank|dive/.test(key))return'gank';if(/dragon|herald|baron|rift|atakhan|scuttle/.test(key))return'objective';if(/invade|steal/.test(key))return'invade';return'camp'}
function mapLegend(){const entries=[['camp','Jungle camp'],['gank','Gank / dive'],['objective','River objective'],['invade','Invade / steal'],['blue','Blue route'],['red','Red route']];return `<section class="map-legend" aria-labelledby="map-legend-title"><div><span>MAP VISUAL CONTRACT</span><h3 id="map-legend-title">Marker legend</h3><p>Number shows route order; marker color identifies the action without replacing the workbook text.</p></div><div role="list">${entries.map(([tone,label])=>`<span role="listitem" class="${tone}"><i aria-hidden="true"></i><b>${esc(label)}</b></span>`).join('')}</div></section>`}
function mapRouteVisual(side,route){const marks=route.steps.map((step,index)=>{let [x,y]=routeCoordinate(step,route,index);if(side==='red'){x=100-x;y=100-y}return {step,index,x,y,type:routeStepType(step)}}),poly=marks.map(mark=>`${mark.x},${mark.y}`).join(' ');return `<div class="route-map route-map-icons ${side}"><img src="https://ddragon.leagueoflegends.com/cdn/${DATA.patch}/img/map/map11.png" alt="Summoner's Rift" width="512" height="512" loading="lazy" decoding="async"><svg class="route-polyline" viewBox="0 0 100 100" preserveAspectRatio="none" aria-hidden="true"><polyline points="${poly}"></polyline></svg><div>${marks.map(mark=>`<span class="${mark.type}" style="left:${mark.x}%;top:${mark.y}%" title="${esc(`${mark.index+1}. ${mark.step} · ${mark.type}`)}"><b>${campIcon(mark.step,'route-marker-icon')}<i>${mark.index+1}</i></b><small>${esc(mark.step)}</small></span>`).join('')}</div></div>`}
function mapRouteCard(side){const jungler=byId(state[side][1]),route=normalizedRoute(jungleRouteFor(side));return `<article class="map-route-card ${side}"><header>${jungler?portrait(jungler,'sm'):''}<div><small>${side} jungle</small><h3>${esc(jungler?.name||'Chưa chọn jungler')}</h3></div><b>${esc(route.risk)} risk</b></header>${mapRouteVisual(side,route)}<div class="route-steps route-steps-icons">${route.steps.map((step,i)=>routeStepChip(step,i)).join('')}</div><dl><div><dt>Start</dt><dd>${esc(route.start)}</dd></div><div><dt>First gank</dt><dd>${esc(route.firstGank)}</dd></div><div><dt>Objective intent</dt><dd>${esc(route.objectivePlan)}</dd></div><div><dt>Scuttler</dt><dd>${esc(route.scuttler||'—')}</dd></div></dl>${jungler?`<div class="map-jungle-skills">${jungler.abilities.slice(0,5).map(miniAbility).join('')}</div>`:''}</article>`}
function renderMap(){const phase=state.mapPhase,objectives=[['Void Grubs','early','Top/Mid priority','Medium'],['Dragon','early','Bot/Mid priority','Medium'],['Rift Herald','mid','Top river vision','Medium'],['Baron Nashor','late','Two pushed lanes','High'],['Elder Dragon','late','Full team setup','Critical'],['Atakhan','mid','Tempo and side vision','High']];return pageIntro('Map plan','Chuyển đặc điểm đội hình thành kế hoạch lane priority, đường rừng, vision và mục tiêu theo từng giai đoạn.',`<div class="segmented">${PHASES.map(p=>`<button type="button" data-map-phase="${p}" class="${phase===p?'active':''}">${p}</button>`).join('')}</div>`)+`<div class="map-layout"><section class="map-timeline"><div class="map-lanes"><span>TOP</span><span>RIVER</span><span>MID</span><span>RIVER</span><span>BOT</span>${ROLES.map((role,i)=>{const bp=lanePriority('blue',i,phase),rp=lanePriority('red',i,phase);return `<div class="map-match"><b>${role}</b><span>${byId(state.blue[i])?portrait(byId(state.blue[i]),'xs'):''}${esc(byId(state.blue[i])?.name||'—')}<em>${bp.toFixed(1)}</em></span><strong class="${compareValue(bp,rp)}">${bp===rp?'=':bp>rp?'Blue priority':'Red priority'}</strong><span>${byId(state.red[i])?portrait(byId(state.red[i]),'xs'):''}${esc(byId(state.red[i])?.name||'—')}<em>${rp.toFixed(1)}</em></span></div>`}).join('')}</div><div class="objective-board"><h3>${phase.toUpperCase()} objectives</h3>${objectives.map(([name,p,setup])=>`<span class="${p===phase?'priority':''}"><b>${name}</b><small>${setup}</small></span>`).join('')}</div></section><aside class="map-plans"><section class="blue"><h3>Blue plan</h3>${objectivePlan('blue',phase).map(x=>`<p>${esc(x)}</p>`).join('')}</section><section class="red"><h3>Red plan</h3>${objectivePlan('red',phase).map(x=>`<p>${esc(x)}</p>`).join('')}</section><section><h3>Objective checklist</h3><p>Đẩy lane → quét vision → giữ choke → theo dõi cooldown → quyết định start/turn.</p></section></aside></div><section class="objective-table"><div class="section-head"><h3>Objective taxonomy</h3><span>Setup và risk theo phase</span></div><table class="data-table"><thead><tr><th>Objective</th><th>Phase</th><th>Required setup</th><th>Risk</th><th>Blue action</th><th>Red action</th></tr></thead><tbody>${objectives.map(([name,p,setup,risk])=>`<tr><td><b>${name}</b></td><td>${p}</td><td>${setup}</td><td>${pill(risk,risk==='Critical'?'danger':'warning')}</td><td>${esc(objectivePlan('blue',p)[0])}</td><td>${esc(objectivePlan('red',p)[0])}</td></tr>`).join('')}</tbody></table></section><div class="map-route-grid">${mapRouteCard('blue')}${mapRouteCard('red')}</div>`}

function strategyContributors(side,type){const list=team(side),score=c=>type==='engage'?(hasCapability(c,'Engage','CC Hard','Stun','Root','Airborne')?4:0)+Number(c.ratings.control||0):type==='poke'?(hasCapability(c,'Poke','Range')?4:0)+Number(c.ratings.damage||0):type==='split'?(slug(c.combat.macro)==='split'?5:0)+Number(c.ratings.tower||0)/20:type==='protect'?(hasCapability(c,'Shield','Heal','Peel','Disengage')?5:0)+Number(c.ratings.utility||0):type==='frontline'?Number(c.ratings.toughness||0)+(c.classification.primary==='Tank'?5:0):Number(c.ratings.control||0)+Number(c.ratings.utility||0);return list.map(c=>({c,score:score(c)})).sort((a,b)=>b.score-a.score).slice(0,3).map(item=>item.c)}
function strategyRules(side){const enemy=side==='blue'?'red':'blue',m=teamMetrics(side),e=teamMetrics(enemy),rules=[];const add=(priority,phase,title,copy,contributors)=>rules.push({priority,phase,title,copy,contributors});if(m.weightedPower.early>e.weightedPower.early)add('High','Early','Tăng tốc ván đấu','Dùng lợi thế lane và jungle để lấy mục tiêu đầu, không đổi tempo lấy farm thụ động.',phaseContributors(side,'early').slice(0,3).map(x=>x.champion));if(m.weightedPower.late>e.weightedPower.late)add('Medium','Late','Bảo toàn điều kiện scale','Giảm giao tranh rủi ro, phân bổ tài nguyên cho carry và giữ vision phòng thủ.',phaseContributors(side,'late').slice(0,3).map(x=>x.champion));if(m.engage>e.disengage)add('High','Teamfight','Chủ động mở giao tranh','Ép đối thủ vào choke quanh objective và mở khi carry địch mất vị trí.',strategyContributors(side,'engage'));if(m.poke>e.poke)add('Medium','Setup','Poke trước mục tiêu','Đến sớm, kiểm soát bụi và bào máu trước khi buộc đối thủ phải vào.',strategyContributors(side,'poke'));if(m.split>e.split)add('Medium','Macro','Tạo áp lực cánh','Dùng 4-1, giữ teleport và tránh mở giao tranh khi người đẩy lẻ chưa tạo áp lực.',strategyContributors(side,'split'));if(!m.frontline)add('High','Teamfight','Tránh front-to-back','Thiếu frontline: ưu tiên catch, flank hoặc poke thay vì đứng đối diện đánh lâu.',strategyContributors(side,'poke'));if(e.mobilitySources>m.control)add('High','Defense','Bảo vệ backline','Đối thủ có nhiều mobility; giữ CC để phản engage và không dùng hết kỹ năng vào frontline.',strategyContributors(side,'protect'));if(!rules.length)add('Medium','All','Đánh theo nhịp mục tiêu','Hai đội tương đối cân bằng; thắng bằng lane priority, vision và cooldown chủ chốt.',strategyContributors(side,'control'));return rules}
function renderStrategy(){const side=state.strategySide,rules=strategyRules(side);return pageIntro('Strategy playbook','Rule engine biến dữ liệu đội hình thành hành động cụ thể theo phase, macro và teamfight.',`<div class="segmented"><button type="button" data-strategy-side="blue" class="${side==='blue'?'active':''}">Blue</button><button type="button" data-strategy-side="red" class="${side==='red'?'active':''}">Red</button></div>`)+`<div class="strategy-layout"><section class="strategy-rules">${rules.map((r,i)=>`<article><span>${String(i+1).padStart(2,'0')}</span><div><small>${esc(r.phase)} · ${esc(r.priority)}</small><h3>${esc(r.title)}</h3><p>${esc(r.copy)}</p><footer>${(r.contributors||[]).map(c=>`<button type="button" data-focus="${c.id}" data-route="champions">${portrait(c,'xs')}<span>${esc(c.name)}</span></button>`).join('')}</footer></div></article>`).join('')}</section><aside><section><h3>Role-weighted power curve</h3>${['blue','red'].map(s=>`<div class="strategy-phase"><b>${s}</b>${PHASES.map(p=>`<span>${p}<i style="height:${Math.round(weightedPhasePercent(s,p)/100*70)}px"></i><small>${teamMetrics(s).weightedPower[p].toFixed(1)}</small></span>`).join('')}</div>`).join('')}</section><section><h3>Composition risks</h3>${warnings(side).map(x=>pill(x,'warning')).join('')||pill('No critical risk','success')}</section><section><h3>Win condition</h3>${winCondition(side,side==='blue'?'red':'blue').map(x=>`<p>${esc(x)}</p>`).join('')}</section></aside></div>`}

const FIGHT_SCENARIOS=[['standard','Front-to-back'],['objective','Objective fight'],['siege','Siege / poke'],['pick','Pick / catch'],['disengage','Disengage']];
function scenarioScore(side,scenario){const m=teamMetrics(side),weights={standard:[['damage',2],['toughness',2],['control',1],['utility',1]],objective:[['control',2],['engage',1.5],['utility',1.5],['frontline',1]],siege:[['poke',2],['clearwave',.05],['range',1],['disengage',1]],pick:[['catch',2],['mobilitySources',1.5],['control',1.5]],disengage:[['disengage',2],['poke',1],['utility',1.5],['control',1]]};return (weights[scenario]||weights.standard).reduce((n,[key,w])=>n+(Number(key==='range'?m.ranged:m[key])||0)*w,0)}
function scenarioAdvice(side,scenario){const m=teamMetrics(side),roles=fightRoles(side),texts={standard:`Đặt ${roles.frontline?.name||'frontline'} phía trước và giữ ${roles.carry?.name||'carry'} ngoài tầm engage.`,objective:m.engage>=m.poke?'Giữ choke, ép face-check rồi mở combat theo quân số.':'Đến sớm, giữ khoảng cách và bào máu trước khi start mục tiêu.',siege:m.poke?'Đẩy wave, luân phiên poke và không bước qua vùng vision.':'Không kéo dài thế siege; tìm flank hoặc đổi sang side lane.',pick:`Dùng vision denial để tạo góc cho ${roles.controller?.name||'nguồn CC'} bắt mục tiêu đi lẻ.`,disengage:m.disengage?'Nhử đối thủ dùng mobility rồi phản giao tranh khi cooldown đã mất.':'Giữ đội hình chặt; tránh đứng tách để đối thủ chia cắt.'};return texts[scenario]}
function teamfightScenarioPanel(){const active=state.fightScenario,bs=scenarioScore('blue',active),rs=scenarioScore('red',active);return `<section class="scenario-lab"><div class="section-head"><h3>Fight scenario lab</h3><span>Điểm thay đổi theo cách giao tranh</span></div><div class="segmented scenario-tabs">${FIGHT_SCENARIOS.map(([id,label])=>`<button type="button" data-fight-scenario="${id}" class="${active===id?'active':''}">${label}</button>`).join('')}</div><div class="scenario-result"><article class="blue"><span>Blue</span><b>${bs.toFixed(1)}</b><p>${esc(scenarioAdvice('blue',active))}</p></article><strong>${bs===rs?'EVEN':bs>rs?'BLUE FAVORED':'RED FAVORED'}</strong><article class="red"><span>Red</span><b>${rs.toFixed(1)}</b><p>${esc(scenarioAdvice('red',active))}</p></article></div><div class="cc-table-wrap"><table class="data-table"><thead><tr><th>Scenario</th><th>Blue</th><th>Red</th><th>Advantage</th></tr></thead><tbody>${FIGHT_SCENARIOS.map(([id,label])=>{const b=scenarioScore('blue',id),r=scenarioScore('red',id);return `<tr><td><b>${label}</b></td><td>${b.toFixed(1)}</td><td>${r.toFixed(1)}</td><td>${b===r?'Even':b>r?'Blue':'Red'}</td></tr>`}).join('')}</tbody></table></div></section>`}
function radarPoints(metrics){const keys=['damage','toughness','control','mobility','utility'];return keys.map((key,index)=>{const angle=-Math.PI/2+index*Math.PI*2/keys.length,radius=Math.min(70,(Number(metrics[key])||0)/3*70);return `${(100+Math.cos(angle)*radius).toFixed(1)},${(100+Math.sin(angle)*radius).toFixed(1)}`}).join(' ')}
function scatterPoints(side){return team(side).map((c,index)=>{const x=35+((Number(c.ratings.control)||0)+(Number(c.ratings.utility)||0))/6*230,y=170-((Number(c.ratings.damage)||0)+(Number(c.ratings.toughness)||0))/6*130;return `<g><circle cx="${x}" cy="${y}" r="${9+Number(c.ratings.mobility||0)*2}" class="${side}"></circle><text x="${x}" y="${y-15}" text-anchor="middle">${esc(c.name)}</text></g>`}).join('')}
function teamfightCharts(){const b=teamMetrics('blue'),r=teamMetrics('red'),objectives=[['Infernal','damage'],['Mountain','toughness'],['Cloud','mobility'],['Ocean','utility'],['Hextech','control'],['Chemtech','damage'],['Baron','control'],['Elder','damage']];return `<section class="fight-charts"><article><div class="section-head"><h3>Combat radar</h3><span>Team averages</span></div><svg viewBox="0 0 200 200" role="img" aria-label="Team combat radar"><g class="radar-grid"><polygon points="100,30 166.6,78.4 141.1,156.6 58.9,156.6 33.4,78.4"></polygon><line x1="100" y1="100" x2="100" y2="30"></line><line x1="100" y1="100" x2="166.6" y2="78.4"></line><line x1="100" y1="100" x2="141.1" y2="156.6"></line><line x1="100" y1="100" x2="58.9" y2="156.6"></line><line x1="100" y1="100" x2="33.4" y2="78.4"></line></g><polygon class="radar-blue" points="${radarPoints(b)}"></polygon><polygon class="radar-red" points="${radarPoints(r)}"></polygon><text x="100" y="18" text-anchor="middle">Damage</text><text x="178" y="76">Toughness</text><text x="145" y="174">Control</text><text x="20" y="174">Mobility</text><text x="2" y="76">Utility</text></svg></article><article><div class="section-head"><h3>Champion impact scatter</h3><span>Size = mobility</span></div><svg viewBox="0 0 300 190" role="img" aria-label="Champion impact scatter"><line x1="30" y1="170" x2="280" y2="170"></line><line x1="30" y1="170" x2="30" y2="20"></line><text x="155" y="188" text-anchor="middle">Control + utility</text><text x="8" y="95" transform="rotate(-90 8 95)" text-anchor="middle">Damage + toughness</text>${scatterPoints('blue')}${scatterPoints('red')}</svg></article><article class="objective-affinity"><div class="section-head"><h3>Objective affinity</h3><span>Composition value by objective</span></div>${objectives.map(([name,key])=>{const bv=Number(b[key])||0,rv=Number(r[key])||0;return `<div><b>${name}</b><span class="blue">${bv.toFixed(1)}</span><i><em style="width:${Math.min(50,bv/5*50)}%"></em><em style="width:${Math.min(50,rv/5*50)}%"></em></i><span class="red">${rv.toFixed(1)}</span></div>`}).join('')}</article></section>`}
const TEAMFIGHT_MODES=['Basic','Aram','Combat','Dragon','Baron','Atakhan Top','Atakhan Bot'];
const TEAMFIGHT_FORMATIONS=['1-2-2','1-4','2-1-2','2-2-1','2-3','3-1-1','3-2','4-1','5'];
const TEAMFIGHT_TRIGGERS=['Engage','Disengage','Poke','Strong Ult','TeamFight','Gank','CC Hard','CC','Slow','Dash','Speed','Heal','Shield','Buff','Burst Dame'];
function semanticTagMatch(tag,query){const left=slug(tag),right=slug(query);if(!left||!right)return false;if(left===right)return true;const shorter=Math.min(left.length,right.length);return shorter>=4&&(left.startsWith(right)||right.startsWith(left))}
function teamfightTriggerMatches(side,trigger){return team(side).flatMap(c=>c.abilities.filter(a=>(a.tags||[]).some(tag=>semanticTagMatch(tag,trigger))).map(a=>({c,a})))}
function triggerMatchRow(side,trigger,label){const matching=teamfightTriggerMatches(side,trigger);return `<div class="trigger-result"><b><small>${esc(label)}</small>${esc(trigger)}</b>${matching.map(({c,a})=>`<span>${portrait(c,'xs')}${a.images[0]?`<img src="${esc(a.images[0])}" alt="${esc(a.name)}" width="28" height="28" loading="lazy" decoding="async">`:''}<small>${esc(c.name)} · ${esc(a.slot)}</small></span>`).join('')||'<small>No matching skill in this team.</small>'}</div>`}
function teamfightWorkbookControls(){const side=state.teamfightSide,enemy=side==='blue'?'red':'blue',options=(values,active)=>values.map(value=>`<option value="${esc(value)}" ${active===value?'selected':''}>${esc(value)}</option>`).join('');return `<section class="workbook-controls teamfight-workbook"><div><label><span>Side · Teamfight!B2</span><select data-teamfight-control="teamfightSide"><option value="blue" ${side==='blue'?'selected':''}>Blue</option><option value="red" ${side==='red'?'selected':''}>Red</option></select></label><label><span>Mode · Teamfight!M2</span><select data-teamfight-control="teamfightMode">${options(TEAMFIGHT_MODES,state.teamfightMode)}</select></label><label><span>Our formation · Teamfight!P2</span><select data-teamfight-control="teamfightFormation">${options(TEAMFIGHT_FORMATIONS,state.teamfightFormation)}</select></label><label><span>Enemy formation · Teamfight!R2</span><select data-teamfight-control="teamfightEnemyFormation">${options(TEAMFIGHT_FORMATIONS,state.teamfightEnemyFormation)}</select></label><label><span>Phase · Teamfight!U2</span><select data-teamfight-control="teamfightPhase">${PHASES.map(value=>`<option value="${value}" ${state.teamfightPhase===value?'selected':''}>${value[0].toUpperCase()+value.slice(1)}</option>`).join('')}</select></label><label><span>Primary trigger · Teamfight!X2</span><select data-teamfight-control="teamfightTrigger">${options(TEAMFIGHT_TRIGGERS,state.teamfightTrigger)}</select></label><label><span>Response trigger · Teamfight!Z2</span><select data-teamfight-control="teamfightCounterTrigger">${options(TEAMFIGHT_TRIGGERS,state.teamfightCounterTrigger)}</select></label></div><div class="trigger-duel">${triggerMatchRow(side,state.teamfightTrigger,`${side} primary`)}${triggerMatchRow(enemy,state.teamfightCounterTrigger,`${enemy} response`)}</div></section>`}
function teamfightWorkbookParity(){const side=state.teamfightSide,enemy=side==='blue'?'red':'blue',ours=teamfightTriggerMatches(side,state.teamfightTrigger),theirs=teamfightTriggerMatches(enemy,state.teamfightCounterTrigger),rangeRows=[['Frontline','125–175'],['Midline','125–300'],['Backline','125–500'],['Carry','525–550'],['Flank','550']],verdict=ours.length===theirs.length?'Trigger coverage is even':ours.length>theirs.length?`${side} has more primary trigger coverage`:`${enemy} has more response coverage`;return `<section class="teamfight-parity"><div class="section-head"><h3>Workbook execution contract</h3><span>Teamfight!B2:Z2 · live state parity</span></div><div class="teamfight-parity-grid"><article><small>Formation matchup</small><b>${esc(state.teamfightFormation)} vs ${esc(state.teamfightEnemyFormation)}</b><p>${esc(state.teamfightMode)} · ${esc(state.teamfightPhase)} phase</p></article><article><small>Trigger coverage</small><b>${ours.length} vs ${theirs.length}</b><p>${esc(verdict)}</p></article><article><small>Validation</small><b>7 modes · 9 formations · 15 triggers</b><p>Values mirror the strict workbook dropdowns.</p></article></div><div class="range-contract" aria-label="Workbook positioning ranges">${rangeRows.map(([role,value])=>`<span><small>${role}</small><b>${value}</b></span>`).join('')}</div></section>`}
function teamfightExecutionPanel(){const side=state.teamfightSide,enemy=side==='blue'?'red':'blue',roles=fightRoles(side),enemyRoles=fightRoles(enemy),target=state.teamfightTarget==='lowhp'?team(enemy).sort((a,b)=>(Number(a.ratings.toughness)||0)-(Number(b.ratings.toughness)||0))[0]:enemyRoles.carry,engage=roles.engage||roles.controller,follow=team(side).filter(c=>c!==engage).sort((a,b)=>(Number(b.ratings.damage)||0)-(Number(a.ratings.damage)||0)),ranges=[['Frontline','125–175'],['Midline','125–300'],['Backline','125–500'],['Carry','525–550'],['Flank','550']];return `<section class="teamfight-execution"><div class="section-head"><h3>Fight execution board</h3><span>${esc(state.teamfightFormation)} · ${esc(state.teamfightMode)}</span></div><div class="execution-controls"><label><span>Priority target</span><select data-teamfight-execution="teamfightTarget"><option value="carry" ${state.teamfightTarget==='carry'?'selected':''}>Carry</option><option value="lowhp" ${state.teamfightTarget==='lowhp'?'selected':''}>Low HP</option></select></label><label><input type="checkbox" data-teamfight-flank ${state.teamfightFlank?'checked':''}><span>Enable flank assignment</span></label></div><div class="execution-chain"><article>${engage?portrait(engage,'sm'):''}<small>1 · Engage</small><b>${esc(engage?.name||'No engage source')}</b><span>${esc(engage?.abilities.find(a=>a.tags.includes(state.teamfightTrigger)||a.tags.includes('Engage'))?.name||state.teamfightTrigger)}</span></article>${follow.slice(0,3).map((c,index)=>`<article>${portrait(c,'sm')}<small>${index+2} · ${index===0?'Burst':'Follow-up'}</small><b>${esc(c.name)}</b><span>${esc(keyLaneSkills(c)[0]?.name||'Basic attack')}</span></article>`).join('')}<strong>→</strong><article class="target">${target?portrait(target,'sm'):''}<small>Target · ${esc(state.teamfightTarget)}</small><b>${esc(target?.name||'No enemy target')}</b><span>${state.teamfightFlank?'Attack from flank':'Front-to-back access'}</span></article></div><div class="distance-ladder">${ranges.map(([role,value])=>`<span><small>${role}</small><b>${value}</b></span>`).join('')}</div></section>`}
function renderTeamfightFull(){return afterPageIntro(renderTeamfight(),teamfightWorkbookControls()+phaseWeightPanel())+teamfightWorkbookParity()+teamfightExecutionPanel()+teamfightScenarioPanel()+teamfightCharts()}
function strategyMatrix(){return `<section class="strategy-matrix"><div class="section-head"><h3>Phase execution matrix</h3><span>Lane · jungle · objective · teamfight</span></div><div class="cc-table-wrap"><table class="data-table"><thead><tr><th>Phase</th><th>Weighted score</th><th>Blue lane plan</th><th>Blue objective</th><th>Red lane plan</th><th>Red objective</th><th>Key check</th></tr></thead><tbody>${PHASES.map(phase=>{const b=teamMetrics('blue').weightedPower[phase],r=teamMetrics('red').weightedPower[phase];return `<tr><td>${pill(phase)}</td><td><b class="blue">${b.toFixed(2)}</b> / <b class="red">${r.toFixed(2)}</b></td><td>${esc(b>=r?'Chủ động lấy priority và chuyển trước':'Giữ wave an toàn, không đổi máu thiếu thông tin')}</td><td>${esc(objectivePlan('blue',phase).join(' '))}</td><td>${esc(r>=b?'Chủ động lấy priority và chuyển trước':'Giữ wave an toàn, không đổi máu thiếu thông tin')}</td><td>${esc(objectivePlan('red',phase).join(' '))}</td><td>${phase==='early'?'Jungle tracking + first reset':phase==='mid'?'Side waves + vision timing':'Buyback + major cooldowns'}</td></tr>`}).join('')}</tbody></table></div></section>`}
function strategyTierPanel(){const role=state.strategyRole,list=CHAMPIONS.filter(c=>c.roles.includes(role)),tiers=['S+','S','A+','A'];return `<section class="strategy-tier-panel"><div class="section-head"><h3>Meta · Master · Flex matrix</h3><span>Workbook tier checks by role</span></div><div class="lane-tabs segmented">${ROLES.map(value=>`<button type="button" data-strategy-role="${value}" class="${value===role?'active':''}">${value}</button>`).join('')}</div><div class="tier-columns">${tiers.map(tier=>`<article><header><b>${tier}</b><span>${list.filter(c=>c.tier===tier).length}</span></header>${list.filter(c=>c.tier===tier).map(c=>`<button type="button" data-library-focus="${c.id}" data-library-route="champions">${portrait(c,'xs')}<span><b>${esc(c.name)}</b><small>${[c.profiles.mastery?'Master':'',c.profiles.flex?'Flex':'',c.profiles.carry?'Carry':''].filter(Boolean).join(' · ')||'Meta pool'}</small></span></button>`).join('')||'<p class="empty">No records</p>'}</article>`).join('')}</div></section>`}
const MACRO_PLAYBOOK={Auto:'Select from composition strengths and enemy weaknesses.',Turtle:'Defend, stall the game and wait for the correct counter-engage.',Scaling:'Protect resource allocation and avoid low-value early fights.',Split:'Create side-lane pressure, hold teleport and delay forced 5v5s.',Macro:'Win through wave timing, rotations and objective trades.',Control:'Take space first, deny vision and force enemies through choke points.',Teamfight:'Group on major cooldowns and force coordinated 5v5 engagements.',Catch:'Deny vision and punish isolated rotations before objectives.',Argo:'Use high-tempo movement and repeated engagements to overwhelm the enemy.',Turbo:'Accelerate every advantage through dives, invades and fast objective chains.'};
function macroPlaybookPanel(){const active=state.strategyMacro,side=state.strategySide,m=teamMetrics(side),recommended=weightedPhasePercent(side,'late')>weightedPhasePercent(side,'early')?'Scaling':m.split?'Split':m.catch?'Catch':m.engage?'Teamfight':'Control',selected=active==='Auto'?recommended:active;return `<section class="macro-playbook"><div class="section-head"><h3>Macro style workbook</h3><span>Recommended: ${recommended}</span></div><label><span>Active macro</span><select data-strategy-macro>${Object.keys(MACRO_PLAYBOOK).map(value=>`<option ${active===value?'selected':''}>${value}</option>`).join('')}</select></label><div class="macro-style-grid">${Object.entries(MACRO_PLAYBOOK).map(([name,copy])=>`<article class="${name===selected?'active':''}"><b>${name}</b><p>${esc(copy)}</p><small>${name===selected?'ACTIVE PLAN':'Reference rule'}</small></article>`).join('')}</div></section>`}
function strategyWorkbookContract(){const side=state.strategySide,enemy=side==='blue'?'red':'blue',m=teamMetrics(side),e=teamMetrics(enemy);return `<section class="strategy-contract"><div class="section-head"><h3>Strategy workbook contract</h3><span>Strategy!DA1:EI125 · dependent on Setting pools and team slots</span></div><div class="strategy-contract-grid">${[['Selected side',side.toUpperCase()],['Team completeness',`${m.count}/5`],['Enemy completeness',`${e.count}/5`],['Early edge',(m.weightedPower.early-e.weightedPower.early).toFixed(2)],['Mid edge',(m.weightedPower.mid-e.weightedPower.mid).toFixed(2)],['Late edge',(m.weightedPower.late-e.weightedPower.late).toFixed(2)],['Macro',state.strategyMacro],['Generated rules',strategyRules(side).length]].map(([label,value])=>`<span><small>${label}</small><b>${esc(value)}</b></span>`).join('')}</div><p>Outputs are regenerated from the current 5 role slots. Role eligibility continues to use the named Setting ranges; no separate Strategy-only champion copy is maintained.</p></section>`}
function renderStrategyFull(){return afterPageIntro(renderStrategy(),strategyWorkbookContract())+macroPlaybookPanel()+strategyTierPanel()+strategyMatrix()}

function libraryList(route,selectedId){const query=state.libraryQuery.toLowerCase();return `<aside class="library-list"><label class="field"><span>Search</span><input data-library-search value="${esc(state.libraryQuery)}" placeholder="Champion name..."></label><div>${CHAMPIONS.filter(c=>[c.name,...c.roles,...c.capabilities].join(' ').toLowerCase().includes(query)).map(c=>`<button type="button" class="${c.id===selectedId?'active':''}" data-library-focus="${c.id}" data-library-route="${route}">${portrait(c,'xs')}<span><b>${esc(c.name)}</b><small>${esc(c.roles.join(' · '))}</small></span></button>`).join('')}</div></aside>`}
function abilityCard(a,champion){const record=champion?normalizedAbility(champion,a):a;return `<article class="ability-card ${record.form==='alternate'?'alternate':''}"><div>${record.images.map(src=>`<img src="${esc(src)}" alt="${esc(record.name)}" width="56" height="56" loading="lazy" decoding="async">`).join('')||`<span>${esc(record.slot[0])}</span>`}</div><section><small>${esc(record.slot)}${record.form==='alternate'?' · Alternate form':''} · ${esc(record.impact||'Standard')} impact</small><h3>${esc(record.name)}</h3>${record.cooldown?`<b>${esc(record.cooldown)}</b>`:''}<p>${record.tags.map(x=>pill(x)).join('')||'No tags'}</p>${record.ccTypes?.length?`<footer>CC: ${record.ccTypes.map(x=>pill(x,'danger')).join('')}</footer>`:''}</section></article>`}
function renderChampions(){const c=byId(state.focus)||CHAMPIONS[0],guide=guideFor(c),stats=Object.entries(c.baseStats||{}).filter(([,v])=>v!=null),empty='No data available.';return pageIntro('Champion library','Normalized champion profiles shared across the whole engine.')+`<div class="library-layout">${libraryList('champions',c.id)}<main class="champion-profile">${focusDetail(c)}<section class="profile-section profile-meta"><span><small>Patch</small><b>${esc(c.metadata?.patch||'—')}</b></span><span><small>Release year</small><b>${esc(c.metadata?.releaseYear||'—')}</b></span><span><small>Tier</small><b>${esc(c.tier||'—')}</b></span><span><small>Difficulty</small><b>${esc(c.difficulty??'—')}</b></span><span><small>Roles</small><b>${esc(c.roles.join(' · '))}</b></span><span><small>Range</small><b>${esc(c.range)}</b></span></section><section class="profile-section"><h3>Ratings</h3><div class="rating-grid">${Object.entries(c.ratings).filter(([,v])=>v!=null).map(([k,v])=>`<span><small>${esc(k)}</small><b>${v}</b></span>`).join('')}</div></section><section class="profile-section"><h3>Base stats</h3><div class="stat-grid">${stats.map(([key,value])=>`<span><small>${esc(key)}</small><b>${esc(value)}</b></span>`).join('')}</div></section><section class="profile-section"><h3>Strengths & weaknesses</h3><div class="guide-grid"><p>${esc(guide.strengths||empty)}</p><p>${esc(guide.weaknesses||empty)}</p></div></section><section class="profile-section"><h3>Game plan</h3><div class="plan-grid">${PHASES.map(p=>`<article><b>${p}</b><p>${esc(guide.gamePlan?.[p]||empty)}</p></article>`).join('')}</div></section><section class="profile-section"><h3>Power spikes</h3><div class="plan-grid spikes">${PHASES.map(p=>`<article><b>${p}</b><p>${esc(guide.powerSpikes?.[p]||empty)}</p></article>`).join('')}</div></section></main></div>`}
function renderSkills(){const c=byId(state.focus)||CHAMPIONS[0];return pageIntro('Skill library','Each skill is a separate record with image, cooldown, tags, related CC, impact level, and alternate forms.')+`<div class="library-layout">${libraryList('skills',c.id)}<main class="skill-profile"><header class="profile-head">${portrait(c,'lg')}<div><span>${esc(c.classification.primary)}</span><h2>${esc(c.name)}</h2><p>${c.abilities.length} skill / form · ${c.capabilities.length} capability tags</p></div></header><div class="capability-cloud">${c.capabilities.map(x=>pill(x)).join('')}</div><div class="ability-grid">${c.abilities.map(a=>abilityCard(a,c)).join('')}</div></main></div>`}
function renderRoutes(){const q=state.libraryQuery.toLowerCase(),routes=DATA.jungleRoutes.map(normalizedRoute).filter(r=>[r.name,r.style,r.side,r.objectivePlan,...r.steps].join(' ').toLowerCase().includes(q));return pageIntro('Jungle route data','Thư viện route chuẩn hóa dùng bởi Map Plan và gợi ý jungle; champion phù hợp được suy luận từ phase, mobility và kiểu route.')+`<label class="library-search"><span>Tìm route, camp hoặc style</span><input data-library-search value="${esc(state.libraryQuery)}" placeholder="Full clear, gank, Raptors..."></label><div class="route-grid">${routes.map(r=>`<article><header><span>${esc(r.style)} · ${esc(r.side)} side</span><h3>${esc(r.name)}</h3><b>${r.campsCount} camps</b></header><div class="route-steps route-steps-icons">${r.steps.map((step,i)=>routeStepChip(step,i)).join('')}</div><div class="route-details"><span><small>Start</small><b>${esc(r.start)}</b></span><span><small>First gank</small><b>${esc(r.firstGank)}</b></span><span><small>Objective intent</small><b>${esc(r.objectivePlan)}</b></span><span><small>Risk</small><b>${esc(r.risk)}</b></span></div><div class="route-fit"><small>Best profile fit</small>${routeChampions(r).map(c=>`<button type="button" data-library-focus="${c.id}" data-library-route="champions">${portrait(c,'xs')}<span>${esc(c.name)}</span></button>`).join('')}</div><footer><span>Scuttler: ${esc(r.scuttler||'—')}</span><span>${r.earlyGank?'Early gank':'Standard timing'}</span><span>${r.jungleSteal?'Invade route':'Own jungle'}</span></footer></article>`).join('')||'<p class="empty">Không có route phù hợp.</p>'}</div>`}
function renderCc(){const q=state.libraryQuery.toLowerCase(),items=DATA.crowdControl.filter(c=>Object.values(c).flat().join(' ').toLowerCase().includes(q));return pageIntro('Crowd control taxonomy','Thư viện định nghĩa tác động của từng loại CC, dùng để chấm Control và phản giao tranh.')+`<label class="library-search"><span>Tìm hiệu ứng</span><input data-library-search value="${esc(state.libraryQuery)}" placeholder="Airborne, Blind, movement..."></label><div class="cc-table-wrap"><table class="data-table"><thead><tr><th>Effect</th><th>Severity</th><th>Movement</th><th>Attack</th><th>Abilities</th><th>Interrupt</th><th>Summoner</th><th>Tenacity</th></tr></thead><tbody>${items.map(c=>`<tr><td><b>${esc(c.name)}</b></td><td>${pill(c.severity,c.severity==='Hard'?'danger':'soft')}</td><td>${esc(c.movement)}</td><td>${esc(c.attacking)}</td><td>${esc(c.abilities)}</td><td>${esc(c.interruptsChannels)}</td><td>${esc(c.summonerSpells)}</td><td>${esc(c.tenacity)}</td></tr>`).join('')}</tbody></table></div>`}

function qualityChecks(){
  const checks=[],abilityRecords=CHAMPIONS.flatMap(champion=>(champion.abilities||[]).map(ability=>({champion,ability}))),matchupNames=unique(CHAMPIONS.flatMap(champion=>Object.values(champion.matchups||{}).flat()));
  const duplicateValues=values=>unique(values.filter((value,index)=>values.indexOf(value)!==index));
  const add=(label,records,detail,format)=>{const list=Array.isArray(records)?records:[],count=Array.isArray(records)?records.length:Number(records)||0,examples=format?list.slice(0,3).map(format).filter(Boolean):[];checks.push({label,count,detail,examples})};
  add('Champions without roles',CHAMPIONS.filter(champion=>!Array.isArray(champion.roles)||!champion.roles.length),'champion.roles',champion=>champion.name);
  add('Invalid role values',CHAMPIONS.flatMap(champion=>(champion.roles||[]).filter(role=>!ROLES.includes(role)).map(role=>({champion,role}))),'Top, Jungle, Mid, AD or Support',item=>`${item.champion.name}: ${item.role}`);
  add('Champions without a primary class',CHAMPIONS.filter(champion=>!champion.classification?.primary),'champion.classification.primary',champion=>champion.name);
  add('Incomplete ability kits',CHAMPIONS.filter(champion=>(champion.abilities||[]).length<5),'at least five ability records',champion=>champion.name);
  add('Malformed ability records',abilityRecords.filter(({ability})=>!ability?.slot||!ability?.name||!Array.isArray(ability.tags)||!Array.isArray(ability.images)),'slot, name, tags and images',({champion,ability})=>`${champion.name}: ${ability?.slot||'unknown slot'}`);
  add('Abilities without semantic tags',abilityRecords.filter(({ability})=>!ability.tags?.length),'ability.tags',({champion,ability})=>`${champion.name}: ${ability.slot}`);
  add('Champions without matchups',CHAMPIONS.filter(champion=>!Object.values(champion.matchups||{}).some(list=>Array.isArray(list)&&list.length)),'matchup relationship coverage',champion=>champion.name);
  add('Unresolved matchup references',matchupNames.filter(name=>!splitName(name)),'names absent from the champion catalog',name=>name);
  add('Champions without ability images',CHAMPIONS.filter(champion=>!(champion.abilities||[]).some(ability=>ability.images?.length)),'ability images',champion=>champion.name);
  add('Duplicate champion IDs',duplicateValues(CHAMPIONS.map(champion=>champion.id)),'unique champion.id',id=>id);
  add('Duplicate champion names',duplicateValues(CHAMPIONS.map(champion=>slug(champion.name))),'normalized champion name',name=>name);
  add('Missing power values',CHAMPIONS.flatMap(champion=>PHASES.filter(phase=>!['Weak','Average','Strong'].includes(champion.power?.[phase])).map(phase=>({champion,phase}))),'missing values remain explicit',item=>`${item.champion.name}: ${item.phase}`);
  add('Missing patch metadata',CHAMPIONS.filter(champion=>!champion.metadata?.patch),'metadata.patch',champion=>champion.name);
  add('Missing release year',CHAMPIONS.filter(champion=>!champion.metadata?.releaseYear),'releaseDate → metadata.releaseYear',champion=>champion.name);
  add('Missing Vietnamese guides',CHAMPIONS.filter(champion=>!champion.guideVi?.strengths||!champion.guideVi?.powerSpikes),'guideVi strengths and power spikes',champion=>champion.name);
  add('Invalid numeric ratings',CHAMPIONS.flatMap(champion=>Object.entries(champion.ratings||{}).filter(([,value])=>value!=null&&!Number.isFinite(Number(value))).map(([rating])=>({champion,rating}))),'finite numeric ratings',item=>`${item.champion.name}: ${item.rating}`);
  add('Malformed jungle routes',DATA.jungleRoutes.filter(route=>!route.name||!Array.isArray(route.steps)||!route.steps.length),'route name and steps',route=>route.name||route.id);
  add('Duplicate jungle route names',duplicateValues(DATA.jungleRoutes.map(route=>slug(route.name))),'normalized route name',name=>name);
  add('Duplicate CC type names',duplicateValues(DATA.crowdControl.map(type=>slug(type.name))),'normalized CC type',name=>name);
  add('Invalid CC severity',DATA.crowdControl.filter(type=>!['Soft','Hard'].includes(type.severity)),'Soft or Hard',type=>`${type.name}: ${type.severity}`);
  return checks
}
function renderSystem(){
  const checks=qualityChecks(),checkCards=checks.map(check=>`<article class="${check.count?'issue':'ok'}"><span>${check.count?'Needs review':'Passed'}</span><b>${check.count}</b><h3>${esc(check.label)}</h3><p>${esc(check.detail)}</p>${check.examples.length?`<ul aria-label="Example records">${check.examples.map(example=>`<li>${esc(example)}</li>`).join('')}</ul>`:''}</article>`).join('');
  return pageIntro('Data Quality & Settings','Validate imported data, runtime contracts, and Teamfight scoring weights.')+`<div class="system-layout"><section class="quality-grid">${checkCards}</section><aside class="settings-panel"><h3>Teamfight weights</h3><p>These weights directly affect the weighted score.</p>${Object.entries(state.weights).map(([key,value])=>`<label><span>${esc(key)}</span><input type="range" min="0" max="2" step="0.1" value="${value}" data-weight="${key}"><output>${value}</output></label>`).join('')}<button type="button" data-action="reset-weights">Restore defaults</button><dl><div><dt>Champions</dt><dd>${CHAMPIONS.length}</dd></div><div><dt>Abilities</dt><dd>${CHAMPIONS.reduce((sum,champion)=>sum+champion.abilities.length,0)}</dd></div><div><dt>Matchups</dt><dd>${CHAMPIONS.filter(champion=>champion.matchups.counters.length).length}</dd></div><div><dt>Jungle routes</dt><dd>${DATA.jungleRoutes.length}</dd></div><div><dt>CC types</dt><dd>${DATA.crowdControl.length}</dd></div></dl></aside></div>`
}

function ccRemovalPanel(){return `<section class="cc-removal"><div class="section-head"><h3>Removal & cleanse matrix</h3><span>Counterplay reference for every CC type</span></div><div class="cc-table-wrap"><table class="data-table"><thead><tr><th>Effect</th><th>Severity</th><th>Removal / cleanse</th><th>Tenacity</th><th>Stops movement</th><th>Stops attacks</th><th>Stops abilities</th><th>Interrupts channels</th></tr></thead><tbody>${DATA.crowdControl.map(c=>`<tr><td><b>${esc(c.name)}</b></td><td>${pill(c.severity,c.severity==='Hard'?'danger':'soft')}</td><td>${esc(c.removal||'No explicit source')}</td><td>${esc(c.tenacity)}</td><td>${esc(c.movement)}</td><td>${esc(c.attacking)}</td><td>${esc(c.abilities)}</td><td>${esc(c.interruptsChannels)}</td></tr>`).join('')}</tbody></table></div></section>`}
