function renderPicker(){const {search,summary,list}=pickerElements();if(!search||!list)return;const q=search.value.trim().toLowerCase(),[kind,field,index]=pickerTarget.split(':'),slot=Number(index),F=state.pickerFilters,used=new Set([...state.blue,...state.red].filter(Boolean)),banned=new Set([...state.blueBans,...state.redBans].filter(Boolean)),locked=new Set(state.route==='draft'?fearlessIds():[]),current=Array.isArray(state[field])?state[field][slot]:state[field];const listItems=CHAMPIONS.filter(c=>c.name.toLowerCase().includes(q)&&pickerPass(c,F));if(summary)summary.textContent=`${listItems.length} results · Picked or banned champions are locked`;list.innerHTML=listItems.map(c=>{const laneOk=kind!=='slot'||roleFits(c,slot),reason=banned.has(c.id)?'BANNED':locked.has(c.id)?'FEARLESS LOCK':used.has(c.id)&&current!==c.id?'ALREADY IN DRAFT':'',unavailable=Boolean(reason);return `<button type="button" class="${laneOk?'':'wrong-lane'}" data-pick="${c.id}" ${unavailable?'disabled':''} aria-label="${esc(c.name)}${reason?`, ${reason}`:laneOk?'':', off-role warning'}">${portrait(c,'sm')}<span><b>${esc(c.name)}</b><small>${esc(c.roles.join(' · '))} · ${esc(c.classification.primary)}</small>${!laneOk?'<strong class="picker-warning">! Not a natural fit for this lane</strong>':''}</span>${reason?`<em class="unavailable-reason">${reason}</em>`:c.tier?pill(c.tier,'tier'):''}</button>`}).join('')||'<p class="empty">No champions match these filters.</p>'}
function applyPick(id){const [kind,field,index]=pickerTarget.split(':'),slot=Number(index),champion=byId(id),current=Array.isArray(state[field])?state[field][slot]:state[field],picked=[...state.blue,...state.red],banned=[...state.blueBans,...state.redBans];if(!champion){notify('Invalid champion');return}if(kind==='slot'&&banned.includes(id)){notify(`${champion.name} is banned`);return}if(kind==='slot'&&picked.includes(id)&&current!==id){notify(`${champion.name} is already in the draft`);return}if(kind==='ban'&&[...picked,...banned].includes(id)&&current!==id){notify(`${champion.name} is already in the draft`);return}if((kind==='slot'||kind==='ban')&&Array.isArray(state[field])&&Number.isInteger(slot)&&slot>=0&&slot<state[field].length)state[field][slot]=id;else if(kind==='focus'&&field in state)state[field]=id;else{notify('Unknown champion slot');return}const laneWarning=kind==='slot'&&!roleFits(champion,slot);closePicker();save();render();notify(laneWarning?`Picked ${champion.name} · Warning: not a natural fit for ${roleForIndex(slot)}`:`Picked ${champion.name}`)}
function swapRoleSlots(from,to){const [fromSide,fromIndexText]=String(from||'').split(':'),[toSide,toIndexText]=String(to||'').split(':'),fromIndex=Number(fromIndexText),toIndex=Number(toIndexText);if(!['blue','red'].includes(fromSide)||!['blue','red'].includes(toSide)||!Number.isInteger(fromIndex)||!Number.isInteger(toIndex)||fromIndex<0||fromIndex>=ROLES.length||toIndex<0||toIndex>=ROLES.length||(fromSide===toSide&&fromIndex===toIndex))return;const fromTeam=state[fromSide],toTeam=state[toSide];[fromTeam[fromIndex],toTeam[toIndex]]=[toTeam[toIndex],fromTeam[fromIndex]];save();render();const moved=byId(toTeam[toIndex]),warning=moved&&!roleFits(moved,toIndex),message=fromSide===toSide?'Role swapped':'Champion moved across teams';notify(warning?`${message} · ${moved.name} is not a natural fit for ${roleForIndex(toIndex)}`:message)}
function applyDraftPick(id){const turn=DRAFT_SEQUENCE[state.draftStep];if(!turn||selectedIds().includes(id)||fearlessIds().includes(id))return;const [,field,index]=turn;state[field][index]=id;state.draftStep=Math.min(DRAFT_SEQUENCE.length,state.draftStep+1);save();render()}
function clearCurrentDraft(){state.blue=[null,null,null,null,null];state.red=[null,null,null,null,null];state.blueBans=[null,null,null,null,null];state.redBans=[null,null,null,null,null];state.draftStep=0}
function swapSides(){[state.blue,state.red]=[state.red,state.blue];[state.blueBans,state.redBans]=[state.redBans,state.blueBans];save();render();notify('Blue and Red swapped')}

function mapWorkbookControls(){const routeSelect=side=>{const field=side==='blue'?'mapRouteBlue':'mapRouteRed',active=jungleRouteFor(side);return `<label><span>${side} route</span><select data-map-route="${side}"><option value="">Auto by jungler</option>${DATA.jungleRoutes.map(route=>`<option value="${esc(route.name)}" ${state[field]===route.name?'selected':''}>${esc(route.name)}</option>`).join('')}</select><small>${active.earlyGank?'Gank early':'Full clear'} · ${active.jungleSteal?'Jungle steal':'Own jungle'} · ${esc(active.scuttler||'Scuttler flexible')}</small></label>`};const blue=normalizedRoute(jungleRouteFor('blue')),red=normalizedRoute(jungleRouteFor('red'));return `<section class="workbook-controls map-workbook"><div>${routeSelect('blue')}${routeSelect('red')}</div><div class="route-flags">${[['Blue start',blue.start],['Blue gank',blue.firstGank],['Blue camps',blue.campsCount],['Red start',red.start],['Red gank',red.firstGank],['Red camps',red.campsCount]].map(([label,value])=>`<span><small>${label}</small><b>${esc(value)}</b></span>`).join('')}</div></section>`}
function mapRouteWorkbookMatrix(){const routes=[['blue',normalizedRoute(jungleRouteFor('blue'))],['red',normalizedRoute(jungleRouteFor('red'))]];return `<section class="map-route-matrix"><div class="section-head"><h3>Workbook route sequence</h3><span>Start · Gank · Jungle Steal · Riftscuttler · Monster 1–9</span></div>${routes.map(([side,route])=>`<article class="${side}"><header><b>${side.toUpperCase()} · ${esc(route.name)}</b><span>${route.earlyGank?'Gank early':'Standard'} · Scuttler ${esc(route.scuttlerAt||route.scuttler||'—')} ${esc(route.scuttlerPosition||'')}</span></header><div class="route-control-strip">${[['Start',route.start],['Clear',route.clearCount||route.campsCount],['Gank count',route.gankCount||'—'],['Gank soon',route.gankSoon||'—'],['Gank lane',route.gankLane||'—'],['Jungle steal',route.jungleSteal?'Yes':'No']].map(([label,value])=>`<span><small>${label}</small><b>${esc(value)}</b></span>`).join('')}</div><div class="route-nine">${Array.from({length:9},(_,index)=>routeStepChip(route.steps[index]||'',index)).join('')}</div></article>`).join('')}</section>`}
function mapWorkbookContract(){const blue=normalizedRoute(jungleRouteFor('blue')),red=normalizedRoute(jungleRouteFor('red')),items=[['Start',blue.start,red.start,'Map!W'],['Gank',blue.firstGank,red.firstGank,'Map!X'],['Jungle steal',blue.jungleSteal?'Yes':'No',red.jungleSteal?'Yes':'No','Map!Y'],['Riftscuttler',blue.scuttler||'Flexible',red.scuttler||'Flexible','Map!Z'],['Gank early',blue.earlyGank?'Yes':'No',red.earlyGank?'Yes':'No','Map!AA'],['Monster sequence',blue.steps.filter(Boolean).length,red.steps.filter(Boolean).length,'Map!AC:AK']];return `<section class="workbook-contract-bar map-contract"><div class="section-head"><h3>Map workbook contract</h3><span>Map!W1:AK · Start through Monster 9</span></div><div class="map-contract-grid">${items.map(([label,b,r,source])=>`<span><small>${esc(label)} · ${esc(source)}</small><b><i>Blue</i>${esc(b)}</b><b><i>Red</i>${esc(r)}</b></span>`).join('')}</div></section>`}
const MAP_OBJECTIVES=[
  {name:'Void Grubs',phase:'early',kind:'topside',color:'#8b5cf6',need:'Top/Mid priority + first move'},
  {name:'Rift Herald',phase:'mid',kind:'topside',color:'#14b8a6',need:'Top river vision + plate/tower pressure'},
  {name:'Baron Nashor',phase:'late',kind:'baron',color:'#7c3aed',need:'Two pushed lanes + turn tools'},
  {name:'Ocean Drake',phase:'early',kind:'dragon',color:'#22c55e',need:'Sustain fights + bot/mid setup'},
  {name:'Mountain Drake',phase:'mid',kind:'dragon',color:'#a16207',need:'Frontline + resist scaling'},
  {name:'Hextech Drake',phase:'mid',kind:'dragon',color:'#38bdf8',need:'Pick range + map tempo'},
  {name:'Cloud Drake',phase:'mid',kind:'dragon',color:'#60a5fa',need:'Engage speed + rotation'},
  {name:'Infernal Drake',phase:'late',kind:'dragon',color:'#ef4444',need:'Damage check + grouped fight'},
  {name:'Chemtech Drake',phase:'late',kind:'dragon',color:'#84cc16',need:'Low HP brawl + frontline'},
  {name:'Elder Dragon',phase:'late',kind:'elder',color:'#f59e0b',need:'Full 5v5 setup + no face-check'},
  {name:'Atakhan',phase:'mid',kind:'atakhan',color:'#dc2626',need:'Tempo lead + side river control'}
];
function mapSvgData(label,bg='#334155',fg='#fff'){const text=String(label||'?').slice(0,3).toUpperCase(),svg=`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><linearGradient id="g" x1="0" x2="1" y1="0" y2="1"><stop offset="0" stop-color="${bg}"/><stop offset="1" stop-color="#07111f"/></linearGradient></defs><rect x="3" y="3" width="58" height="58" rx="13" fill="url(#g)" stroke="${fg}" stroke-opacity=".7" stroke-width="2"/><path d="M32 9 52 22 45 51H19L12 22Z" fill="none" stroke="${fg}" stroke-width="4" stroke-linejoin="round" opacity=".86"/><text x="32" y="38" text-anchor="middle" font-family="Arial,Helvetica,sans-serif" font-size="16" font-weight="900" fill="${fg}">${text}</text></svg>`;return `data:image/svg+xml,${encodeURIComponent(svg)}`}
function campMeta(step){const key=slug(step),map=[['redbrambleback','Red','#dc2626'],['redbuff','Red','#dc2626'],['bluesentinel','Blue','#2563eb'],['bluebuff','Blue','#2563eb'],['gromp','Gromp','#16a34a'],['murkwolves','Wolves','#64748b'],['wolves','Wolves','#64748b'],['raptors','Raptors','#f97316'],['krugs','Krugs','#a16207'],['riftscuttler','Scuttle','#06b6d4'],['scuttle','Scuttle','#06b6d4'],['gank','Gank','#f59e0b'],['dragon','Dragon','#7c3aed'],['herald','Herald','#14b8a6'],['baron','Baron','#7c3aed'],['atakhan','Atakhan','#ef4444']].find(([needle])=>key.includes(needle));return map?{label:map[1],color:map[2],type:routeStepType(step)}:{label:step||'—',color:'#475569',type:'camp'}}
function campIcon(step,small=''){const meta=campMeta(step),src=sheetIconSrc(step)||sheetIconSrc(meta.label)||mapSvgData(meta.label,meta.color);return `<img class="map-token-img ${small} ${sheetIconSrc(step)||sheetIconSrc(meta.label)?'sheet-camp-icon':''}" src="${esc(src)}" alt="${esc(meta.label)}" width="38" height="38" loading="lazy" decoding="async">`}
function routeStepChip(step,index){return `<span class="${campMeta(step).type}"><small>${index+1}</small>${step?campIcon(step,'route-step-icon'):'<i></i>'}<b>${esc(step||'—')}</b></span>`}
function objectiveIcon(objective){return `<img class="objective-img" src="${mapSvgData(objective.name,objective.color)}" alt="${esc(objective.name)}" width="44" height="44" loading="lazy" decoding="async">`}
function otherSide(side){return side==='blue'?'red':'blue'}
function laneRouteMatch(route,role){const text=slug(`${route.gankLane||''} ${route.gankSoon||''} ${route.firstGank||''}`);if(role==='AD'||role==='Support')return text.includes('bot')||text.includes('adc')||text.includes('support');return text.includes(slug(role))}
function setupScore(c){return c?(Number(c.ratings.control)||0)+(Number(c.ratings.mobility)||0)*.8+(hasCapability(c,'Stun','Root','Airborne','Charm','Fear','CC Hard','Engage')?2:0)+(hasCapability(c,'Dash','Blink','Speed')?1:0):0}
function mapGankScore(side,index,phase,route){const enemy=otherSide(side),ally=byId(state[side][index]),target=byId(state[enemy][index]),role=ROLES[index];if(!ally||!target||role==='Jungle')return 0;const allyPriority=lanePriority(side,index,phase),enemyPriority=lanePriority(enemy,index,phase),routeBonus=laneRouteMatch(route,role)?2.4:0,jungler=byId(state[side][1]),jungleBonus=jungler?setupScore(jungler)*.28:0,setup=setupScore(ally)*.55,vulnerable=(target.range==='Ranged'&&ally.range==='Melee'?1.2:0)+(Number(target.ratings.mobility)<=2?1.1:0);return Math.max(0,enemyPriority-allyPriority)*1.15+setup+vulnerable+routeBonus+jungleBonus}
function mapGankVerdict(score){return score>=7?['Gank now','danger']:score>=4.6?['Cover / countergank','warning']:score>=2.6?['Path near','lane']:['Farm past','soft']}
function mapSkillSet(c,intent='lane'){if(!c)return '';const wants=intent==='objective'?['TeamFight','Strong Ult','Aoe','CC Hard','Shield','Heal','Poke','Engage']:['CC Hard','Stun','Root','Airborne','Slow','Dash','Blink','Poke','Clearwave','Engage'];const ranked=[...c.abilities.filter(a=>a.slot!=='Passive')].sort((a,b)=>{const hit=ability=>ability.tags.filter(tag=>wants.some(w=>slug(w)===slug(tag)||slug(tag).includes(slug(w)))).length;return hit(b)-hit(a)||b.tags.length-a.tags.length});return `<div class="map-skill-set">${ranked.slice(0,3).map(a=>`<span title="${esc(`${a.slot} · ${a.name} · ${a.tags.join(', ')}`)}">${a.images?.[0]?`<img src="${esc(a.images[0])}" alt="${esc(a.name)}" width="28" height="28" loading="lazy" decoding="async">`:esc(a.slot)}<small>${esc(a.slot)}</small></span>`).join('')}</div>`}
function lanePlanRead(index,phase){const role=ROLES[index],blue=byId(state.blue[index]),red=byId(state.red[index]),bp=lanePriority('blue',index,phase),rp=lanePriority('red',index,phase),prob=Math.round(Math.max(15,Math.min(85,50+(bp-rp)*11))),blueRoute=normalizedRoute(jungleRouteFor('blue')),redRoute=normalizedRoute(jungleRouteFor('red')),blueGank=mapGankScore('blue',index,phase,blueRoute),redGank=mapGankScore('red',index,phase,redRoute),winner=prob===50?'Even':prob>50?'Blue lane wins':'Red lane wins';return {role,blue,red,bp,rp,prob,winner,blueGank,redGank}}
function mapLaneWorkbook(phase){const rows=ROLES.map((_,index)=>lanePlanRead(index,phase));return `<section class="map-lane-workbook"><div class="section-head"><h3>Lane matchup + gank plan</h3><span>Lane pressure uses matchup imports, phase power, waveclear, mobility and route fit</span></div><div class="map-lane-head"><span>Lane</span><span>Blue win tools</span><span>Read</span><span>Red win tools</span><span>Gank call</span></div>${rows.map(row=>{const [bv,bt]=mapGankVerdict(row.blueGank),[rv,rt]=mapGankVerdict(row.redGank);return `<article class="${row.role==='Jungle'?'jungle-row':''}"><div><b>${esc(row.role)}</b><small>${row.role==='Jungle'?'Pathing duel':'Lane state'}</small></div><div class="map-lane-side blue">${row.blue?portrait(row.blue,'sm'):''}<span><b>${esc(row.blue?.name||'—')}</b><small>${row.blue?esc(`${row.blue.range} · ${row.blue.damage.profile}`):'No pick'}</small>${mapSkillSet(row.blue)}</span></div><div class="map-lane-read"><strong class="${row.prob>55?'blue':row.prob<45?'red':'tie'}">${row.prob}% · ${100-row.prob}%</strong><small>${esc(row.winner)}</small><i><em style="width:${row.prob}%"></em></i></div><div class="map-lane-side red">${row.red?portrait(row.red,'sm'):''}<span><b>${esc(row.red?.name||'—')}</b><small>${row.red?esc(`${row.red.range} · ${row.red.damage.profile}`):'No pick'}</small>${mapSkillSet(row.red)}</span></div><div class="map-gank-calls">${row.role==='Jungle'?`<span class="soft"><b>Jungle duel</b><small>route + scuttle</small></span>`:`<span class="${bt}"><b>Blue: ${esc(bv)}</b><small>${row.blueGank.toFixed(1)} setup score</small></span><span class="${rt}"><b>Red: ${esc(rv)}</b><small>${row.redGank.toFixed(1)} setup score</small></span>`}</div></article>`}).join('')}</section>`}
function objectiveScore(side,objective,phase){const m=teamMetrics(side),top=lanePriority(side,0,phase),mid=lanePriority(side,2,phase),ad=lanePriority(side,3,phase),sup=lanePriority(side,4,phase),phaseMetric=phase==='early'?m.early:phase==='mid'?m.mid:m.late,phaseBand=phaseMetric>2.25?'Strong':phaseMetric<1.75?'Weak':'Average';let score=38+phaseValue(phaseBand)*4;if(objective.kind==='dragon')score+=mid*5+(ad+sup)*3+m.damage*5+m.control*4;if(objective.kind==='topside')score+=(top+mid)*5+m.tower*5+m.clearwave*.08;if(objective.kind==='baron')score+=m.damage*5+m.control*5+m.frontline*4+m.clearwave*.08;if(objective.kind==='elder')score+=m.damage*6+m.engage*4+m.disengage*2+m.cc*3;if(objective.kind==='atakhan')score+=m.mobility*5+m.catch*4+m.damage*3+m.frontline*2;if(objective.name.includes('Ocean'))score+=m.heal*6+m.shield*4;if(objective.name.includes('Mountain'))score+=m.frontline*6+m.toughness*5;if(objective.name.includes('Hextech'))score+=m.catch*5+m.poke*4;if(objective.name.includes('Cloud'))score+=m.engage*5+m.mobility*5;if(objective.name.includes('Infernal'))score+=m.damage*7;if(objective.name.includes('Chemtech'))score+=m.frontline*4+m.damage*4;return Math.round(Math.max(5,Math.min(99,score)))}
function objectiveStrength(score){return score>=72?['Strong','success']:score>=52?['Average','warning']:['Weak','danger']}
function mapObjectiveWorkbook(phase){return `<section class="map-objective-workbook"><div class="section-head"><h3>Objective / Drake strength</h3><span>Which dragon/objective is stronger for each team</span></div><div class="objective-grid">${MAP_OBJECTIVES.map(obj=>{const bs=objectiveScore('blue',obj,phase),rs=objectiveScore('red',obj,phase),[bl,bt]=objectiveStrength(bs),[rl,rt]=objectiveStrength(rs);return `<article class="${obj.phase===phase?'active':''}"><header>${objectiveIcon(obj)}<span><small>${esc(obj.phase)} · ${esc(obj.kind)}</small><b>${esc(obj.name)}</b></span></header><p>${esc(obj.need)}</p><div class="objective-duel"><span class="${bt}"><small>Blue</small><b>${bs}</b><em>${esc(bl)}</em></span><span class="${rl==='Strong'?'danger':rt}"><small>Red</small><b>${rs}</b><em>${esc(rl)}</em></span></div></article>`}).join('')}</div></section>`}
function mapRouteWorkbookControls(){const select=side=>{const field=side==='blue'?'mapRouteBlue':'mapRouteRed',route=normalizedRoute(jungleRouteFor(side));return `<label class="${side}"><span>${side.toUpperCase()} route</span><select data-map-route="${side}"><option value="">Auto by jungler</option>${DATA.jungleRoutes.map(r=>`<option value="${esc(r.name)}" ${state[field]===r.name?'selected':''}>${esc(r.name)}</option>`).join('')}</select><small>${esc(route.start||'No start')} · ${route.earlyGank?'Early gank':'Farm route'} · ${esc(route.gankLane||route.gankSoon||'Flexible lane')}</small></label>`};return `<section class="map-plan-controls"><div class="segmented">${PHASES.map(p=>`<button type="button" data-map-phase="${p}" class="${state.mapPhase===p?'active':''}">${p}</button>`).join('')}</div>${select('blue')}${select('red')}</section>`}
function mapRouteSheet(side,phase){const route=normalizedRoute(jungleRouteFor(side)),jungler=byId(state[side][1]),enemy=otherSide(side),ganks=ROLES.map((role,index)=>({role,index,score:mapGankScore(side,index,phase,route)})).filter(x=>x.role!=='Jungle').sort((a,b)=>b.score-a.score),best=ganks[0],bestLane=best?ROLES[best.index]:'—',avatar=jungler?portrait(jungler,'sm'):`<span class="map-route-avatar">${campIcon(route.start,'route-avatar')}</span>`;return `<article class="map-route-sheet ${side}"><header>${avatar}<div><small>${side.toUpperCase()} jungle route</small><h3>${esc(jungler?.name||'No jungler')} · ${esc(route.name)}</h3></div><b>${esc(route.risk)} risk</b></header><div class="route-sheet-meta">${[['Start',route.start],['Gank',route.gankLane||route.gankSoon||route.firstGank],['Jungle steal',route.jungleSteal?'Yes':'No'],['Scuttler',`${route.scuttlerAt||route.scuttler||'—'} ${route.scuttlerPosition||''}`],['Gank early',route.earlyGank?'Yes':'No'],['Best lane',bestLane]].map(([label,value])=>`<span><small>${esc(label)}</small><b>${esc(value||'—')}</b></span>`).join('')}</div><div class="route-monsters">${Array.from({length:9},(_,index)=>{const step=route.steps[index]||'';return `<span class="${campMeta(step).type}"><small>${index+1}</small>${step?campIcon(step):'<i></i>'}<b>${esc(step||'—')}</b></span>`}).join('')}</div><div class="route-map-row">${mapRouteVisual(side,route)}<aside><h4>Lane to pressure</h4>${ganks.slice(0,4).map(item=>{const [label,tone]=mapGankVerdict(item.score),ally=byId(state[side][item.index]),target=byId(state[enemy][item.index]);return `<div class="${tone}"><b>${esc(item.role)} · ${esc(label)}</b><small>${esc(ally?.name||'—')} into ${esc(target?.name||'—')} · ${item.score.toFixed(1)}</small></div>`}).join('')}<h4>Route skill display</h4>${jungler?mapSkillSet(jungler,'objective'):'<p class="empty">Pick a jungler to show route skills.</p>'}</aside></div></article>`}
function renderMapWorkbook(){const phase=state.mapPhase||'early';return pageIntro('Map plan','Workbook-style map plan: lane win read, gank target, jungle route loop, monster sequence, objective and drake strength.',mapRouteWorkbookControls())+`<div class="map-workbook-page">${mapLaneWorkbook(phase)}<div class="map-route-duo">${mapRouteSheet('blue',phase)}${mapRouteSheet('red',phase)}</div>${mapObjectiveWorkbook(phase)}${mapWorkbookContract()}</div>`}
function renderMapFull(){return renderMapWorkbook()}

function routeWorkbookTable(){const routes=DATA.jungleRoutes.map(normalizedRoute);return `<section class="route-workbook-table"><div class="section-head"><h3>Jungle Route workbook fields</h3><span>${routes.length} normalized routes</span></div><div class="cc-table-wrap"><table class="data-table"><thead><tr><th>Name</th><th>Side</th><th>Early gank</th><th>Scuttler</th><th>Position</th><th>Clear</th><th>Gank count</th><th>Gank soon</th><th>Gank lane</th><th>Steps 1–9</th></tr></thead><tbody>${routes.map(route=>`<tr><td><b>${esc(route.name)}</b></td><td>${esc(route.side)}</td><td>${route.earlyGank?'Yes':'No'}</td><td>${esc(route.scuttlerAt||route.scuttler||'—')}</td><td>${esc(route.scuttlerPosition||'—')}</td><td>${esc(route.clearCount||route.campsCount)}</td><td>${esc(route.gankCount||'—')}</td><td>${esc(route.gankSoon||'—')}</td><td>${esc(route.gankLane||'—')}</td><td>${esc(route.steps.slice(0,9).join(' → '))}</td></tr>`).join('')}</tbody></table></div></section>`}
function routeCompatibilityPanel(){const junglers=CHAMPIONS.filter(c=>c.roles.includes('Jungle')),champion=byId(state.routeChampion)&&byId(state.routeChampion).roles.includes('Jungle')?byId(state.routeChampion):junglers[0],ranked=DATA.jungleRoutes.map(normalizedRoute).map(route=>({route,score:routeFitScore(route,champion)})).sort((a,b)=>b.score-a.score||a.route.name.localeCompare(b.route.name)),best=ranked[0];return `<section class="route-compatibility"><div class="section-head"><h3>Champion route planner</h3><span>Jungle Route!A1:W44 · 16 live route records</span></div><div class="route-champion-control"><div>${portrait(champion,'lg')}<span><small>Selected jungler</small><b>${esc(champion.name)}</b><em>${esc(champion.power.early)} early · ${esc(champion.power.mid)} mid · Mobility ${esc(champion.ratings.mobility)}</em></span></div><label><span>Jungle champion</span><select data-route-champion>${junglers.sort((a,b)=>a.name.localeCompare(b.name)).map(c=>`<option value="${c.id}" ${c.id===champion.id?'selected':''}>${esc(c.name)}</option>`).join('')}</select></label></div>${best?`<article class="recommended-route"><header><span>RECOMMENDED · SCORE ${best.score}</span><h3>${esc(best.route.name)}</h3><b>${esc(best.route.side)} side</b></header><div class="route-nine">${Array.from({length:9},(_,index)=>routeStepChip(best.route.steps[index]||'',index)).join('')}</div><footer>${pill(best.route.earlyGank?'Early gank':'Full clear',best.route.earlyGank?'warning':'success')}${pill(`Scuttler ${best.route.scuttlerAt||best.route.scuttler||'flexible'}`)}${pill(best.route.gankLane||best.route.firstGank,'lane')}</footer></article>`:''}<div class="route-ranking">${ranked.slice(0,8).map(({route,score},index)=>`<span><b>${index+1}. ${esc(route.name)}</b><i><em style="width:${score/11*100}%"></em></i><strong>${score}/11</strong><small>${route.earlyGank?'early pressure':'farm'} · ${esc(route.side)} · ${esc(route.gankLane||'flex lane')}</small></span>`).join('')}</div></section>`}
function renderRoutesFull(){return afterPageIntro(renderRoutes(),routeCompatibilityPanel())+routeWorkbookTable()}

function workbookChampionPanel(c){const active=Object.entries(c.workbookFlags||{}).filter(([,value])=>activeFlagValue(value));return `<section class="sheet-detail-panel"><div class="section-head"><h3>Champion workbook fields</h3><span>Observed values from Champion sheet</span></div><div class="sheet-meta"><span><small>Release date</small><b>${esc(c.metadata?.releaseDate||'—')}</b></span><span><small>Sheet score</small><b>${esc(c.metadata?.sheetScore||'—')}</b></span><span><small>Last changed</small><b>${esc(c.metadata?.lastChanged||c.metadata?.patch||'—')}</b></span><span><small>Strong skill order</small><b>${esc(c.strongSkills||'—')}</b></span></div><div class="sheet-flags icon-flags">${active.map(([key])=>featureBadge(key,FEATURE_LABELS[key]||key)).join('')||'<span class="muted">No active workbook type</span>'}</div></section>`}
function strongSkillPanel(c){const sequence=String(c.strongSkills||'').split(',').map(value=>value.trim()).filter(Boolean),resolve=value=>{const key=slug(value),index=Number(value);if(key==='p')return c.abilities.find(a=>a.slot==='Passive');if(key==='ult'||key==='r')return c.abilities.find(a=>a.slot==='R');if(Number.isFinite(index)&&index>0)return c.abilities[index];return c.abilities.find(a=>slug(a.slot)===key||slug(a.name)===key)};return `<section class="strong-skill-panel"><div class="section-head"><h3>Strong skill sequence</h3><span>Exact order from Skill sheet · ${esc(c.strongSkills||'not defined')}</span></div><div>${sequence.map((value,index)=>{const ability=resolve(value);return `<article><b>${index+1}</b>${ability?.images?.[0]?`<img src="${esc(ability.images[0])}" alt="">`:''}<span><small>${esc(value)}</small><strong>${esc(ability?.name||'Workbook reference')}</strong><em>${esc(ability?.tags?.join(' · ')||'No matching ability record')}</em></span></article>`}).join('')||'<p class="empty">No strong-skill sequence in the workbook.</p>'}</div></section>`}
function libraryCoveragePanel(kind){const abilities=CHAMPIONS.flatMap(c=>c.abilities||[]),championMetrics=[['Records',CHAMPIONS.length],['Release metadata',CHAMPIONS.filter(c=>c.metadata?.releaseDate||c.metadata?.releaseYear).length],['Workbook flags',CHAMPIONS.filter(c=>Object.keys(c.workbookFlags||{}).length).length],['Base-stat profiles',CHAMPIONS.filter(c=>Object.keys(c.baseStats||{}).length).length]],skillMetrics=[['Skill records',abilities.length],['Tagged skills',abilities.filter(a=>a.tags?.length).length],['Cooldown values',abilities.filter(a=>String(a.cooldown||'').trim()).length],['Strong sequences',CHAMPIONS.filter(c=>String(c.strongSkills||'').trim()).length]],metrics=kind==='skills'?skillMetrics:championMetrics,source=kind==='skills'?'Skill!A1:BL211':'Champion!A1:DM204';return `<section class="library-coverage"><div class="section-head"><h3>${kind==='skills'?'Skill':'Champion'} data coverage</h3><span>${source}</span></div><div>${metrics.map(([label,value])=>`<span><small>${esc(label)}</small><b>${value}</b></span>`).join('')}</div><p>${kind==='skills'?'Passive plus Skill 1–14 fields are normalized into ability records with tags, cooldowns and alternate forms.':'Phase, class, combat, macro, lane and profile fields share one normalized champion record across every tool.'}</p></section>`}
function dedupedSkillRecords(c){const grouped=new Map;(c.abilities||[]).forEach(ability=>{const record=normalizedAbility(c,ability),key=`${slug(record.slot)}:${slug(record.name)}`;if(!grouped.has(key))grouped.set(key,{...record,tags:[...(record.tags||[])],images:[...(record.images||[])],ccTypes:[...(record.ccTypes||[])],forms:new Set(record.form&&record.form!=='base'?[record.form]:[]),sources:1});else{const current=grouped.get(key);current.tags=unique([...(current.tags||[]),...(record.tags||[])]);current.images=unique([...(current.images||[]),...(record.images||[])]);current.ccTypes=unique([...(current.ccTypes||[]),...(record.ccTypes||[])]);if(record.form&&record.form!=='base')current.forms.add(record.form);current.cooldown=current.cooldown||record.cooldown;current.impact=['High','Medium','Standard'].sort((a,b)=>['High','Medium','Standard'].indexOf(a)-['High','Medium','Standard'].indexOf(b)).find(level=>[current.impact,record.impact].includes(level))||current.impact;current.sources+=1}});return [...grouped.values()].sort((a,b)=>['Passive','Q','W','E','R'].indexOf(a.slot)-['Passive','Q','W','E','R'].indexOf(b.slot))}
function skillTagGroup(tags){const buckets=[['Damage',['Damage','Burst','DPS','Aoe','Poke','Execute','True Damage']],['Control',['CC','CC Hard','Airborne','Stun','Root','Slow','Silence','Fear','Charm','Suppress','Knockup']],['Mobility',['Dash','Blink','Speed','Displacement']],['Defense',['Shield','Heal','Buff','Cleanse','Untargetable']],['Macro',['Clearwave','TeamFight','Engage','Disengage','Gank','Vision','Strong Ult']]];return buckets.map(([name,keys])=>{const matches=tags.filter(tag=>keys.some(key=>semanticTagMatch(tag,key)));return matches.length?`<article><b>${esc(name)}</b><p>${matches.map(tag=>pill(tag,semanticTone(tag))).join('')}</p></article>`:''}).join('')}
function skillCard(record){const forms=[...(record.forms||[])],primaryImage=record.images?.[0],extraImages=(record.images||[]).slice(1,4);return `<article class="skill-card ${record.impact==='High'?'high-impact':record.impact==='Medium'?'mid-impact':''}"><header><span class="skill-slot">${esc(record.slot)}</span>${primaryImage?`<img src="${esc(primaryImage)}" alt="${esc(record.name)}" width="56" height="56" loading="lazy" decoding="async">`:`<i>${esc(record.slot[0]||'?')}</i>`}<div><small>${esc(record.impact||'Standard')} impact${forms.length?` · ${forms.map(esc).join(' / ')}`:''}</small><h3>${esc(record.name)}</h3><em>${esc(record.cooldown||'No cooldown data')}</em></div></header>${extraImages.length?`<div class="skill-alt-images">${extraImages.map(src=>`<img src="${esc(src)}" alt="${esc(record.name)} form" width="28" height="28" loading="lazy" decoding="async">`).join('')}</div>`:''}<section class="skill-meta-row"><span><small>Record</small><b>${record.sources>1?`${record.sources} merged`:'Unique'}</b></span><span><small>Form</small><b>${forms.length?forms.map(esc).join(' / '):'Base'}</b></span><span><small>CC</small><b>${record.ccTypes?.length?record.ccTypes.length:'—'}</b></span></section><div class="skill-tag-line">${(record.tags||[]).map(tag=>pill(tag,semanticTone(tag))).join('')||'<span class="muted">No tags</span>'}</div>${record.ccTypes?.length?`<footer><small>CC TYPES</small>${record.ccTypes.map(type=>pill(type,'danger')).join('')}</footer>`:''}</article>`}
function skillWorkbookPanel(c){const records=dedupedSkillRecords(c),rawCount=(c.abilities||[]).length,tags=unique(records.flatMap(record=>record.tags||[])).sort(),cc=unique(records.flatMap(record=>record.ccTypes||[])).sort(),high=records.filter(record=>record.impact==='High').length;return `<main class="skill-profile skill-workbook-profile"><section class="skill-hero">${portrait(c,'lg')}<div><span>${esc(c.classification.primary)} · ${esc(c.roles.join(' / '))}</span><h2>${esc(c.name)}</h2><p>${records.length} visible skills · ${rawCount-records.length} duplicate/form records merged · ${tags.length} tags</p></div><aside><span><small>High impact</small><b>${high}</b></span><span><small>CC types</small><b>${cc.length}</b></span><span><small>Cooldown rows</small><b>${records.filter(record=>String(record.cooldown||'').trim()).length}</b></span></aside></section><section class="skill-sheet-summary"><div class="section-head"><h3>Skill tag form</h3><span>Tags grouped from normalized Skill records</span></div><div class="skill-tag-groups">${skillTagGroup(tags)||'<p class="empty">No normalized tags.</p>'}</div></section>${strongSkillPanel(c)}<section class="skill-card-section"><div class="section-head"><h3>Skill records</h3><span>Deduped by slot + skill name · tags merged</span></div><div class="skill-card-grid">${records.map(skillCard).join('')}</div></section></main>`}
function renderChampionsFull(){const c=byId(state.focus)||CHAMPIONS[0];return afterPageIntro(renderChampions(),libraryCoveragePanel('champions'))+championSkillPanel(c)+strongSkillPanel(c)+workbookChampionPanel(c)}
function renderSkillsFull(){const c=byId(state.focus)||CHAMPIONS[0];return pageIntro('Skill library','Normalized champion skills with merged duplicate forms, full tags, cooldowns, CC types and strong-skill order.')+libraryCoveragePanel('skills')+`<div class="library-layout skill-library-layout">${libraryList('skills',c.id)}${skillWorkbookPanel(c)}</div>`}

function draftRuleAllows(c){const rules=state.draftRestrictions,turn=DRAFT_SEQUENCE[state.draftStep],type=turn?.[0];if(!rules.enabled||!rules.assistant)return false;if(type==='ban'&&rules.onlyBanPool&&!state.draftEnemyPool.includes(c.id))return false;if(type==='slot'&&rules.onlyOwnPool&&!state.draftOwnPool.includes(c.id))return false;if(type==='slot'&&rules.onlyEnemyPool&&!state.draftEnemyPool.includes(c.id))return false;return true}
const draftRecommendationBase=draftRecommendation;
draftRecommendation=function(){return draftRecommendationBase().filter(({c})=>draftRuleAllows(c))};

document.addEventListener('click',event=>{
  const filterSummary=event.target.closest('.picker-filter>summary');if(filterSummary)document.querySelectorAll('.picker-filter[open]').forEach(details=>{if(details!==filterSummary.parentElement)details.removeAttribute('open')});
  const pick=event.target.closest('[data-pick]');if(pick){applyPick(pick.dataset.pick);return}
  const pickerReset=event.target.closest('[data-picker-reset]');if(pickerReset){state.pickerFilters=structuredClone(DEFAULT_STATE.pickerFilters);renderPickerFilters();renderPicker();return}
  const pickerPanel=event.target.closest('[data-picker-filter-panel]');if(pickerPanel){pickerFiltersCollapsed=!pickerFiltersCollapsed;renderPickerFilters();return}
  if(event.target?.id==='champion-picker'){const rect=event.target.getBoundingClientRect(),outside=event.clientX<rect.left||event.clientX>rect.right||event.clientY<rect.top||event.clientY>rect.bottom;if(outside)closePicker();return}
  const language=event.target.closest('[data-lang]');if(language){state.lang=enumValue(language.dataset.lang,['en','vi'],state.lang);save();syncRouteUrl('replaceState');render();return}
  const teamFocusLane=event.target.closest('[data-team-focus-lane]');if(teamFocusLane){state.teamFocusLane=enumValue(teamFocusLane.dataset.teamFocusLane,['Top','Jungle','Mid','Bot'],state.teamFocusLane);save();render();return}
  const teamFocusPhase=event.target.closest('[data-team-focus-phase]');if(teamFocusPhase){state.teamFocusPhase=enumValue(teamFocusPhase.dataset.teamFocusPhase,PHASES,state.teamFocusPhase);save();render();return}
  const checkRole=event.target.closest('button[data-check-role]');if(checkRole){const role=checkRole.dataset.checkRole,roles=finderList('roles'),active=roles.includes(role);state.finder.roles=active?[]:[role];state.checkLane=role;refreshFinderFocus();save();render();return}
  const checkEffectRemove=event.target.closest('[data-check-effect-remove]');if(checkEffectRemove){const value=checkEffectRemove.dataset.checkEffectRemove,values=finderList('skillEffects'),index=values.indexOf(value);if(index>=0)values.splice(index,1);refreshFinderFocus();save();render();return}
  const checkToggle=event.target.closest('label.check-filter-toggle');if(checkToggle){event.preventDefault();const input=checkToggle.querySelector('input[data-filter]');if(!input||input.disabled)return;const values=finderList(input.dataset.filter),index=values.indexOf(input.value);index>=0?values.splice(index,1):values.push(input.value);refreshFinderFocus();save();render();return}
  const route=event.target.closest('button[data-route],a[data-route]');if(route){const routeFocus=event.target.closest('[data-focus]');if(routeFocus)state.focus=routeFocus.dataset.focus;routeTo(route.dataset.route);return}
  const action=event.target.closest('[data-action]');if(action){const a=action.dataset.action;if(a==='toggle-nav'){const open=document.body.classList.toggle('nav-open');action.setAttribute('aria-expanded',String(open))}if(a==='toggle-sidebar'){state.sidebarCollapsed=!state.sidebarCollapsed;save();updateShell()}if(a==='close-picker')closePicker();if(a==='recover-view')routeTo('system',{historyMode:'replaceState'});if(a==='reset-workspace'&&confirm('Reset every composition and filter?'))resetState();if(a==='swap-sides')swapSides();if(a==='save-session')saveNamedSession();if(a==='copy-session-link')void copySessionLink();if(a==='export-session')downloadSession();if(a==='toggle-bans'){state.bansVisible=!state.bansVisible;save();render()}if(a==='reset-all-bans'&&confirm('Clear all 10 bans?')){state.blueBans=championSlots([]);state.redBans=championSlots([]);save();render();notify('All bans cleared')}if(a==='reset-side-bans'){const side=action.dataset.side;if(['blue','red'].includes(side)){state[`${side}Bans`]=championSlots([]);save();render();notify(`${side} bans cleared`)}}if(a==='reset-draft'){clearCurrentDraft();save();render()}if(a==='reset-series'&&confirm('Clear the whole series history and Fearless pool?')){clearCurrentDraft();state.draftSeries={...DEFAULT_STATE.draftSeries,games:[]};save();render()}if(a==='draft-prev'){state.draftStep=Math.max(0,state.draftStep-1);save();render()}if(a==='draft-next'){state.draftStep=Math.min(DRAFT_SEQUENCE.length,state.draftStep+1);save();render()}if(a==='auto-roles'){state.blue=assignDraftRoles(state.blue);state.red=assignDraftRoles(state.red);save();render();notify('Optimal roles assigned for both teams')}if(a==='complete-game')completeDraftGame();if(a==='clear-filters'){state.finder=structuredClone(DEFAULT_STATE.finder);save();render()}if(a==='reset-weights'){state.weights={...DEFAULT_STATE.weights};save();render()}return}
  const clear=event.target.closest('[data-clear]');if(clear){event.stopPropagation();const [field,index]=clear.dataset.clear.split(':');state[field][Number(index)]=null;save();render();return}
  const picker=event.target.closest('[data-picker]');if(picker){openPicker(picker.dataset.picker);return}
  const draftPick=event.target.closest('[data-draft-pick]');if(draftPick){const c=byId(draftPick.dataset.draftPick);if(!c||!draftRuleAllows(c)){notify('Champion is outside the active draft pool rules');return}applyDraftPick(draftPick.dataset.draftPick);return}
  const focus=event.target.closest('[data-focus]');if(focus){state.focus=focus.dataset.focus;save();render();return}
  const library=event.target.closest('[data-library-focus]');if(library){state.focus=library.dataset.libraryFocus;state.route=library.dataset.libraryRoute;save();render();return}
  const draftStep=event.target.closest('[data-draft-step]');if(draftStep){state.draftStep=Number(draftStep.dataset.draftStep);save();render();return}
  const draftMode=event.target.closest('[data-draft-mode]');if(draftMode){state.draftMode=draftMode.dataset.draftMode;save();render();return}
  const analysisMode=event.target.closest('[data-analysis-mode]');if(analysisMode){state.analysisMode=analysisMode.dataset.analysisMode;if(!availableTeamSections().some(([id])=>id===state.teamSection))state.teamSection='overview';save();render();return}
  const perspective=event.target.closest('[data-perspective]');if(perspective){state.perspective=perspective.dataset.perspective;save();render();return}
  const teamSection=event.target.closest('[data-team-section]');if(teamSection){state.teamSection=teamSection.dataset.teamSection;save();render();document.getElementById('app-main').focus();return}
  const mobileTeamSide=event.target.closest('[data-mobile-team-side]');if(mobileTeamSide){state.mobileTeamSide=mobileTeamSide.dataset.mobileTeamSide;save();render();return}
  const historyEntry=event.target.closest('[data-history-index]');if(historyEntry){restoreHistoryEntry(historyEntry.dataset.historyIndex);return}
  const poolMode=event.target.closest('[data-pool-mode]');if(poolMode){state.draftPoolMode=poolMode.dataset.poolMode;save();render();return}
  const seriesFormat=event.target.closest('[data-series-format]');if(seriesFormat){state.draftSeries.format=Number(seriesFormat.dataset.seriesFormat);save();render();return}
  const gameWinner=event.target.closest('[data-game-winner]');if(gameWinner){const [index,winner]=gameWinner.dataset.gameWinner.split(':');state.draftSeries.games[Number(index)].winner=winner;save();render();return}
  const phase=event.target.closest('[data-map-phase]');if(phase){state.mapPhase=phase.dataset.mapPhase;save();render();return}
  const fightPhase=event.target.closest('[data-teamfight-phase]');if(fightPhase){state.teamfightPhase=fightPhase.dataset.teamfightPhase;save();render();return}
  const fightScenario=event.target.closest('[data-fight-scenario]');if(fightScenario){state.fightScenario=fightScenario.dataset.fightScenario;save();render();return}
  const matchupLane=event.target.closest('[data-matchup-lane]');if(matchupLane){state.matchupLane=matchupLane.dataset.matchupLane;save();render();return}
  const matchupOpponent=event.target.closest('[data-matchup-opponent]');if(matchupOpponent){state.matchupOpponent=matchupOpponent.dataset.matchupOpponent;save();render();return}
  const compareLane=event.target.closest('[data-compare-lane]');if(compareLane){state.compareLane=compareLane.dataset.compareLane;normalizeCompareLineup(state.compareLane);save();render();return}
  const strategyRole=event.target.closest('[data-strategy-role]');if(strategyRole){state.strategyRole=strategyRole.dataset.strategyRole;save();render();return}
  const side=event.target.closest('[data-strategy-side]');if(side){state.strategySide=side.dataset.strategySide;save();render()}
});
document.addEventListener('change',async event=>{
  const sessionLoad=event.target.closest('[data-session-load]');if(sessionLoad){const record=state.savedSessions.find(item=>item.id===sessionLoad.value);if(record)applySessionPayload(record);return}
  const sessionImport=event.target.closest('[data-session-import]');if(sessionImport){const file=sessionImport.files?.[0];if(!file)return;try{applySessionPayload(JSON.parse(await file.text()));notify('Session JSON imported')}catch(error){console.error('Session import failed.',error);notify(`Import failed · ${error.message}`)}finally{sessionImport.value=''}return}
  const pickerFilter=event.target.closest('[data-picker-filter]');if(pickerFilter){const values=state.pickerFilters[pickerFilter.dataset.pickerFilter],index=values.indexOf(pickerFilter.value);pickerFilter.checked&&index<0?values.push(pickerFilter.value):!pickerFilter.checked&&index>=0&&values.splice(index,1);refreshPickerFilterHeader(pickerFilter);renderPicker();return}
  const draftFilter=event.target.closest('[data-draft-filter]');if(draftFilter){state.draftFilters[draftFilter.dataset.draftFilter]=draftFilter.checked;save();render();return}
  const draftRestriction=event.target.closest('[data-draft-restriction]');if(draftRestriction){state.draftRestrictions[draftRestriction.dataset.draftRestriction]=draftRestriction.checked;save();render();return}
  const teamfightFlank=event.target.closest('[data-teamfight-flank]');if(teamfightFlank){state.teamfightFlank=teamfightFlank.checked;save();render();return}
  const poolAssign=event.target.closest('[data-pool-assign]');if(poolAssign){const [type,id]=poolAssign.dataset.poolAssign.split(':'),field=type==='own'?'draftOwnPool':'draftEnemyPool',index=state[field].indexOf(id);poolAssign.checked&&index<0?state[field].push(id):!poolAssign.checked&&index>=0&&state[field].splice(index,1);save();render();return}
  const draftSort=event.target.closest('[data-draft-sort]');if(draftSort){state.draftSort=draftSort.value;save();render();return}
  const comparePick=event.target.closest('[data-compare-pick]');if(comparePick){const field=comparePick.dataset.comparePick;if(['compareA','compareB','compareBlueSupport','compareRedSupport'].includes(field)){state[field]=comparePick.value;normalizeCompareLineup(state.compareLane);save();render()}return}
  const compareLevel=event.target.closest('[data-compare-level]');if(compareLevel){state.compareLevel=Number(compareLevel.value);save();render();return}
  const fearless=event.target.closest('[data-series-fearless]');if(fearless){state.draftSeries.fearless=fearless.checked;save();render();return}
  const teamfightControl=event.target.closest('[data-teamfight-control]');if(teamfightControl){state[teamfightControl.dataset.teamfightControl]=teamfightControl.value;if(teamfightControl.dataset.teamfightControl==='teamfightMode'){const mode={Aram:'siege',Dragon:'objective',Baron:'objective','Atakhan Top':'objective','Atakhan Bot':'objective',Combat:'standard',Basic:'standard'};state.fightScenario=mode[teamfightControl.value]||state.fightScenario}save();render();return}
  const teamfightExecution=event.target.closest('[data-teamfight-execution]');if(teamfightExecution){state[teamfightExecution.dataset.teamfightExecution]=teamfightExecution.value;save();render();return}
  const strategyMacro=event.target.closest('[data-strategy-macro]');if(strategyMacro){state.strategyMacro=strategyMacro.value;save();render();return}
  const checkControl=event.target.closest('[data-check-control]');if(checkControl){const field=checkControl.dataset.checkControl;state[field]=checkControl.value;if(field==='checkLane'&&!byId(state.focus)?.roles.includes(checkControl.value))state.focus=CHAMPIONS.find(c=>c.roles.includes(checkControl.value))?.id||state.focus;save();render();return}
  const checkEffectAdd=event.target.closest('[data-check-effect-add]');if(checkEffectAdd){const value=checkEffectAdd.value,values=finderList('skillEffects');if(value&&!values.includes(value))values.push(value);refreshFinderFocus();save();render();return}
  const checkSelectControl=event.target.closest('[data-check-select]');if(checkSelectControl){state.finder[checkSelectControl.dataset.checkSelect]=checkSelectControl.value?[checkSelectControl.value]:[];refreshFinderFocus();save();render();return}
  const mapRoute=event.target.closest('[data-map-route]');if(mapRoute){state[mapRoute.dataset.mapRoute==='blue'?'mapRouteBlue':'mapRouteRed']=mapRoute.value;save();render();return}
  const routeChampion=event.target.closest('[data-route-champion]');if(routeChampion){state.routeChampion=routeChampion.value;save();render();return}
  const filter=event.target.closest('[data-filter]');if(filter){const values=finderList(filter.dataset.filter),i=values.indexOf(filter.value);filter.checked&&i<0?values.push(filter.value):!filter.checked&&i>=0&&values.splice(i,1);refreshFinderFocus();save();render();return}
  const phase=event.target.closest('[data-phase-filter]');if(phase){state.finder.phase[phase.dataset.phaseFilter]=phase.value;const next=CHAMPIONS.find(champion=>finderPass(champion));if(next)state.focus=next.id;save();render();return}
  const year=event.target.closest('[data-year-filter]');if(year){state.finder.releaseYear=year.value;const next=CHAMPIONS.find(champion=>finderPass(champion));if(next)state.focus=next.id;save();render();return}
  const weight=event.target.closest('[data-weight]');if(weight){state.weights[weight.dataset.weight]=Number(weight.value);save();render()}
});
document.addEventListener('input',event=>{
  if(event.target.matches('[data-session-name]')){state.sessionName=event.target.value.slice(0,80);save();return}
  if(event.target.matches('[data-finder-search]')){state.finder.search=event.target.value;save();render();refocus('[data-finder-search]',event.target.value.length)}
  if(event.target.matches('[data-library-search]')){state.libraryQuery=event.target.value;save();render();refocus('[data-library-search]',event.target.value.length)}
  if(event.target.id==='picker-search')renderPicker();
  if(event.target.matches('[data-weight]')){state.weights[event.target.dataset.weight]=Number(event.target.value);event.target.nextElementSibling.textContent=event.target.value;save()}
});
function refocus(selector,pos){const input=document.querySelector(selector);input?.focus();input?.setSelectionRange(pos,pos)}

// Keep champion selection local to the dialog. Some browsers can lose a
// delegated document click while a modal dialog is in the top layer.
const pickerList=document.getElementById('picker-list');
pickerList?.addEventListener('click',event=>{
  const option=event.target.closest('[data-pick]');
  if(!option||option.disabled)return;
  event.preventDefault();
  event.stopPropagation();
  applyPick(option.dataset.pick);
});
document.querySelector('#champion-picker [data-action="close-picker"]')?.addEventListener('click',event=>{
  event.preventDefault();event.stopImmediatePropagation();closePicker();
});
document.getElementById('champion-picker')?.addEventListener('cancel',event=>{
  event.preventDefault();closePicker();
});
document.addEventListener('keydown',event=>{if(event.key==='Escape'&&document.getElementById('champion-picker')?.open){event.preventDefault();closePicker()}});
document.querySelector('.topbar [data-action="swap-sides"]')?.addEventListener('click',event=>{
  event.preventDefault();event.stopImmediatePropagation();swapSides();
});
window.addEventListener('popstate',()=>{
  const route=new URLSearchParams(location.search).get('route');
  if(!NAVIGATION.some(group=>group.items.some(([id])=>id===route))||route===state.route)return;
  state.route=route;save();render();document.getElementById('app-main').focus();
});

syncRouteUrl('replaceState');renderNav();render();
